  // ID prepaid для пополнения: глобальный ключ → снимок текущей фirmы.
  static Future<String> resolvedAccountId([String? firmId]) async {
    final g = await accountId();
    if (g != null && g.isNotEmpty) return g;
    final fid = (firmId ?? (await subjectId()) ?? '').trim();
    if (fid.isEmpty) return '';
    final infos = await _readFirmInfos();
    final m = infos[fid];
    if (m is Map) {
      final s = (m['accountId'] ?? '').toString().trim();
      if (s.isNotEmpty) {
        await setAccountId(s);
        return s;
      }
    }
    return '';
  }

  // Подтянуть в глобальные ключи данные из снимка firmы (после смены фirmы).
  static Future<void> applyFirmSnapshot(String firmId) async {
    if (firmId.isEmpty) return;
    final infos = await _readFirmInfos();
    final m = infos[firmId];
    if (m is! Map) return;
    final aid = (m['accountId'] ?? '').toString().trim();
    if (aid.isNotEmpty) await setAccountId(aid);
    final bal = (m['balance'] ?? '').toString().trim();
    if (bal.isNotEmpty) {
      await setBalanceRaw(
          bal, m['time'] is int ? m['time'] as int : null);
    }
    final comp = (m['company'] ?? '').toString().trim();
    if (comp.isNotEmpty) await setCompany(comp);
    final lg = (m['login'] ?? '').toString().trim();
    if (lg.isNotEmpty) await setLastLogin(lg);
  }
}

