// Переключить язык eTOLL на английский (один раз).
// Ищем переключатель языка (PL/EN) и кликаем EN, если стоит не EN.
Future<void> _setEnglish() async {
  if (_controller == null) return;
  await _controller!.evaluateJavascript(source: r'''
    (function(){
      try {
        if (window.__rcEnSet) return;
        // 1) Ищем выпадашку/кнопку выбора языка и опцию EN
        function clickEn(){
          // 1a) Ссылки с параметром языка в href (надёжно для gov-сайтов)
          var links = document.querySelectorAll('a[href]');
          for (var j=0;j<links.length;j++){
            var h = (links[j].getAttribute('href')||'').toLowerCase();
            if (h.indexOf('lang=en')>=0 || h.indexOf('culture=en')>=0 ||
                h.indexOf('/en')>=0 || h.indexOf('language=en')>=0){
              if (links[j].offsetParent!==null){
                try { links[j].click(); window.__rcEnSet = true; return true; } catch(e){}
              }
            }
          }
          // 1b) Кнопки/пункты с текстом EN
          var all = document.querySelectorAll('a, button, [role="option"], [role="menuitem"], li, span, div, option');
          for (var i=0;i<all.length;i++){
            var el = all[i];
            if (el.offsetParent===null) continue;
            var t = (el.innerText || el.textContent || '').trim().toLowerCase();
            // именно короткий "en" / "english" — не абзац
            if ((t==='en' || t==='english' || t==='angielski') && t.length<10){
              try { el.click(); window.__rcEnSet = true; return true; } catch(e){}
            }
          }
          return false;
        }
        // Сначала пробуем открыть выпадашку языка (часто это кнопка с "PL")
        function openLangThenEn(){
          if (clickEn()) return true;
          var all = document.querySelectorAll('a, button, [role="button"], div, span');
          for (var i=0;i<all.length;i++){
            var el = all[i];
            if (el.offsetParent===null) continue;
            var t = (el.innerText || '').trim().toLowerCase();
            if ((t==='pl' || t==='polski') && t.length<10){
              try { el.click(); } catch(e){}
              // после открытия меню — пробуем кликнуть EN
              if (clickEn()) return true;
            }
          }
          return clickEn();
        }
        if (!openLangThenEn()){
          var n=0;
          var iv=setInterval(function(){
            n++;
            if (openLangThenEn() || n>=5) clearInterval(iv);
          }, 700);
        }
      } catch(e){}
    })();
  ''');
}

