// Нажать «Details» / «Szczegóły» у счёта на financing/list (или прямая ссылка).
Future<String> _clickPrepaidDetailsLink() async {
  final aid = _aid.replaceAll("'", '');
  if (aid.isEmpty) return '0';
  final r = await _controller?.evaluateJavascript(source: '''
    (function(){try{
      function realClick(el){try{var rc=el.getBoundingClientRect();
        var o={bubbles:true,cancelable:true,view:window,
          clientX:rc.left+rc.width/2,clientY:rc.top+rc.height/2};
        el.dispatchEvent(new MouseEvent('pointerdown',o));
        el.dispatchEvent(new MouseEvent('mousedown',o));
        el.dispatchEvent(new MouseEvent('mouseup',o));
        el.dispatchEvent(new MouseEvent('click',o));el.click();
      }catch(e){try{el.click();}catch(e2){}}}
      var aid='$aid';
      var direct=document.querySelectorAll('a[href*="/prepaid/'+aid+'/details"]');
      for(var d=0;d<direct.length;d++){
        if(direct[d].offsetParent!==null){realClick(direct[d]);return 'href';}
      }
      var words=['details','szczegóły','szczegoly','detail'];
      var blocks=document.querySelectorAll('div,section,article,li,tr,mat-card,[class*="card"]');
      for(var b=0;b<blocks.length;b++){
        var blk=blocks[b];
        if((blk.innerText||'').indexOf(aid)<0) continue;
        var links=blk.querySelectorAll('a,button,[role="button"]');
        for(var i=0;i<links.length;i++){
          var el=links[i]; if(el.offsetParent===null) continue;
          var t=(el.innerText||el.textContent||'').trim().toLowerCase();
          if(!t||t.length>20) continue;
          for(var w=0;w<words.length;w++){
            if(t===words[w]||t.indexOf(words[w])===0){realClick(el);return 'details';}
          }
        }
      }
      return '0';
    }catch(e){return '0';}})();
  ''');
  return (r?.toString() ?? '');
}

bool _isPrepaidDetails(String lu) =>
    lu.contains('/prepaid/') && lu.contains('/details');

bool _isCardChangePage(String lu) =>
    lu.contains('/change-card') ||
    lu.contains('/change_card') ||
    lu.contains('/payment-card') ||
    lu.contains('/paymentcard') ||
    lu.contains('/card-change') ||
    (lu.contains('/prepaid/') &&
        lu.contains('/card') &&
        !lu.contains('/details')) ||
    (lu.contains('/payment') &&
        !lu.contains('/details') &&
        lu.contains('/prepaid/'));

