// Прямой режим с нативного TopUpAccountScreen — без financing/list.
if (widget.directAction == 'changeCard' &&
    sid.isNotEmpty &&
    _aid.isNotEmpty) {
  if (_isCardChangePage(lu)) {
    _setDbg('форма смены карты', u, '');
    _topUpDone = true;
    return;
  }

  if (_isPrepaidDetails(lu)) {
    if (_stepTicks >= 2 &&
        (_changeCardAttempts < 8 || _stepTicks % 2 == 0)) {
      _changeCardAttempts++;
      final cc = await _clickChangeCard();
      _setDbg('смена карты', u, cc);
      if (cc != '0' && cc != 'null') {
        await Future.delayed(const Duration(milliseconds: 900));
      }
    }
    if (_changeCardAttempts >= 6 && _stepTicks % 3 == 0) {
      for (final suffix in [
        'change-card',
        'payment-card',
        'payment-card/change',
        'card/change',
      ]) {
        await _goPrepaid(suffix);
        await Future.delayed(const Duration(milliseconds: 400));
      }
      _setDbg('→ change-card (fallback)', u, '');
    }
    return;
  }

  if (lu.contains('/financing/list') ||
      (lu.contains('/financing') && !lu.contains('/prepaid/'))) {
    final det = await _clickPrepaidDetailsLink();
    _setDbg('→ Details', u, det);
    if (det == '0' &&
        (_stepTicks <= 2 || _stepTicks % 2 == 0 || lu.contains('/manage'))) {
      await _goPrepaid('details');
      _setDbg('→ details (url)', u, '');
    }
    return;
  }

  if (!lu.contains('/card') &&
      !lu.contains('/payment') &&
      !lu.contains('login')) {
    if (_stepTicks <= 2 || _stepTicks % 2 == 0 || lu.contains('/manage')) {
      await _goPrepaid('details');
      _setDbg('→ details', u, '');
    }
    return;
  }
  return;
}

