/// Тематическая эмблема для плиток меню (eTOLL, транспорт, фирмы).
enum PaymentTileEmblemKind { etoll, transport, firms }

class PaymentTileEmblem extends StatelessWidget {
  const PaymentTileEmblem({
    super.key,
    required this.kind,
    this.overlayText,
  });

  final PaymentTileEmblemKind kind;
  final String? overlayText;

  static const _size = 46.0;
  static const _radius = 13.0;

  static List<BoxShadow> glowShadows(Color glow, {double intensity = 1}) => [
        BoxShadow(
          color: glow.withValues(alpha: 0.48 * intensity),
          blurRadius: 14,
          spreadRadius: 0.5,
          offset: const Offset(0, 2),
        ),
        BoxShadow(
          color: glow.withValues(alpha: 0.28 * intensity),
          blurRadius: 22,
          spreadRadius: 3,
        ),
      ];

  Color get _glowColor => switch (kind) {
        PaymentTileEmblemKind.etoll => RcTheme.etollRed,
        PaymentTileEmblemKind.transport => RcTheme.accent,
        PaymentTileEmblemKind.firms => RcTheme.accent,
      };

  Color get _borderColor => switch (kind) {
        PaymentTileEmblemKind.etoll =>
          RcTheme.etollRed.withValues(alpha: 0.72),
        PaymentTileEmblemKind.transport =>
          RcTheme.accent.withValues(alpha: 0.58),
