/// Прямые URL eTOLL selfservice (mobile/subject/…).
abstract final class EtollUrls {
  static const base = 'https://mojekonto.etoll.gov.pl/selfservice/';
  static const etollKey = 'https://etoll.gov.pl/';

  static String _subject(String subjectId) =>
      '#/mobile/subject/$subjectId';

  static String billingList(String subjectId) =>
      '$base${_subject(subjectId)}/billing-account/list';

  static String financingList(String subjectId) =>
      '$base${_subject(subjectId)}/manage/financing/list';

  static String prepaidDetails(String subjectId, String prepaidId) =>
      '$base${_subject(subjectId)}/financing/prepaid/$prepaidId/details';

  static String prepaidTopUp(String subjectId, String prepaidId) =>
      '$base${_subject(subjectId)}/financing/prepaid/$prepaidId/top-up';
}

class EtollPrepaidDetails {
  final String card4;
  final String finType; // 'auto' | 'prepay' | ''
  final String autoMin;
  final String autoFill;

  const EtollPrepaidDetails({
    this.card4 = '',
    this.finType = '',
    this.autoMin = '',
    this.autoFill = '',
  });

  bool get hasCard => card4.length == 4;

  Map<String, dynamic> toJson() => {
        'card4': card4,
        'finType': finType,
        'autoMin': autoMin,
        'autoFill': autoFill,
      };

  factory EtollPrepaidDetails.fromJson(Map<String, dynamic> m) {
    return EtollPrepaidDetails(
      card4: (m['card4'] ?? '').toString(),
      finType: (m['finType'] ?? '').toString(),
      autoMin: (m['autoMin'] ?? '').toString(),
      autoFill: (m['autoFill'] ?? '').toString(),
    );
  }
}

/// JS для парсинга страницы prepaid/…/details eTOLL.
abstract final class EtollDetailsParser {
  static const parseJs = r'''
(function(){
  try {
    var t = (document.body && document.body.innerText) ? document.body.innerText : '';
    var out = {card4:'', finType:'', autoMin:'', autoFill:''};
    var cm = t.match(/(?:••••|\*{4}|\.{3}|…)\s*(\d{4})/i)
          || t.match(/visa[^\d]{0,20}(\d{4})/i)
          || t.match(/mastercard[^\d]{0,20}(\d{4})/i)
          || t.match(/(\d{4})\s*(?:\n|$)/);
    if (cm) out.card4 = cm[1];
    var tl = t.toLowerCase();
    if (tl.indexOf('automatic') >= 0 || tl.indexOf('automat') >= 0) out.finType = 'auto';
    else if (tl.indexOf('prepaid') >= 0 || tl.indexOf('prepay') >= 0 || tl.indexOf('prepaid') >= 0) out.finType = 'prepay';
    var nums = t.match(/(\d+(?:[.,]\d+)?)\s*PLN/gi) || [];
    var plain = [];
    for (var i=0;i<nums.length;i++){
      var n = nums[i].replace(/PLN/i,'').replace(/\s/g,'').replace(',','.');
      plain.push(n);
    }
    if (plain.length >= 2) {
      out.autoMin = plain[0];
      out.autoFill = plain[1];
    } else if (plain.length === 1) {
      out.autoMin = plain[0];
    }
    var thresh = t.match(/(?:below|under|poni[żz]ej|mniej|threshold|pr[óo]g)[^\d]{0,40}(\d+)/i);
    if (thresh) out.autoMin = thresh[1];
    var fill = t.match(/(?:amount|kwot|sum|fill|do[łl]ad)[^\d]{0,40}(\d+)/i);
    if (fill && !out.autoFill) out.autoFill = fill[1];
    return JSON.stringify(out);
  } catch(e) { return '{}'; }
})();
''';

  static EtollPrepaidDetails parseResult(dynamic jsResult) {
    try {
      final raw = (jsResult ?? '{}').toString().trim();
      if (raw.isEmpty || raw == 'null') return const EtollPrepaidDetails();
      final m = Map<String, dynamic>.from(
          (raw.startsWith('{') ? _decode(raw) : {}) as Map? ?? {});
      return EtollPrepaidDetails.fromJson(m);
    } catch (_) {
      return const EtollPrepaidDetails();
    }
  }

  static dynamic _decode(String raw) {
    // avoid importing dart:convert in hot path — caller can use jsonDecode
    return _jsonDecode(raw);
  }

  static dynamic _jsonDecode(String s) {
    // minimal inline — use dart:convert
    return null;
  }
}

