/// Данные prepaid/details — отдельно от BalanceStore (по firmId).
class EtollDetailsStore {
  static String _key(String firmId) => 'etoll_details_$firmId';

  static Future<EtollPrepaidDetails?> load(String firmId) async {
    if (firmId.isEmpty) return null;
    final prefs = await SharedPreferences.getInstance();
    final raw = prefs.getString(_key(firmId));
    if (raw == null || raw.isEmpty) return null;
    try {
      return EtollPrepaidDetails.fromJson(
          Map<String, dynamic>.from(jsonDecode(raw) as Map));
    } catch (_) {
      return null;
    }
  }

  static Future<void> save(String firmId, EtollPrepaidDetails d) async {
    if (firmId.isEmpty) return;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(_key(firmId), jsonEncode(d.toJson()));
  }
}

/// JS: переключить интерфейс eTOLL на English (если есть селектор языка).
abstract final class EtollPreferEnglish {
  static const js = r'''
(function(){
  try {
    if (window.__etEnDone) return 'done';
    var sel = document.querySelector('select[aria-label*="language" i], select[name*="lang" i], select[id*="lang" i]');
    if (sel) {
      for (var i=0;i<sel.options.length;i++){
        var o = sel.options[i];
        var t = (o.text||o.label||'').toLowerCase();
        if (t.indexOf('english')>=0 || t.indexOf('en ')===0 || t==='en') {
          sel.value = o.value; sel.dispatchEvent(new Event('change',{bubbles:true}));
          window.__etEnDone = true; return 'select';
        }
      }
    }
    var btns = document.querySelectorAll('button,a,[role="button"],li,span');
    for (var j=0;j<btns.length;j++){
      var el = btns[j];
      if (el.offsetParent===null) continue;
      var tx = (el.innerText||'').trim().toLowerCase();
      if (tx==='english' || tx==='en' || tx.indexOf('english')===0) {
        try { el.click(); window.__etEnDone = true; return 'click'; } catch(e){}
      }
    }
    return 'none';
  } catch(e) { return 'err'; }
})();
''';
}

typedef BalanceTr = String Function(String key);
typedef CredentialsLoader = Future<List<Map<String, String>>> Function(String key);

/// Зависимости блока balance от main (без circular import).
