/// Headless: открыть prepaid/details → распарсить карту/тип/автопополнение.
class EtollDetailsFetcher {
  static const _ua =
      'Mozilla/5.0 (Linux; Android 14; SM-S918B) AppleWebKit/537.36 (KHTML, like Gecko) '
      'Chrome/149.0.0.0 Mobile Safari/537.36';

  static Future<EtollPrepaidDetails?> fetch({
    required String firmId,
    required String login,
    required String subjectId,
    required String accountId,
    required CredentialsLoader loadCredentials,
    void Function(String card4)? onCard4,
  }) async {
    if (firmId.isEmpty || subjectId.isEmpty || accountId.isEmpty) return null;

    HeadlessInAppWebView? headless;
    InAppWebViewController? ctrl;
    EtollPrepaidDetails? result;

    final target = EtollUrls.prepaidDetails(subjectId, accountId);

    try {
      headless = HeadlessInAppWebView(
        initialSize: const Size(412, 915),
        initialUrlRequest: URLRequest(url: WebUri(target)),
        initialSettings: InAppWebViewSettings(
          userAgent: _ua,
          javaScriptEnabled: true,
          domStorageEnabled: true,
          thirdPartyCookiesEnabled: true,
          useHybridComposition: false,
        ),
        onWebViewCreated: (c) => ctrl = c,
      );
      await headless.run();

      for (int i = 0; i < 80 && result == null; i++) {
        await Future.delayed(const Duration(milliseconds: 500));
        if (ctrl == null) continue;
        final cur = (await ctrl!.getUrl())?.toString() ?? '';

        await ctrl!.evaluateJavascript(source: EtollPreferEnglish.js);

        if (cur.contains('login') || cur.endsWith('/selfservice/')) {
          await _autofillLogin(ctrl!, login, loadCredentials);
          await _enterFirm(ctrl!, subjectId);
          if (!cur.contains('/details')) {
            try {
              await ctrl!.loadUrl(urlRequest: URLRequest(url: WebUri(target)));
            } catch (_) {}
          }
          continue;
        }

        if (cur.contains('/details')) {
          final raw = await ctrl!.evaluateJavascript(
              source: EtollDetailsParser.parseJs);
          final parsed = EtollDetailsParser.parseResult(raw);
          if (parsed.hasCard || parsed.finType.isNotEmpty) {
            result = parsed;
            await EtollDetailsStore.save(firmId, parsed);
            if (parsed.hasCard && onCard4 != null) {
              onCard4(parsed.card4);
            }
            break;
          }
        } else if (cur.contains('/financing')) {
          await ctrl!.evaluateJavascript(source: _clickDetailsJs(accountId));
        }
      }
    } catch (_) {
    } finally {
      try {
        await headless?.dispose();
      } catch (_) {}
    }
    return result;
  }

  static String _clickDetailsJs(String accountId) {
    final aid = accountId.replaceAll("'", '');
    return '''
(function(){
  try {
    var fa = document.querySelectorAll('a[href*="/financing/prepaid/$aid"]');
    for (var i=0;i<fa.length;i++) {
      if (fa[i].offsetParent!==null) { fa[i].click(); return 'link'; }
    }
    var words=['details','szczegóły','szczegoly'];
    var els=document.querySelectorAll('a,button,[role="button"]');
    for (var j=0;j<els.length;j++){
      var t=(els[j].innerText||'').trim().toLowerCase();
      for (var w=0;w<words.length;w++){
        if (t===words[w]||t.indexOf(words[w])===0){ els[j].click(); return 'btn'; }
      }
    }
    return 'none';
  } catch(e){ return 'err'; }
})();
''';
  }

  static Future<void> _autofillLogin(
    InAppWebViewController ctrl,
    String login,
    CredentialsLoader loadCredentials,
  ) async {
    if (login.trim().isEmpty) return;
    final hasPw = await ctrl.evaluateJavascript(source: r'''
      (function(){return document.querySelector('input[type="password"]')?'1':'0';})();
    ''');
    if ((hasPw ?? '0').toString().trim() != '1') return;

    final accounts = await loadCredentials(EtollUrls.etollKey);
    String norm(String s) => s.trim().toLowerCase();
    final want = norm(login);
    final acc = accounts.cast<Map<String, String>?>().firstWhere(
          (a) => norm(a?['l'] ?? '') == want,
          orElse: () => null,
        );
    if (acc == null || acc.isEmpty) return;

    final l = (acc['l'] ?? '').replaceAll("'", "\\'");
    final p = (acc['p'] ?? '').replaceAll("'", "\\'");
    await ctrl.evaluateJavascript(source: '''
      (function(){
        function fire(el){el.focus();
          el.dispatchEvent(new Event('input',{bubbles:true}));
          el.dispatchEvent(new Event('change',{bubbles:true}));}
        var pw=document.querySelector('input[type="password"]');
        if(pw){pw.value='$p';fire(pw);}
        var cands=document.querySelectorAll('input[type="text"],input[type="email"]');
        for(var i=0;i<cands.length;i++){if(cands[i].offsetParent!==null){cands[i].value='$l';fire(cands[i]);break;}}
      })();
    ''');
    await Future.delayed(const Duration(milliseconds: 900));
    await ctrl.evaluateJavascript(source: r'''
      (function(){
        var btn=document.querySelector('button[type="submit"],input[type="submit"]');
        if(btn) btn.click();
      })();
    ''');
  }

  static Future<void> _enterFirm(
      InAppWebViewController ctrl, String subjectId) async {
    if (subjectId.isEmpty) return;
    await ctrl.evaluateJavascript(source: r'''
      (function(){try{
        var words=['active','aktywny','aktywna'];
        var els=document.querySelectorAll('span,div,button,a');
        for(var j=0;j<els.length;j++){
          var tx=(els[j].innerText||'').trim().toLowerCase();
          for(var w=0;w<words.length;w++){if(tx===words[w]){els[j].click();return;}}
        }
      }catch(e){}})();
    ''');
  }
}

