import 'package:flutter/material.dart';

import 'rc_theme.dart';

/// Тематическая эмблема для плиток меню (eTOLL, транспорт, фирмы).
enum PaymentTileEmblemKind { etoll, transport, firms }

/// Универсальный значок: градиент + неоновое свечение (главная, страны, меню).
class GlowBadge extends StatelessWidget {
  const GlowBadge({
    super.key,
    required this.glowColor,
    required this.child,
    this.size = 46,
    this.radius = 13,
    this.gradientColors,
    this.borderAlpha = 0.62,
    this.glowIntensity = 0.85,
  });

  final Color glowColor;
  final Widget child;
  final double size;
  final double radius;
  final List<Color>? gradientColors;
  final double borderAlpha;
  final double glowIntensity;

  factory GlowBadge.icon({
    required IconData icon,
    required Color color,
    double size = 44,
    double iconSize = 24,
    List<Color>? gradientColors,
    double glowIntensity = 0.85,
  }) {
    return GlowBadge(
      glowColor: color,
      size: size,
      radius: size >= 46 ? 13 : 12,
      gradientColors: gradientColors,
      glowIntensity: glowIntensity,
      child: Icon(
        icon,
        color: Colors.white,
        size: iconSize,
        shadows: [
          Shadow(color: color.withValues(alpha: 0.5), blurRadius: 8),
        ],
      ),
    );
  }

  factory GlowBadge.text({
    required String text,
    required Color color,
    String? overlayBottomLine,
    double size = 46,
    double fontSize = 16,
  }) {
    return GlowBadge(
      glowColor: color,
      size: size,
      child: Stack(
        alignment: Alignment.center,
        children: [
          Text(
            text,
            style: TextStyle(
              color: Colors.white,
              fontSize: fontSize,
              fontWeight: FontWeight.w700,
              letterSpacing: -0.5,
              shadows: [
                Shadow(color: color.withValues(alpha: 0.5), blurRadius: 8),
              ],
            ),
          ),
          if (overlayBottomLine != null)
            Positioned(
              bottom: 7,
              left: 9,
              right: 9,
              child: Container(
                height: 3,
                decoration: BoxDecoration(
                  color: Colors.white.withValues(alpha: 0.62),
                  borderRadius: BorderRadius.circular(2),
                  boxShadow: [
                    BoxShadow(
                      color: Colors.white.withValues(alpha: 0.2),
                      blurRadius: 4,
                    ),
                  ],
                ),
              ),
            ),
        ],
      ),
    );
  }

  static List<BoxShadow> glowShadows(Color glow, {double intensity = 1}) =>
      PaymentTileEmblem.glowShadows(glow, intensity: intensity);

  static List<Color> gradientFor(Color base) => [
        Color.lerp(base, Colors.white, 0.12)!,
        base,
        Color.lerp(base, const Color(0xFF0A0D14), 0.72)!,
      ];

  @override
  Widget build(BuildContext context) {
    final colors = gradientColors ?? gradientFor(glowColor);
    return SizedBox(
      width: size,
      height: size,
      child: DecoratedBox(
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(radius),
          gradient: LinearGradient(
            begin: Alignment.topLeft,
            end: Alignment.bottomRight,
            colors: colors,
            stops: colors.length >= 3
                ? const [0.0, 0.45, 1.0]
                : null,
          ),
          border: Border.all(
            color: glowColor.withValues(alpha: borderAlpha),
            width: 1.2,
          ),
          boxShadow: glowShadows(glowColor, intensity: glowIntensity),
        ),
        child: ClipRRect(
          borderRadius: BorderRadius.circular(radius),
          child: Stack(
            fit: StackFit.expand,
            children: [
              Positioned(
                top: -8,
                left: -4,
                child: Container(
                  width: size * 0.62,
                  height: size * 0.62,
                  decoration: BoxDecoration(
                    shape: BoxShape.circle,
                    gradient: RadialGradient(
                      colors: [
                        Colors.white.withValues(alpha: 0.18),
                        Colors.transparent,
                      ],
                    ),
                  ),
                ),
              ),
              Center(child: child),
            ],
          ),
        ),
      ),
    );
  }
}

