typedef BalanceTr = String Function(String key);
typedef CredentialsLoader = Future<List<Map<String, String>>> Function(String key);

/// Зависимости блока balance от main (без circular import).
class BalanceBindings {
  final BalanceTr tr;
  final Future<String?> Function() subjectId;
  final Future<String?> Function() accountId;
  final Future<String?> Function() lastBalance;
  final Future<String?> Function() company;
  final Future<String> Function() topUpAmount;
  final Future<String> Function() topUpCard4;
  final Future<void> Function(String card4) setTopUpCard4;
  final Future<bool> Function() autoTopUp;
  final Future<void> Function(bool v) setAutoTopUp;
  final CredentialsLoader loadCredentials;
  final Future<bool> Function({bool silent})? onRefreshBalance;

  const BalanceBindings({
    required this.tr,
    required this.subjectId,
    required this.accountId,
    required this.lastBalance,
    required this.company,
    required this.topUpAmount,
    required this.topUpCard4,
    required this.setTopUpCard4,
    required this.autoTopUp,
    required this.setAutoTopUp,
    required this.loadCredentials,
    this.onRefreshBalance,
  });
}

import 'package:flutter/material.dart';

import 'balance_bindings.dart';
import 'balance_colors.dart';
import 'etoll_details_fetcher.dart';
import 'etoll_details_model.dart';
import 'etoll_details_store.dart';
import 'top_up_web_screen.dart';

/// Нативный экран счёта eTOLL — стиль как на Details-странице.
class TopUpAccountScreen extends StatefulWidget {
  final String login;
  final String subjectId;
  final String language;
  final BalanceBindings bindings;

  const TopUpAccountScreen({
    super.key,
    required this.login,
    this.subjectId = '',
    this.language = 'ru',
    required this.bindings,
  });

  @override
  State<TopUpAccountScreen> createState() => _TopUpAccountScreenState();
}

class _TopUpAccountScreenState extends State<TopUpAccountScreen> {
  String _subjectId = '';
  String _accountId = '';
  String _balance = '';
  String _company = '';
  String _card4 = '';
  String _finType = '';
  String _autoMin = '50';
  String _autoFill = '100';
  bool _autoTopUp = false;
  bool _loading = true;
  bool _refreshing = false;
  bool _fetchingCard = false;

  String _tr(String k) => widget.bindings.tr(k);

  @override
  void initState() {
    super.initState();
    _load();
  }

  Future<void> _load() async {
    setState(() => _loading = true);

    _subjectId = widget.subjectId.trim().isNotEmpty
        ? widget.subjectId.trim()
        : (await widget.bindings.subjectId()) ?? '';
    _accountId = (await widget.bindings.accountId()) ?? '';
    _balance = (await widget.bindings.lastBalance()) ?? '';
    _company = (await widget.bindings.company()) ?? '';
    _autoTopUp = await widget.bindings.autoTopUp();

    final stored = await EtollDetailsStore.load(_subjectId);
    if (stored != null) _applyDetails(stored);

    final cardSaved = await widget.bindings.topUpCard4();
    if (_card4.isEmpty && cardSaved.isNotEmpty) _card4 = cardSaved;

    if (mounted) setState(() => _loading = false);

    if (_card4.isEmpty && _subjectId.isNotEmpty && _accountId.isNotEmpty) {
      _fetchDetails(); // background — не блокируем экран
    }
  }

  void _applyDetails(EtollPrepaidDetails d) {
    if (d.card4.isNotEmpty) _card4 = d.card4;
    if (d.finType.isNotEmpty) _finType = d.finType;
    if (d.autoMin.isNotEmpty) _autoMin = d.autoMin;
    if (d.autoFill.isNotEmpty) _autoFill = d.autoFill;
  }

  Future<void> _fetchDetails() async {
    if (_subjectId.isEmpty || _accountId.isEmpty) return;
    if (!mounted) return;
    setState(() => _fetchingCard = true);
    final d = await EtollDetailsFetcher.fetch(
      firmId: _subjectId,
      login: widget.login,
      subjectId: _subjectId,
      accountId: _accountId,
      loadCredentials: widget.bindings.loadCredentials,
      onCard4: widget.bindings.setTopUpCard4,
    );
    if (mounted) {
      setState(() {
        _fetchingCard = false;
        if (d != null) _applyDetails(d);
      });
    }
  }

  Future<void> _onRefreshTap() async {
    setState(() => _refreshing = true);
    final fn = widget.bindings.onRefreshBalance;
    if (fn != null) await fn(silent: true);
    await _load();
    if (mounted) setState(() => _refreshing = false);
  }

  void _openWeb(String directAction) {
    final canDirect =
        _subjectId.isNotEmpty && _accountId.isNotEmpty && directAction.isNotEmpty;
    Navigator.of(context).push(
      MaterialPageRoute(
        builder: (_) => TopUpWebScreen(
          title: directAction == 'changeCard'
              ? _tr('change_card')
              : _tr('etoll_topup'),
          login: widget.login,
          subjectId: _subjectId,
          accountId: _accountId,
          directAction: canDirect ? directAction : '',
          language: widget.language,
          tr: widget.bindings.tr,
          loadCredentials: widget.bindings.loadCredentials,
          topUpAmount: widget.bindings.topUpAmount,
        ),
      ),
    ).then((_) => _load());
  }

  String _finTypeLabel() {
    if (_finType == 'auto') return _tr('fin_type_auto');
    if (_finType == 'prepay') return _tr('fin_type_prepay');
    if (_autoTopUp) return _tr('fin_type_auto');
    return '—';
  }

  @override
  Widget build(BuildContext context) {
    const green = Color(0xFF34C77B);
    const etRed = Color(0xFFE2231A);
    return Scaffold(
      backgroundColor: BalanceColors.background,
      appBar: AppBar(
        backgroundColor: BalanceColors.background,
        elevation: 0,
        iconTheme: const IconThemeData(color: BalanceColors.accent),
        title: Text(
          _tr('topup_title'),
          style: const TextStyle(color: BalanceColors.textPrimary, fontSize: 18),
        ),
        actions: [
          if (_refreshing)
            const Padding(
              padding: EdgeInsets.all(14),
              child: SizedBox(
                width: 22,
                height: 22,
                child: CircularProgressIndicator(
                    strokeWidth: 2, color: BalanceColors.accent),
              ),
            )
          else
            IconButton(
              tooltip: _tr('refresh'),
              icon: const Icon(Icons.refresh_rounded, color: BalanceColors.accent),
              onPressed: _onRefreshTap,
            ),
          IconButton(
            tooltip: _tr('to_home'),
            icon: const Icon(Icons.home_rounded, color: BalanceColors.accent),
            onPressed: () =>
                Navigator.of(context).popUntil((r) => r.isFirst),
          ),
        ],
      ),
      body: _loading
          ? const Center(
              child: CircularProgressIndicator(color: BalanceColors.accent))
          : ListView(
              padding: const EdgeInsets.fromLTRB(20, 8, 20, 24),
              children: [
                if (_company.isNotEmpty)
                  Padding(
                    padding: const EdgeInsets.only(bottom: 2),
                    child: Text(
                      _company,
                      style: const TextStyle(
                          color: BalanceColors.textMuted, fontSize: 13),
                    ),
                  ),
                if (_accountId.isNotEmpty)
                  Padding(
                    padding: const EdgeInsets.only(bottom: 14),
                    child: Text(
                      '${_tr("account_id")}: $_accountId',
                      style: const TextStyle(
                          color: BalanceColors.textMuted, fontSize: 12),
                    ),
                  ),
                // ── Карточка с данными счёта ──
                Container(
                  padding: const EdgeInsets.all(16),
                  decoration: BoxDecoration(
                    color: BalanceColors.surface,
                    borderRadius: BorderRadius.circular(14),
                    border: Border.all(color: BalanceColors.border),
                  ),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: [
                      _row(_tr('type_lbl'), _finTypeLabel()),
                      _row(
                        _tr('balance_etoll'),
                        _balance.isNotEmpty ? _balance : '—',
                        valueColor: green,
                      ),
                      if (_finType == 'auto' || _autoTopUp) ...[
                        _row(_tr('topup_below'), '$_autoMin PLN'),
                        _row(_tr('topup_fill_amt'), '$_autoFill PLN'),
                      ],
                      const Padding(
                        padding: EdgeInsets.symmetric(vertical: 8),
                        child: Divider(height: 1, color: BalanceColors.border),
                      ),
                      // ── Карта инлайн ──
                      Row(
                        children: [
                          const Icon(Icons.credit_card,
                              color: BalanceColors.textMuted, size: 20),
                          const SizedBox(width: 8),
                          Expanded(
                            child: _fetchingCard && _card4.isEmpty
                                ? Row(
                                    children: [
                                      const SizedBox(
                                        width: 16,
                                        height: 16,
                                        child: CircularProgressIndicator(
                                            strokeWidth: 2,
                                            color: BalanceColors.accent),
                                      ),
                                      const SizedBox(width: 8),
                                      Text(
                                        '…',
                                        style: const TextStyle(
                                            color: BalanceColors.textMuted,
                                            fontSize: 14),
                                      ),
                                    ],
                                  )
                                : Text(
                                    _card4.isNotEmpty
                                        ? '•••• $_card4'
                                        : _tr('card_not_linked'),
                                    style: TextStyle(
                                      color: _card4.isNotEmpty
                                          ? BalanceColors.textPrimary
                                          : BalanceColors.textMuted,
                                      fontSize: 14,
                                      fontWeight: _card4.isNotEmpty
                                          ? FontWeight.w700
                                          : FontWeight.normal,
                                    ),
                                  ),
                          ),
                          TextButton(
                            onPressed: () => _openWeb('changeCard'),
                            style: TextButton.styleFrom(
                              padding: const EdgeInsets.symmetric(
                                  horizontal: 8, vertical: 4),
                              tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                            ),
                            child: Text(
                              _tr('change_card'),
                              style: const TextStyle(
                                  color: BalanceColors.accent, fontSize: 13),
                            ),
                          ),
                        ],
                      ),
                    ],
                  ),
                ),
                const SizedBox(height: 20),
                // ── Кнопка «Пополнить счёт» ──
                SizedBox(
                  height: 52,
                  child: ElevatedButton.icon(
                    onPressed: () => _openWeb('topUp'),
                    icon: const Icon(Icons.add_card,
                        color: Colors.white, size: 20),
                    label: Text(
                      _tr('topup_account_btn'),
                      style: const TextStyle(
                          color: Colors.white,
                          fontWeight: FontWeight.w800,
                          fontSize: 16),
                    ),
                    style: ElevatedButton.styleFrom(
                      backgroundColor: etRed,
                      shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(14)),
                    ),
                  ),
                ),
                const SizedBox(height: 12),
                // ── Тоггл автопополнения ──
                SwitchListTile(
                  contentPadding: EdgeInsets.zero,
                  title: Text(
                    _tr('autopay'),
                    style: const TextStyle(
                        color: BalanceColors.textPrimary,
                        fontWeight: FontWeight.w600),
                  ),
                  value: _autoTopUp,
                  activeColor: etRed,
                  onChanged: (v) {
                    setState(() => _autoTopUp = v);
                    widget.bindings.setAutoTopUp(v);
                  },
                ),
              ],
            ),
    );
  }

  Widget _row(String label, String value, {Color? valueColor}) {
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 6),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          SizedBox(
            width: 130,
            child: Text(
              label,
              style: const TextStyle(
                  color: BalanceColors.textMuted, fontSize: 14),
            ),
          ),
          Expanded(
            child: Text(
              value,
              style: TextStyle(
                color: valueColor ?? BalanceColors.textPrimary,
                fontSize: 15,
                fontWeight: FontWeight.w600,
              ),
            ),
          ),
        ],
      ),
    );
  }
}

