    // Фоновый fetch карты: запускаем только если карта ещё не сохранена.
    final existingCard = await BalanceStore.topUpCard4();
    final accIdForFetch = (aid ?? '').trim().isNotEmpty
        ? aid!.trim()
        : await BalanceStore.resolvedAccountId();
    if (existingCard.isEmpty &&
        sid != null && sid.isNotEmpty &&
        accIdForFetch.isNotEmpty) {
      final savedDetails = await EtollDetailsStore.load(sid);
      if (savedDetails == null || savedDetails.card4.isEmpty) {
        final firms = await BalanceStore.firms();
        final firm = firms.firstWhere(
            (f) => (f['id'] ?? '') == sid,
            orElse: () => <String, String>{});
        var login = (firm['login'] ?? '').trim();
        if (login.isEmpty) {
          final accs =
              await CredentialStore.loadAll('https://etoll.gov.pl/');
          if (accs.isNotEmpty) login = (accs.first['l'] ?? '').trim();
        }
        EtollDetailsFetcher.fetch(
          firmId: sid,
          login: login,
          subjectId: sid,
          accountId: accIdForFetch,
          loadCredentials: CredentialStore.loadAll,
          onCard4: BalanceStore.setTopUpCard4,
        );
      }
    }
  }
}

