import 'package:flutter/material.dart';

import 'balance_bindings.dart';
import 'balance_colors.dart';
import 'etoll_details_fetcher.dart';
import 'etoll_details_model.dart';
import 'etoll_details_store.dart';
import 'top_up_web_screen.dart';

/// Стильный экран eTOLL-счёта: карточный UI, карта — именно этой фирмы.
class TopUpAccountScreen extends StatefulWidget {
  final String login;
  final String subjectId;
  final String language;
  final BalanceBindings bindings;

  const TopUpAccountScreen({
    super.key,
    required this.login,
    this.subjectId = '',
    this.language = 'ru',
    required this.bindings,
  });

  @override
  State<TopUpAccountScreen> createState() => _TopUpAccountScreenState();
}

class _TopUpAccountScreenState extends State<TopUpAccountScreen> {
  String _subjectId = '';
  String _accountId = '';
  String _balance = '';
  String _company = '';
  String _card4 = '';
  String _finType = '';
  String _autoMin = '50';
  String _autoFill = '100';
  bool _autoTopUp = false;
  bool _loading = true;
  bool _refreshing = false;
  bool _fetchingCard = false;

  static const _green = Color(0xFF34C77B);
  static const _etRed = Color(0xFFE2231A);

  String _tr(String k) => widget.bindings.tr(k);

  @override
  void initState() {
    super.initState();
    _load();
  }

  Future<void> _load() async {
    setState(() => _loading = true);

    _subjectId = widget.subjectId.trim().isNotEmpty
        ? widget.subjectId.trim()
        : (await widget.bindings.subjectId()) ?? '';
    _accountId = (await widget.bindings.accountId()) ?? '';
    _balance = (await widget.bindings.lastBalance()) ?? '';
    _company = (await widget.bindings.company()) ?? '';
    _autoTopUp = await widget.bindings.autoTopUp();

    // Карта — только из per-firm хранилища этой фирмы.
    final stored = await EtollDetailsStore.load(_subjectId);
    if (stored != null) _applyDetails(stored);

    if (mounted) setState(() => _loading = false);

    // Если карта ещё не сохранена — запускаем fetch в фоне.
    if (_card4.isEmpty && _subjectId.isNotEmpty && _accountId.isNotEmpty) {
      _fetchDetails();
    }
  }

  void _applyDetails(EtollPrepaidDetails d) {
    if (d.card4.isNotEmpty) _card4 = d.card4;
    if (d.finType.isNotEmpty) _finType = d.finType;
    if (d.autoMin.isNotEmpty) _autoMin = d.autoMin;
    if (d.autoFill.isNotEmpty) _autoFill = d.autoFill;
  }

  Future<void> _fetchDetails() async {
    if (_subjectId.isEmpty || _accountId.isEmpty) return;
    if (!mounted) return;
    setState(() => _fetchingCard = true);
    final d = await EtollDetailsFetcher.fetch(
      firmId: _subjectId,
      login: widget.login,
      subjectId: _subjectId,
      accountId: _accountId,
      loadCredentials: widget.bindings.loadCredentials,
      onCard4: widget.bindings.setTopUpCard4,
    );
    if (mounted) {
      setState(() {
        _fetchingCard = false;
        if (d != null) _applyDetails(d);
      });
    }
  }

  Future<void> _onRefreshTap() async {
    setState(() => _refreshing = true);
    final fn = widget.bindings.onRefreshBalance;
    if (fn != null) await fn(silent: true);
    // После обновления баланса — сбрасываем кеш карты и снова читаем.
    setState(() => _card4 = '');
    await _load();
    if (mounted) setState(() => _refreshing = false);
  }

  void _openWeb(String directAction) {
    final canDirect =
        _subjectId.isNotEmpty && _accountId.isNotEmpty;
    Navigator.of(context).push(
      MaterialPageRoute(
        builder: (_) => TopUpWebScreen(
          title: directAction == 'changeCard'
              ? _tr('change_card')
              : _tr('etoll_topup'),
          login: widget.login,
          subjectId: _subjectId,
          accountId: _accountId,
          directAction: canDirect ? directAction : '',
          language: widget.language,
          tr: widget.bindings.tr,
          loadCredentials: widget.bindings.loadCredentials,
          topUpAmount: widget.bindings.topUpAmount,
        ),
      ),
    ).then((_) => _load());
  }

  String _finTypeLabel() {
    if (_finType == 'auto') return _tr('fin_type_auto');
    if (_finType == 'prepay') return _tr('fin_type_prepay');
    if (_autoTopUp) return _tr('fin_type_auto');
    return '—';
  }

  // ── BUILD ────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: BalanceColors.background,
      appBar: _buildAppBar(),
      body: _loading
          ? const Center(
              child: CircularProgressIndicator(color: BalanceColors.accent))
          : ListView(
              padding: const EdgeInsets.fromLTRB(16, 12, 16, 28),
              children: [
                _buildVisualCard(),
                const SizedBox(height: 16),
                _buildBalanceTile(),
                const SizedBox(height: 10),
                _buildInfoChips(),
                const SizedBox(height: 20),
                _buildTopUpButton(),
                const SizedBox(height: 10),
                _buildAutoTopUpSwitch(),
              ],
            ),
    );
  }

  // ── AppBar ───────────────────────────────────────────────────

  AppBar _buildAppBar() {
    return AppBar(
      backgroundColor: BalanceColors.background,
      elevation: 0,
      iconTheme: const IconThemeData(color: BalanceColors.accent),
      title: Text(
        _tr('etoll_topup'),
        style: const TextStyle(
            color: BalanceColors.textPrimary, fontSize: 17),
      ),
      actions: [
        if (_refreshing)
          const Padding(
            padding: EdgeInsets.all(14),
            child: SizedBox(
              width: 20,
              height: 20,
              child: CircularProgressIndicator(
                  strokeWidth: 2, color: BalanceColors.accent),
            ),
          )
        else
          IconButton(
            tooltip: _tr('refresh'),
            icon: const Icon(Icons.refresh_rounded, color: BalanceColors.accent),
            onPressed: _onRefreshTap,
          ),
        IconButton(
          tooltip: _tr('to_home'),
          icon: const Icon(Icons.home_rounded, color: BalanceColors.accent),
          onPressed: () => Navigator.of(context).popUntil((r) => r.isFirst),
        ),
      ],
    );
  }

  // ── Визуальная карта ─────────────────────────────────────────

  Widget _buildVisualCard() {
    return Container(
      height: 175,
      width: double.infinity,
      decoration: BoxDecoration(
        gradient: const LinearGradient(
          begin: Alignment.topLeft,
          end: Alignment.bottomRight,
          colors: [Color(0xFF1B3058), Color(0xFF0B1525)],
        ),
        borderRadius: BorderRadius.circular(20),
        border: Border.all(
          color: BalanceColors.accent.withValues(alpha: 0.30),
          width: 1.5,
        ),
        boxShadow: [
          BoxShadow(
            color: BalanceColors.accent.withValues(alpha: 0.12),
            blurRadius: 24,
            offset: const Offset(0, 6),
          ),
        ],
      ),
      child: Stack(
        children: [
          // Декоративные окружности
          Positioned(
            right: -28,
            top: -28,
            child: Container(
              width: 130,
              height: 130,
              decoration: BoxDecoration(
                shape: BoxShape.circle,
                color: BalanceColors.accent.withValues(alpha: 0.05),
              ),
            ),
          ),
          Positioned(
            right: 18,
            bottom: -18,
            child: Container(
              width: 70,
              height: 70,
              decoration: BoxDecoration(
                shape: BoxShape.circle,
                color: _etRed.withValues(alpha: 0.07),
              ),
            ),
          ),
          // Контент
          Padding(
            padding: const EdgeInsets.fromLTRB(20, 18, 20, 16),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                // Шапка: eTOLL + NFC иконка
                Row(
                  mainAxisAlignment: MainAxisAlignment.spaceBetween,
                  children: [
                    const Text(
                      'eTOLL',
                      style: TextStyle(
                        color: _etRed,
                        fontSize: 20,
                        fontWeight: FontWeight.w900,
                        letterSpacing: 2,
                      ),
                    ),
                    Icon(
                      Icons.contactless_rounded,
                      color: BalanceColors.accent.withValues(alpha: 0.65),
                      size: 24,
                    ),
                  ],
                ),
                const Spacer(),
                // Номер карты
                _buildCardNumber(),
                const SizedBox(height: 12),
                // Низ: фирма + кнопка «Сменить карту»
                Row(
                  children: [
                    Expanded(
                      child: Text(
                        _company.isNotEmpty
                            ? _company.toUpperCase()
                            : 'ID: $_accountId',
                        style: TextStyle(
                          color: Colors.white.withValues(alpha: 0.45),
                          fontSize: 10,
                          letterSpacing: 0.8,
                          fontWeight: FontWeight.w600,
                        ),
                        maxLines: 1,
                        overflow: TextOverflow.ellipsis,
                      ),
                    ),
                    GestureDetector(
                      onTap: () => _openWeb('changeCard'),
                      child: Container(
                        padding: const EdgeInsets.symmetric(
                            horizontal: 10, vertical: 4),
                        decoration: BoxDecoration(
                          border: Border.all(
                            color: BalanceColors.accent.withValues(alpha: 0.45),
                          ),
                          borderRadius: BorderRadius.circular(20),
                        ),
                        child: Text(
                          _tr('change_card'),
                          style: const TextStyle(
                            color: BalanceColors.accent,
                            fontSize: 11,
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildCardNumber() {
    if (_fetchingCard && _card4.isEmpty) {
      return Row(
        children: [
          const SizedBox(
            width: 15,
            height: 15,
            child: CircularProgressIndicator(
                strokeWidth: 2, color: BalanceColors.accent),
          ),
          const SizedBox(width: 10),
          Text(
            '${_tr("type_lbl")}…',
            style: TextStyle(
              color: Colors.white.withValues(alpha: 0.45),
              fontSize: 13,
            ),
          ),
        ],
      );
    }
    if (_card4.isNotEmpty) {
      return Text(
        '•••• •••• •••• $_card4',
        style: const TextStyle(
          color: Colors.white,
          fontSize: 19,
          fontWeight: FontWeight.w700,
          letterSpacing: 2.5,
        ),
      );
    }
    return Row(
      children: [
        Icon(Icons.credit_card,
            color: Colors.white.withValues(alpha: 0.28), size: 18),
        const SizedBox(width: 8),
        Text(
          _tr('card_not_linked'),
          style: TextStyle(
            color: Colors.white.withValues(alpha: 0.4),
            fontSize: 14,
          ),
        ),
      ],
    );
  }

  // ── Баланс ───────────────────────────────────────────────────

  Widget _buildBalanceTile() {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
      decoration: BoxDecoration(
        color: _green.withValues(alpha: 0.08),
        borderRadius: BorderRadius.circular(14),
        border: Border.all(color: _green.withValues(alpha: 0.25)),
      ),
      child: Row(
        children: [
          const Icon(Icons.account_balance_wallet_rounded,
              color: _green, size: 22),
          const SizedBox(width: 12),
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                _tr('balance_etoll'),
                style: TextStyle(
                    color: _green.withValues(alpha: 0.7), fontSize: 11),
              ),
              Text(
                _balance.isNotEmpty ? _balance : '—',
                style: const TextStyle(
                  color: _green,
                  fontSize: 22,
                  fontWeight: FontWeight.w900,
                  letterSpacing: 0.5,
                ),
              ),
            ],
          ),
        ],
      ),
    );
  }

  // ── Чипы инфо (тип, пороги) ──────────────────────────────────

  Widget _buildInfoChips() {
    final showAuto = _finType == 'auto' || _autoTopUp;
    return Wrap(
      spacing: 8,
      runSpacing: 8,
      children: [
        _chip(Icons.label_outline_rounded, _tr('type_lbl'), _finTypeLabel()),
        if (showAuto)
          _chip(Icons.arrow_downward_rounded, _tr('topup_below'),
              '$_autoMin PLN'),
        if (showAuto)
          _chip(Icons.add_circle_outline_rounded, _tr('topup_fill_amt'),
              '$_autoFill PLN'),
      ],
    );
  }

  Widget _chip(IconData icon, String label, String value) {
    return Container(
      padding: const EdgeInsets.fromLTRB(10, 7, 14, 7),
      decoration: BoxDecoration(
        color: BalanceColors.surface,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: BalanceColors.border),
      ),
      child: Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          Icon(icon, size: 14, color: BalanceColors.accent),
          const SizedBox(width: 6),
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            mainAxisSize: MainAxisSize.min,
            children: [
              Text(label,
                  style: const TextStyle(
                      color: BalanceColors.textMuted, fontSize: 10)),
              Text(value,
                  style: const TextStyle(
                      color: BalanceColors.textPrimary,
                      fontSize: 13,
                      fontWeight: FontWeight.w700)),
            ],
          ),
        ],
      ),
    );
  }

  // ── Кнопка пополнить ─────────────────────────────────────────

  Widget _buildTopUpButton() {
    return SizedBox(
      height: 54,
      child: ElevatedButton.icon(
        onPressed: () => _openWeb('topUp'),
        icon: const Icon(Icons.add_card_rounded, color: Colors.white, size: 20),
        label: Text(
          _tr('topup_account_btn'),
          style: const TextStyle(
            color: Colors.white,
            fontWeight: FontWeight.w800,
            fontSize: 16,
            letterSpacing: 0.5,
          ),
        ),
        style: ElevatedButton.styleFrom(
          backgroundColor: _etRed,
          elevation: 4,
          shadowColor: _etRed.withValues(alpha: 0.35),
          shape: RoundedRectangleBorder(
              borderRadius: BorderRadius.circular(14)),
        ),
      ),
    );
  }

  // ── Автопополнение ───────────────────────────────────────────

  Widget _buildAutoTopUpSwitch() {
    return Container(
      decoration: BoxDecoration(
        color: BalanceColors.surface,
        borderRadius: BorderRadius.circular(14),
        border: Border.all(color: BalanceColors.border),
      ),
      child: SwitchListTile(
        contentPadding:
            const EdgeInsets.symmetric(horizontal: 16, vertical: 2),
        title: Text(
          _tr('autopay'),
          style: const TextStyle(
              color: BalanceColors.textPrimary,
              fontWeight: FontWeight.w600,
              fontSize: 15),
        ),
        subtitle: Text(
          _finTypeLabel(),
          style: const TextStyle(
              color: BalanceColors.textMuted, fontSize: 12),
        ),
        value: _autoTopUp,
        activeThumbColor: _etRed,
        activeTrackColor: _etRed.withValues(alpha: 0.35),
        onChanged: (v) {
          setState(() => _autoTopUp = v);
          widget.bindings.setAutoTopUp(v);
        },
      ),
    );
  }
}

