/// ID prepaid-счёта: сначала per-firm снимок текущей фирмы, затем глобальный.
/// Глобальный accountId может содержать данные другой фирмы — не доверяем.
static Future<String> resolvedAccountId() async {
  final sid = await subjectId();
  if (sid != null && sid.isNotEmpty) {
    final infos = await _readFirmInfos();
    final m = infos[sid];
    if (m is Map) {
      final firmId = (m['accountId'] ?? '').toString().trim();
      if (firmId.isNotEmpty) return firmId;
    }
  }
  // Fallback: глобальный ключ (может быть устаревшим после смены фирмы)
  final direct = await accountId();
  if (direct != null && direct.isNotEmpty) return direct;
  return '';
}

