static Future<EtollPrepaidDetails?> _doFetch({
  required String firmId,
  required String login,
  required String subjectId,
  required String accountId,
  required CredentialsLoader loadCredentials,
  void Function(String card4)? onCard4,
}) async {

  HeadlessInAppWebView? headless;
  InAppWebViewController? ctrl;
  EtollPrepaidDetails? result;

  // Целевая страница details
  final target = EtollUrls.prepaidDetails(subjectId, accountId);
  // Стартуем с базового URL — так же как _refreshInBackground.
  // Это работает при активной сессии И при expired сессии (логин не теряет #hash).
  const baseUrl = EtollUrls.base;

  try {
    headless = HeadlessInAppWebView(
      initialSize: const Size(412, 915),
      initialUrlRequest: URLRequest(url: WebUri(baseUrl)),
      initialSettings: InAppWebViewSettings(
        userAgent: _ua,
        javaScriptEnabled: true,
        domStorageEnabled: true,
        thirdPartyCookiesEnabled: true,
        useHybridComposition: false,
      ),
      onWebViewCreated: (c) => ctrl = c,
    );
    await headless.run();

    bool navigatedToTarget = false;
    bool loginDone = false;
    int detailsRetries = 0;

    for (int i = 0; i < 100 && result == null; i++) {
      await Future.delayed(const Duration(milliseconds: 500));
      if (ctrl == null) continue;
      final cur = (await ctrl!.getUrl())?.toString() ?? '';
      final lu = cur.toLowerCase();

      // Принять cookie-баннер на любой странице
      await ctrl!.evaluateJavascript(source: _acceptCookiesJs);
      // Переключить язык
      await ctrl!.evaluateJavascript(source: EtollPreferEnglish.js);

      // ── Уже на странице details → парсим ──
      if (lu.contains('/details') && lu.contains('/prepaid')) {
        detailsRetries++;
        final raw = await ctrl!.evaluateJavascript(
            source: EtollDetailsParser.parseJs);
        final parsed = EtollDetailsParser.parseResult(raw);
        if (parsed.hasCard || parsed.finType.isNotEmpty) {
          result = parsed;
          await EtollDetailsStore.save(firmId, parsed);
          if (parsed.hasCard && onCard4 != null) {
            onCard4(parsed.card4);
          }
          break;
        }
        // Страница ещё рендерится — ждём (не дольше 8 секунд)
        if (detailsRetries < 16) continue;
        break; // не нашли — выходим
      }

      // ── На странице financing/prepaid (список) → кликаем Details ──
      if (lu.contains('/financing') && lu.contains('/prepaid') &&
          !lu.contains('/details')) {
        await ctrl!.evaluateJavascript(source: _clickDetailsJs(accountId));
        continue;
      }

      // ── На странице financing (основная) → кликаем на prepaid ──
      if (lu.contains('/financing') && !lu.contains('/prepaid')) {
        await ctrl!.evaluateJavascript(source: _clickPrepaidJs(accountId));
        continue;
      }

      // ── Страница логина ──
      if (lu.contains('login') || lu.contains('logowanie') ||
          lu.contains('/auth/')) {
        await ctrl!.evaluateJavascript(source: _selectLoginMethodJs);
        await _autofillLogin(ctrl!, login, loadCredentials);
        continue;
      }

      // ── Selfservice root / dashboard после логина ──
      if (lu.contains('/selfservice') && !lu.contains('/subject')) {
        if (loginDone) {
          // Второй раз здесь — идём напрямую на target
          if (!navigatedToTarget) {
            navigatedToTarget = true;
            try {
              await ctrl!.loadUrl(urlRequest: URLRequest(url: WebUri(target)));
            } catch (_) {}
          }
        } else {
          loginDone = true;
          await _enterFirm(ctrl!, subjectId);
          await Future.delayed(const Duration(milliseconds: 1200));
          // После выбора фирмы — идём к details
          if (!navigatedToTarget) {
            navigatedToTarget = true;
            try {
              await ctrl!.loadUrl(urlRequest: URLRequest(url: WebUri(target)));
            } catch (_) {}
          }
        }
        continue;
      }

      // ── На странице фирмы, но не на financing → идём на details ──
      if (lu.contains('/subject/$subjectId') && !navigatedToTarget) {
        navigatedToTarget = true;
        try {
          await ctrl!.loadUrl(urlRequest: URLRequest(url: WebUri(target)));
        } catch (_) {}
        continue;
      }

      // ── Неизвестная страница → после 3 тиков идём на target ──
      if (i > 5 && !lu.contains('/details') && !navigatedToTarget) {
        navigatedToTarget = true;
        try {
          await ctrl!.loadUrl(urlRequest: URLRequest(url: WebUri(target)));
        } catch (_) {}
      }
    }
  } catch (_) {
  } finally {
    try {
      await headless?.dispose();
    } catch (_) {}
  }
  return result;
}

