class EtollPrepaidDetails {
  final String card4;      // последние 4 цифры
  final String cardFirst4; // первые 4 цифры (если eTOLL показывает)
  final String cardType;   // 'visa' | 'mastercard' | ''
  final String finType;    // 'auto' | 'prepay' | ''
  final String autoMin;
  final String autoFill;

  const EtollPrepaidDetails({
    this.card4 = '',
    this.cardFirst4 = '',
    this.cardType = '',
    this.finType = '',
    this.autoMin = '',
    this.autoFill = '',
  });

  bool get hasCard => card4.length == 4;

  /// Тип карты: явный → иначе вывод из первой цифры cardFirst4.
  String get resolvedCardType {
    if (cardType.isNotEmpty) return cardType;
    if (cardFirst4.isNotEmpty) {
      final f = cardFirst4[0];
      if (f == '4') return 'visa';
      if (f == '5' || f == '2') return 'mastercard';
    }
    return '';
  }

  Map<String, dynamic> toJson() => {
        'card4': card4,
        'cardFirst4': cardFirst4,
        'cardType': cardType,
        'finType': finType,
        'autoMin': autoMin,
        'autoFill': autoFill,
      };

  factory EtollPrepaidDetails.fromJson(Map<String, dynamic> m) {
    return EtollPrepaidDetails(
      card4: (m['card4'] ?? '').toString(),
      cardFirst4: (m['cardFirst4'] ?? '').toString(),
      cardType: (m['cardType'] ?? '').toString(),
      finType: (m['finType'] ?? '').toString(),
      autoMin: (m['autoMin'] ?? '').toString(),
      autoFill: (m['autoFill'] ?? '').toString(),
    );
  }
}

import 'dart:convert';

import 'etoll_details_model.dart';

/// JS для парсинга страницы prepaid/…/details eTOLL.
abstract final class EtollDetailsParser {
  static const parseJs = r'''
(function(){
  try {
    var t = (document.body && document.body.innerText) ? document.body.innerText : '';
    var out = {card4:'', cardFirst4:'', cardType:'', finType:'', autoMin:'', autoFill:''};

    // ── Номер карты ──
    // Ищем маскированный номер: первые 4-6 цифр + маска + последние 4 цифры.
    // eTOLL показывает, например: "4434 5... ...3645" или "4434 ●●●● ●●●● 3645"
    var cardFound = false;
    var lines = t.split('\n');
    for (var li = 0; li < lines.length; li++) {
      var ln = lines[li];
      // строка должна содержать замаскированные символы
      if (!/[•●\*\.…Xx]{3,}/.test(ln) && !/\d{4}\s[•●\*\.…X]{4}/.test(ln)) continue;
      // извлечь первые цифры
      var fm = ln.match(/(\d{4,6})/);
      // извлечь последние 4 цифры (не раньше середины строки)
      var all4 = ln.match(/\d{4}/g);
      if (fm && all4 && all4.length >= 1) {
        out.cardFirst4 = fm[1].substring(0, 4);
        out.card4 = all4[all4.length - 1];
        // не брать одну и ту же группу как first4 и card4
        if (out.cardFirst4 !== out.card4) { cardFound = true; break; }
        // если совпали — берём только card4
        out.cardFirst4 = '';
        cardFound = true;
        break;
      }
    }

    // Запасной вариант: только последние 4 цифры по ключевым словам
    if (!cardFound) {
      var cm = t.match(/(?:••••|●{4}|\*{4}|\.{3}|…)\s*(\d{4})/i)
            || t.match(/visa[^\d]{0,20}(\d{4})/i)
            || t.match(/mastercard[^\d]{0,20}(\d{4})/i)
            || t.match(/(?:karta|card|nr karty)[^\d]{0,30}(\d{4})/i);
      if (cm) out.card4 = cm[1];
    }

    // ── Тип карты из текста ──
    var tl = t.toLowerCase();
    if (tl.indexOf('mastercard') >= 0 || tl.indexOf('master card') >= 0) {
      out.cardType = 'mastercard';
    } else if (tl.indexOf('visa') >= 0) {
      out.cardType = 'visa';
    }
    // Уточнить по первой цифре, если тип ещё не известен
    if (!out.cardType && out.cardFirst4) {
      var f = out.cardFirst4.charAt(0);
      if (f === '4') out.cardType = 'visa';
      else if (f === '5' || f === '2') out.cardType = 'mastercard';
    }

    // ── Тип финансирования ──
    if (tl.indexOf('automatic') >= 0 || tl.indexOf('automat') >= 0) out.finType = 'auto';
    else if (tl.indexOf('prepaid') >= 0 || tl.indexOf('prepay') >= 0) out.finType = 'prepay';

    // ── Пороги автопополнения ──
    var nums = t.match(/(\d+(?:[.,]\d+)?)\s*PLN/gi) || [];
    var plain = [];
    for (var i = 0; i < nums.length; i++) {
      var n = nums[i].replace(/PLN/i,'').replace(/\s/g,'').replace(',','.');
      plain.push(n);
    }
    if (plain.length >= 2) { out.autoMin = plain[0]; out.autoFill = plain[1]; }
    else if (plain.length === 1) { out.autoMin = plain[0]; }
    var thresh = t.match(/(?:below|under|poni[żz]ej|mniej|threshold|pr[óo]g)[^\d]{0,40}(\d+)/i);
    if (thresh) out.autoMin = thresh[1];
    var fill = t.match(/(?:amount|kwot|sum|fill|do[łl]ad)[^\d]{0,40}(\d+)/i);
    if (fill && !out.autoFill) out.autoFill = fill[1];

    return JSON.stringify(out);
  } catch(e) { return '{}'; }
})();
''';

  static EtollPrepaidDetails parseResult(dynamic jsResult) {
    try {
      final raw = (jsResult ?? '{}').toString().trim();
      if (raw.isEmpty || raw == 'null') return const EtollPrepaidDetails();
      final decoded = jsonDecode(raw);
      if (decoded is! Map) return const EtollPrepaidDetails();
      return EtollPrepaidDetails.fromJson(Map<String, dynamic>.from(decoded));
    } catch (_) {
      return const EtollPrepaidDetails();
    }
  }
}

