import 'dart:convert';

import 'etoll_details_model.dart';

/// JS для парсинга страницы prepaid/…/details eTOLL.
/// Карта на странице выглядит как «Visa •••• 3441» или «44345... ...3645».
abstract final class EtollDetailsParser {
  static const parseJs = r'''
(function(){
  function digits(s){ return (s||'').replace(/[^0-9]/g,''); }
  try {
    var out = {card4:'', cardFirst4:'', cardType:'', finType:'', autoMin:'', autoFill:'', dump:''};
    var body = (document.body && document.body.innerText) ? document.body.innerText : '';

    // ── 1) Поиск номера карты ──
    // Маркеры маскировки: точки, звёздочки, буллеты, X.
    var maskRe = /[•●○*Xx]{2,}|\.{3,}|…/;

    // a) Прямой шаблон: первые цифры + маска + последние 4
    //    «4434 5•• •••• 3645», «443450 ●●●●●● 3645», «4434 ... 3645»
    var direct = body.match(/(\d{4,6})[\s\u00A0]*(?:[•●○*Xx]{2,}|\.{3,}|…)[\s\u00A0•●○*Xx.…\d]*?(\d{4})(?!\d)/);
    if (direct) {
      var f = direct[1], l = direct[2];
      if (f !== l) { out.cardFirst4 = f.substring(0,4); out.card4 = l; }
      else { out.card4 = l; }
    }

    // b) Построчный разбор — если прямой шаблон не сработал
    if (!out.card4) {
      var lines = body.split('\n');
      for (var i=0;i<lines.length;i++){
        var ln = lines[i];
        if (!maskRe.test(ln)) continue;
        var groups = ln.match(/\d{2,6}/g);
        if (!groups || groups.length === 0) continue;
        // последняя группа из 4 цифр = последние 4
        var last4 = '';
        for (var g=groups.length-1; g>=0; g--){ if (groups[g].length>=4){ last4 = groups[g].slice(-4); break; } }
        if (!last4) continue;
        out.card4 = last4;
        // первая группа (>=4 цифр) и не равна последней = первые цифры
        if (groups[0].length>=4 && groups[0].substring(0,4)!==last4) out.cardFirst4 = groups[0].substring(0,4);
        break;
      }
    }

    // c) По ключевым словам (последние 4)
    if (!out.card4) {
      var kw = body.match(/(?:karta|card|nr\s*karty|card\s*number|numer\s*karty)[^\d]{0,40}(\d{4})(?!\d)/i);
      if (kw) out.card4 = kw[1];
    }

    // ── 2) Тип карты ──
    var bl = body.toLowerCase();
    if (bl.indexOf('mastercard')>=0 || bl.indexOf('master card')>=0) out.cardType='mastercard';
    else if (bl.indexOf('visa')>=0) out.cardType='visa';
    else if (bl.indexOf('maestro')>=0) out.cardType='mastercard';
    if (!out.cardType && out.cardFirst4){
      var d0 = out.cardFirst4.charAt(0);
      if (d0==='4') out.cardType='visa';
      else if (d0==='5'||d0==='2') out.cardType='mastercard';
    }

    // ── 3) Тип финансирования ──
    if (bl.indexOf('automatic')>=0 || bl.indexOf('automat')>=0) out.finType='auto';
    else if (bl.indexOf('prepaid')>=0 || bl.indexOf('prepay')>=0 || bl.indexOf('przedp')>=0) out.finType='prepay';

    // ── 4) Пороги (PLN) ──
    var nums = body.match(/(\d+(?:[.,]\d+)?)\s*PLN/gi) || [];
    var plain = [];
    for (var n=0;n<nums.length;n++){ plain.push(nums[n].replace(/PLN/i,'').replace(/\s/g,'').replace(',','.')); }
    if (plain.length>=2){ out.autoMin=plain[0]; out.autoFill=plain[1]; }
    else if (plain.length===1){ out.autoMin=plain[0]; }
    var th = body.match(/(?:below|under|poni[żz]ej|mniej|threshold|pr[óo]g)[^\d]{0,40}(\d+)/i);
    if (th) out.autoMin=th[1];
    var fl = body.match(/(?:amount|kwot|sum|fill|do[łl]ad)[^\d]{0,40}(\d+)/i);
    if (fl && !out.autoFill) out.autoFill=fl[1];

    // ── 5) Диагностика: первые 600 символов текста страницы ──
    out.dump = body.replace(/\s+/g,' ').trim().substring(0,600);

    return JSON.stringify(out);
  } catch(e) { return JSON.stringify({card4:'',dump:'ERR:'+e}); }
})();
''';

  static EtollPrepaidDetails parseResult(dynamic jsResult) {
    try {
      final raw = (jsResult ?? '{}').toString().trim();
      if (raw.isEmpty || raw == 'null') return const EtollPrepaidDetails();
      final decoded = jsonDecode(raw);
      if (decoded is! Map) return const EtollPrepaidDetails();
      return EtollPrepaidDetails.fromJson(Map<String, dynamic>.from(decoded));
    } catch (_) {
      return const EtollPrepaidDetails();
    }
  }

  /// Извлечь dump-текст страницы (для диагностики), не парся в модель.
  static String dumpOf(dynamic jsResult) {
    try {
      final decoded = jsonDecode((jsResult ?? '{}').toString());
      if (decoded is Map) return (decoded['dump'] ?? '').toString();
    } catch (_) {}
    return '';
  }
}

