      if (lu.contains('/financing') && !lu.contains('/details')) {
        diagStage = 'financing';
        financingTicks++;
        if (!directDetailsTried && financingTicks >= 2) {
          // дать списку прогрузиться, затем прямой переход на details
          directDetailsTried = true;
          try {
            await ctrl!.loadUrl(urlRequest: URLRequest(url: WebUri(target)));
          } catch (_) {}
          await Future.delayed(const Duration(milliseconds: 1500));
        } else {
          // запасной путь — клики по списку: prepaid-счёт → Details
          if (lu.contains('/prepaid')) {
            await ctrl!.evaluateJavascript(source: _clickDetailsJs(accountId));
          } else {
            await ctrl!.evaluateJavascript(source: _clickPrepaidJs(accountId));
          }
        }
        continue;
      }

      // 5) ── Не в financing (после логина закинуло на дашборд) → в financing ──
      if (lu.contains('/selfservice') && !lu.contains('login')) {
        diagStage = 'reenter-financing';
        if (i % 4 == 0 || !wentFinancingList) {
          wentFinancingList = true;
          try {
            await ctrl!.loadUrl(
                urlRequest: URLRequest(url: WebUri(financingListUrl)));
          } catch (_) {}
          await Future.delayed(const Duration(milliseconds: 1500));
        }
        continue;
      }
    }
  } catch (e) {
    diagStage = 'error';
  } finally {
    // Сохраняем диагностику (видно на экране, если карта пустая).
    try {
      final shortUrl = diagUrl.contains('#')
          ? diagUrl.substring(diagUrl.indexOf('#'))
          : diagUrl;
      final dumpShort = diagDump.isEmpty
          ? ''
          : ' | ${diagDump.substring(0, diagDump.length > 80 ? 80 : diagDump.length)}';
      await EtollDetailsStore.saveDiag(
          firmId, '[$diagStage] aid=$accountId $shortUrl$dumpShort');
    } catch (_) {}
    // Перед закрытием очищаем страницу (против чёрного кадра) и закрываем.
    try {
      await ctrl?.loadUrl(urlRequest: URLRequest(url: WebUri('about:blank')));
      await Future.delayed(const Duration(milliseconds: 200));
    } catch (_) {}
    try {
      await headless?.dispose();
    } catch (_) {}
  }
  return result;
}

