/// JS-навигация по ветке financing (карта только тут, не billing).
abstract final class EtollFinancingNav {
  /// Достать prepaid ID со страницы financing/list (поле «ID: 822538» или ссылка Details).
  static const extractAccountIdJs = r'''
(function(){
  try {
    var body = (document.body && document.body.innerText) ? document.body.innerText : '';
    var m = body.match(/\bID\s*:?\s*(\d{5,10})\b/i);
    if (m) return m[1];
    var links = document.querySelectorAll('a[href*="/financing/prepaid/"]');
    for (var i=0;i<links.length;i++){
      var hm = (links[i].getAttribute('href')||'').match(/prepaid\/(\d+)/);
      if (hm) return hm[1];
    }
    links = document.querySelectorAll('a[href*="/details"]');
    for (var j=0;j<links.length;j++){
      var hm2 = (links[j].getAttribute('href')||'').match(/prepaid\/(\d+)/);
      if (hm2) return hm2[1];
    }
    var html = document.body ? document.body.innerHTML : '';
    var m3 = html.match(/prepaid\/(\d{5,10})/);
    return m3 ? m3[1] : '';
  } catch(e){ return ''; }
})();
''';

  /// На financing/list — нажать «Details» / «Szczegóły» (как на скрине пользователя).
  static String clickDetailsJs(String accountId) {
    final aid = accountId.replaceAll("'", '');
    return '''
(function(){
  try {
    function realClick(el){
      try {
        var r=el.getBoundingClientRect();
        var o={bubbles:true,cancelable:true,view:window,
          clientX:r.left+r.width/2,clientY:r.top+r.height/2};
        el.dispatchEvent(new MouseEvent('pointerdown',o));
        el.dispatchEvent(new MouseEvent('mousedown',o));
        el.dispatchEvent(new MouseEvent('mouseup',o));
        el.dispatchEvent(new MouseEvent('click',o));
        el.click();
      } catch(e){ try{el.click();}catch(e2){} }
    }
    var aid='$aid';
    if (aid) {
      var fa=document.querySelectorAll('a[href*="/financing/prepaid/'+aid+'"]');
      for (var i=0;i<fa.length;i++){
        if (fa[i].offsetParent!==null){ realClick(fa[i]); return 'prepaid-link'; }
      }
      var fd=document.querySelectorAll('a[href*="/prepaid/'+aid+'/details"]');
      for (var d=0;d<fd.length;d++){
        if (fd[d].offsetParent!==null){ realClick(fd[d]); return 'details-link'; }
      }
    }
    var words=['details','szczegóły','szczegoly','szczeg'];
    var els=document.querySelectorAll('a,button,[role="button"]');
    for (var j=0;j<els.length;j++){
      var el=els[j]; if(el.offsetParent===null) continue;
      var t=(el.innerText||'').trim().toLowerCase();
      for (var w=0;w<words.length;w++){
        if (t===words[w]||t.indexOf(words[w])===0){ realClick(el); return 'details-btn'; }
      }
    }
    return 'none';
  } catch(e){ return 'err'; }
})();
''';
  }

  static String prepaidDetailsUrl(String subjectId, String accountId) =>
      'https://mojekonto.etoll.gov.pl/selfservice/#/mobile/subject/$subjectId/financing/prepaid/$accountId/details';
}

