/// Определение платёжной системы по BIN (первые цифры номера карты).
abstract final class CardBrandDetect {
  /// Канонические id: visa, mastercard, maestro, amex, discover, diners, jcb, unionpay, mir.
  static String fromBin(String bin) {
    final d = bin.replaceAll(RegExp(r'\D'), '');
    if (d.isEmpty) return '';

    final n4 = d.length >= 4 ? int.tryParse(d.substring(0, 4)) : null;
    final n3 = d.length >= 3 ? int.tryParse(d.substring(0, 3)) : null;
    final n2 = d.length >= 2 ? int.tryParse(d.substring(0, 2)) : null;
    final n1 = int.tryParse(d.substring(0, 1));

    if (n4 != null) {
      if (n4 >= 2200 && n4 <= 2204) return 'mir';
      if (n4 >= 2221 && n4 <= 2720) return 'mastercard';
      if (n4 >= 3528 && n4 <= 3589) return 'jcb';
      if (n4 == 6011) return 'discover';
      if (n4 >= 3000 && n4 <= 3059) return 'diners';
      const maestro4 = {5018, 5020, 5038, 6304, 6759, 6761, 6762, 6763};
      if (maestro4.contains(n4)) return 'maestro';
    }

    if (n3 != null && n3 >= 644 && n3 <= 649) return 'discover';

    if (n2 != null) {
      if (n2 == 34 || n2 == 37) return 'amex';
      if (n2 == 36 || n2 == 38) return 'diners';
      if (n2 >= 51 && n2 <= 55) return 'mastercard';
      if (n2 == 62) return 'unionpay';
      if (n2 == 65) return 'discover';
      if (n2 >= 56 && n2 <= 58) return 'maestro';
    }

    if (n3 != null && n3 >= 300 && n3 <= 305) return 'diners';

    if (n1 == 4) return 'visa';

    return '';
  }

  static String fromSiteText(String? raw) {
    final b = (raw ?? '').trim().toLowerCase();
    if (b.isEmpty) return '';
    if (b.contains('visa')) return 'visa';
    if (b.contains('mastercard') || b == 'mc' || b.contains('master card')) {
      return 'mastercard';
    }
    if (b.contains('maestro')) return 'maestro';
    if (b.contains('amex') || b.contains('american express')) return 'amex';
    if (b.contains('discover')) return 'discover';
    if (b.contains('diners')) return 'diners';
    if (b.contains('jcb')) return 'jcb';
    if (b.contains('unionpay') || b.contains('union pay')) return 'unionpay';
    if (b.contains('mir') || b.contains('мир')) return 'mir';
    return '';
  }

  /// Текст с сайта → иначе BIN (cardFirst4 или полный фрагмент).
  static String resolve({String? siteType, String bin = ''}) {
    final fromText = fromSiteText(siteType);
    if (fromText.isNotEmpty) return fromText;
    return fromBin(bin);
  }

  /// Короткая подпись для UI.
  static String label(String brand) {
    switch (brand) {
      case 'visa':
        return 'VISA';
      case 'mastercard':
        return 'MC';
      case 'maestro':
        return 'Maestro';
      case 'amex':
        return 'AMEX';
      case 'discover':
        return 'Discover';
      case 'diners':
        return 'Diners';
      case 'jcb':
        return 'JCB';
      case 'unionpay':
        return 'UnionPay';
      case 'mir':
        return 'МИР';
      default:
        return '';
    }
  }
}

