/// Дедупликация: только man_* → реальный ID. Разные фирмы с одним логином не схлопываем.
abstract final class FirmDedupe {
  static bool isPendingId(String id) => id.startsWith('man_');

  static String normLogin(String login) => login.trim().toLowerCase();

  static Map<String, String>? findByLogin(
    List<Map<String, String>> firms,
    String login,
  ) {
    final lg = normLogin(login);
    if (lg.isEmpty) return null;
    for (final f in firms) {
      if (normLogin(f['login'] ?? '') == lg) return f;
    }
    return null;
  }

  /// Убирает man_* если уже есть реальный ID с тем же логином; по id — одна запись.
  static List<Map<String, String>> dedupeList(List<Map<String, String>> list) {
    final realLogin = <String, String>{};
    for (final f in list) {
      final lg = normLogin(f['login'] ?? '');
      final id = (f['id'] ?? '').trim();
      if (lg.isNotEmpty && id.isNotEmpty && !isPendingId(id)) {
        realLogin[lg] = id;
      }
    }

    final byId = <String, Map<String, String>>{};
    for (final f in list) {
      final id = (f['id'] ?? '').trim();
      if (id.isEmpty) continue;
      final lg = normLogin(f['login'] ?? '');
      if (isPendingId(id) && lg.isNotEmpty && realLogin.containsKey(lg)) {
        continue;
      }
      final prev = byId[id];
      if (prev == null) {
        byId[id] = f;
      } else {
        byId[id] = _pickBetter(prev, f);
      }
    }
    return byId.values.toList();
  }

  static Map<String, String> _pickBetter(
    Map<String, String> a,
    Map<String, String> b,
  ) {
    final aId = a['id'] ?? '';
    final bId = b['id'] ?? '';
    final aPending = isPendingId(aId);
    final bPending = isPendingId(bId);
    if (aPending && !bPending) return b;
    if (!aPending && bPending) return a;
    final aName = (a['name'] ?? '').trim();
    final bName = (b['name'] ?? '').trim();
    if (aName.contains('@') && !bName.contains('@')) return b;
    if (!aName.contains('@') && bName.contains('@')) return a;
    if (bName.length > aName.length) return b;
    return a;
  }
}

