import 'dart:async';

import 'package:flutter/material.dart';
import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'balance_colors.dart';

/// Показ фоновых WebView (баланс, карта/details) — для отладки на телефоне.
abstract final class EtollDebugWeb {
  /// Пока true — полоски баланса и fetch карты видны на экране.
  static bool showSessions = true;

  static InAppWebViewController? controller;
  static final ValueNotifier<EtollDebugWebState?> panel =
      ValueNotifier<EtollDebugWebState?>(null);

  static Completer<void>? _ready;

  static Future<InAppWebViewController?> openSession({
    required String label,
    String startUrl = '',
  }) async {
    if (!showSessions) return null;
    _ready = Completer<void>();
    controller = null;
    panel.value = EtollDebugWebState(
      label: label,
      url: startUrl,
      stage: 'start',
    );
    try {
      await _ready!.future.timeout(
        const Duration(seconds: 8),
        onTimeout: () {},
      );
    } catch (_) {}
    return controller;
  }

  static void onControllerReady(InAppWebViewController c) {
    controller = c;
    if (_ready != null && !_ready!.isCompleted) {
      _ready!.complete();
    }
  }

  static void track(String label, String url, {String? stage}) {
    if (!showSessions) return;
    final cur = panel.value;
    if (cur == null || cur.label != label) {
      panel.value = EtollDebugWebState(
        label: label,
        url: url,
        stage: stage ?? '',
      );
      return;
    }
    panel.value = cur.copyWith(
      url: url.isNotEmpty ? url : cur.url,
      stage: stage ?? cur.stage,
    );
  }

  static void setStage(String stage, {String? url}) {
    if (!showSessions) return;
    final cur = panel.value;
    if (cur == null) return;
    panel.value = cur.copyWith(
      stage: stage,
      url: url ?? cur.url,
    );
  }

  static void closeSession() {
    controller = null;
    panel.value = null;
    _ready = null;
  }

  /// Полоска баланса: скрыта под контентом или панель снизу (отладка).
  static Widget stripeLayer({
    required Widget child,
    required double debugHeight,
  }) {
    if (!showSessions) {
      return Positioned.fill(child: child);
    }
    return Positioned(
      left: 0,
      right: 0,
      bottom: 0,
      height: debugHeight,
      child: Material(
        elevation: 16,
        color: Colors.black,
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Container(
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
              color: const Color(0xFF1A2030),
              child: Text(
                'eTOLL · баланс (отладка)',
                style: TextStyle(
                  color: BalanceColors.accent.withValues(alpha: 0.95),
                  fontSize: 12,
                  fontWeight: FontWeight.w700,
                ),
              ),
            ),
            Expanded(child: child),
          ],
        ),
      ),
    );
  }
}

class EtollDebugWebState {
  final String label;
  final String url;
  final String stage;

  const EtollDebugWebState({
    required this.label,
    this.url = '',
    this.stage = '',
  });

  EtollDebugWebState copyWith({String? label, String? url, String? stage}) {
    return EtollDebugWebState(
      label: label ?? this.label,
      url: url ?? this.url,
      stage: stage ?? this.stage,
    );
  }

  String get urlShort {
    var u = url;
    if (u.contains('#')) u = u.substring(u.indexOf('#'));
    if (u.length > 72) u = '…${u.substring(u.length - 68)}';
    return u;
  }
}

/// Панель headless→visible: карта / details после баланса.
class EtollDebugWebOverlay extends StatefulWidget {
  final Widget child;
  const EtollDebugWebOverlay({super.key, required this.child});

  @override
  State<EtollDebugWebOverlay> createState() => _EtollDebugWebOverlayState();
}

class _EtollDebugWebOverlayState extends State<EtollDebugWebOverlay> {
  static const _ua =
      'Mozilla/5.0 (Linux; Android 14; SM-S918B) AppleWebKit/537.36 (KHTML, like Gecko) '
      'Chrome/149.0.0.0 Mobile Safari/537.36';

  @override
  Widget build(BuildContext context) {
    return Stack(
      fit: StackFit.expand,
      children: [
        widget.child,
        ValueListenableBuilder<EtollDebugWebState?>(
          valueListenable: EtollDebugWeb.panel,
          builder: (_, st, __) {
            if (st == null || !EtollDebugWeb.showSessions) {
              return const SizedBox.shrink();
            }
            final h = MediaQuery.of(context).size.height * 0.46;
            return Positioned(
              left: 0,
              right: 0,
              bottom: 0,
              height: h,
              child: Material(
                elevation: 20,
                color: Colors.black,
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    Container(
                      padding: const EdgeInsets.fromLTRB(10, 6, 10, 4),
                      color: const Color(0xFF152238),
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(
                            st.label,
                            maxLines: 1,
                            overflow: TextOverflow.ellipsis,
                            style: const TextStyle(
                              color: Color(0xFF5AE89A),
                              fontSize: 13,
                              fontWeight: FontWeight.w800,
                            ),
                          ),
                          if (st.stage.isNotEmpty)
                            Text(
                              st.stage,
                              style: const TextStyle(
                                color: Color(0xFF9EB4CC),
                                fontSize: 11,
                              ),
                            ),
                          if (st.urlShort.isNotEmpty)
                            Text(
                              st.urlShort,
                              maxLines: 2,
                              overflow: TextOverflow.ellipsis,
                              style: const TextStyle(
                                color: Color(0xFF6A8098),
                                fontSize: 10,
                              ),
                            ),
                        ],
                      ),
                    ),
                    Expanded(
                      child: InAppWebView(
                        initialUrlRequest: st.url.isNotEmpty
                            ? URLRequest(url: WebUri(st.url))
                            : null,
                        initialSettings: InAppWebViewSettings(
                          userAgent: _ua,
                          javaScriptEnabled: true,
                          domStorageEnabled: true,
                          thirdPartyCookiesEnabled: true,
                          cacheEnabled: true,
                          useWideViewPort: true,
                        ),
                        onWebViewCreated: (c) {
                          EtollDebugWeb.onControllerReady(c);
                        },
                        onLoadStop: (c, url) {
                          EtollDebugWeb.track(
                            st.label,
                            url?.toString() ?? '',
                          );
                        },
                      ),
                    ),
                  ],
                ),
              ),
            );
          },
        ),
      ],
    );
  }
}

