static Future<void> mirror(String fromId, String toId) async {
  if (fromId.isEmpty || toId.isEmpty || fromId == toId) return;
  final d = await load(fromId);
  if (d != null) await save(toId, d);
  final prefs = await SharedPreferences.getInstance();
  final diag = prefs.getString(_diagKey(fromId));
  if (diag != null && diag.isNotEmpty) {
    await prefs.setString(_diagKey(toId), diag);
  }
}

