import 'dart:async';

import 'package:flutter_inappwebview/flutter_inappwebview.dart';

/// Ожидание полной загрузки eTOLL — без фиксированных «подождать 1.5 сек и идти дальше».
/// Единственные паузы — короткий опрос readyState (роуминг / медленный интернет).
abstract final class EtollPageReady {
  /// Макс. ожидание одной страницы (роуминг).
  static const Duration roamingMaxWait = Duration(seconds: 120);

  static const Duration _poll = Duration(milliseconds: 300);

  static const _readyJs = r'''
(function(){
  try {
    if (document.readyState !== 'complete') return '0';
    var busy = document.querySelector(
      'mat-progress-bar,[role="progressbar"],.loading,.spinner,.mat-progress-spinner');
    if (busy && busy.offsetParent !== null) return '0';
    return '1';
  } catch(e) { return '0'; }
})();
''';

  static const hasPlnBalanceJs = r'''
(function(){
  try {
    var body = document.body ? document.body.innerText : '';
    return /[0-9][0-9\s.,]*\s*PLN/i.test(body) ? '1' : '0';
  } catch(e) { return '0'; }
})();
''';

  static Future<bool> isReady(InAppWebViewController ctrl) async {
    final ready = await ctrl.evaluateJavascript(source: _readyJs);
    return (ready ?? '0').toString().trim() == '1';
  }

  /// Страница complete и без spinner — ждём до [maxWait].
  static Future<bool> waitForReady(
    InAppWebViewController ctrl, {
    Duration maxWait = roamingMaxWait,
  }) async {
    if (await isReady(ctrl)) return true;
    final deadline = DateTime.now().add(maxWait);
    while (DateTime.now().isBefore(deadline)) {
      if (await isReady(ctrl)) return true;
      await Future.delayed(_poll);
    }
    return isReady(ctrl);
  }

  /// Удобная обёртка: не идём дальше, пока страница не готова.
  static Future<bool> ensureReady(
    InAppWebViewController ctrl, {
    Duration maxWait = roamingMaxWait,
  }) =>
      waitForReady(ctrl, maxWait: maxWait);

  static Future<bool> loadAndWait(
    InAppWebViewController ctrl,
    WebUri url, {
    Duration maxWait = roamingMaxWait,
  }) async {
    try {
      await ctrl.loadUrl(urlRequest: URLRequest(url: url));
    } catch (_) {
      return false;
    }
    return waitForReady(ctrl, maxWait: maxWait);
  }

  /// После клика / loadUrl SPA: URL сменился (или страница стала ready).
  static Future<bool> waitAfterAction(
    InAppWebViewController ctrl, {
    String? urlBefore,
    Duration maxWait = roamingMaxWait,
  }) async {
    final deadline = DateTime.now().add(maxWait);
    while (DateTime.now().isBefore(deadline)) {
      final now = (await ctrl.getUrl())?.toString() ?? '';
      if (urlBefore != null && urlBefore.isNotEmpty) {
        if (now.isNotEmpty && now != urlBefore && await isReady(ctrl)) {
          return true;
        }
      } else if (await isReady(ctrl)) {
        return true;
      }
      await Future.delayed(_poll);
    }
    return isReady(ctrl);
  }

  /// Ждём пока JS вернёт '1' (только на уже complete странице).
  static Future<bool> waitForJs(
    InAppWebViewController ctrl,
    String js, {
    Duration maxWait = roamingMaxWait,
  }) async {
    final deadline = DateTime.now().add(maxWait);
    while (DateTime.now().isBefore(deadline)) {
      if (await isReady(ctrl)) {
        final r = await ctrl.evaluateJavascript(source: js);
        if ((r ?? '0').toString().trim() == '1') return true;
      } else {
        final left = deadline.difference(DateTime.now());
        if (left.isNegative) break;
        await waitForReady(
          ctrl,
          maxWait: left < const Duration(seconds: 30)
              ? left
              : const Duration(seconds: 30),
        );
      }
      await Future.delayed(_poll);
    }
    return false;
  }

  static Future<bool> waitForUrlContains(
    InAppWebViewController ctrl,
    String part, {
    Duration maxWait = roamingMaxWait,
  }) async {
    final needle = part.toLowerCase();
    final deadline = DateTime.now().add(maxWait);
    while (DateTime.now().isBefore(deadline)) {
      if (await isReady(ctrl)) {
        final u = ((await ctrl.getUrl())?.toString() ?? '').toLowerCase();
        if (u.contains(needle)) return true;
      }
      await Future.delayed(_poll);
    }
    return false;
  }
}

