import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_debug_web.dart';
import 'etoll_details_model.dart';
import 'etoll_details_parser.dart';
import 'etoll_details_store.dart';
import 'etoll_financing_nav.dart';
import 'etoll_page_ready.dart';
import 'etoll_urls.dart';

/// Чтение карты в уже залогиненной сессии WebView (после баланса).
abstract final class EtollCardInSession {
  static Future<EtollPrepaidDetails?> read({
    required InAppWebViewController ctrl,
    required String firmId,
    required String subjectId,
    String accountId = '',
    String? aliasFirmId,
    void Function(String card4)? onCard4,
    void Function(String prepaidId)? onPrepaidId,
  }) async {
    if (firmId.isEmpty || subjectId.isEmpty) return null;

    var aid = accountId.trim();
    if (aid == subjectId.trim()) aid = '';

    String diagStage = 'session-start';

    try {
      if (aid.isEmpty) {
        await EtollPageReady.ensureReady(ctrl);
        aid = await _extractPrepaidId(ctrl);
        if (aid == subjectId) aid = '';
      }

      if (aid.isEmpty) {
        diagStage = 'session-goto-list';
        final listUrl = EtollUrls.financingList(subjectId);
        await EtollPageReady.loadAndWait(ctrl, WebUri(listUrl));
        EtollDebugWeb.track('Карта in-session', listUrl, stage: diagStage);
        await EtollPageReady.waitForJs(
          ctrl,
          EtollFinancingNav.hasPrepaidAccountJs,
        );
        aid = await _extractPrepaidId(ctrl);
        if (aid == subjectId) aid = '';
      }

      if (aid.isEmpty) {
        diagStage = 'session-no-aid';
        return null;
      }

      diagStage = 'session-open-details';
      final detailsUrl = EtollUrls.prepaidDetails(subjectId, aid);
      await EtollPageReady.loadAndWait(ctrl, WebUri(detailsUrl));
      EtollDebugWeb.track('Карта in-session', detailsUrl, stage: diagStage);
      await EtollPageReady.waitForUrlContains(ctrl, '/details');

      EtollPrepaidDetails? result;
      final gotContent = await EtollPageReady.waitForJs(
        ctrl,
        EtollDetailsParser.hasContentJs,
      );
      if (gotContent || await EtollPageReady.isReady(ctrl)) {
        for (int i = 0; i < 8; i++) {
          await EtollPageReady.ensureReady(ctrl);
          final cur = ((await ctrl.getUrl())?.toString() ?? '').toLowerCase();
          if (!cur.contains('/details') || !cur.contains('/prepaid')) {
            await EtollPageReady.waitForUrlContains(ctrl, '/details');
            continue;
          }
          final raw = await ctrl.evaluateJavascript(
              source: EtollDetailsParser.parseJs);
          final parsed = EtollDetailsParser.parseResult(raw);
          if (parsed.hasCard || parsed.finType.isNotEmpty) {
            result = parsed;
            final alias = aliasFirmId?.trim() ?? '';
            if (alias.isNotEmpty && alias != firmId) {
              await EtollDetailsStore.saveBoth(firmId, alias, parsed);
            } else {
              await EtollDetailsStore.save(firmId, parsed);
            }
            if (parsed.hasCard && onCard4 != null) onCard4(parsed.card4);
            diagStage = parsed.hasCard ? 'session-card-ok' : 'session-fin-only';
            EtollDebugWeb.setStage(diagStage, url: cur);
            break;
          }
          await EtollPageReady.waitForJs(ctrl, EtollDetailsParser.hasContentJs,
              maxWait: const Duration(seconds: 15));
        }
      }

      if (result == null) {
        diagStage = 'session-no-card';
      } else if (aid.isNotEmpty && onPrepaidId != null) {
        onPrepaidId(aid);
      }
      return result;
    } catch (_) {
      diagStage = 'session-error';
      return null;
    } finally {
      await EtollDetailsStore.saveDiag(
        firmId,
        '[$diagStage] sid=$subjectId aid=${aid.isNotEmpty ? aid : accountId} in-session',
      );
    }
  }

  static Future<String> _extractPrepaidId(InAppWebViewController ctrl) async {
    if (!await EtollPageReady.isReady(ctrl)) return '';
    final extracted = await ctrl.evaluateJavascript(
      source: EtollFinancingNav.extractAccountIdJs,
    );
    return (extracted ?? '').toString().trim();
  }
}

