import 'dart:async';
import 'dart:io';

import 'package:flutter/foundation.dart';

/// Глобальный статус фонового refresh eTOLL (баланс + карта).
abstract final class EtollRefreshStatus {
  static final active = ValueNotifier<bool>(false);
  static final state = ValueNotifier<EtollRefreshStatusState>(
    const EtollRefreshStatusState(),
  );

  static Timer? _tick;
  static Timer? _netTimer;
  static int _refs = 0;
  static DateTime? _stageSince;

  /// good | weak | offline — для полоски (пинг только пока идёт refresh).
  static final netLevel = ValueNotifier<String>('good');

  static void begin({String firm = '', String phase = 'balance'}) {
    _refs++;
    _stageSince = DateTime.now();
    active.value = true;
    state.value = EtollRefreshStatusState(
      firm: firm,
      phase: phase,
      stage: 'start',
      elapsedSec: 0,
      loadHint: LoadHint.normal,
    );
    _tick ??= Timer.periodic(const Duration(seconds: 1), (_) => _onTick());
    _netTimer ??= Timer.periodic(const Duration(seconds: 8), (_) => _pingNet());
    _pingNet();
  }

  static void end() {
    if (_refs > 0) _refs--;
    if (_refs > 0) return;
    _tick?.cancel();
    _tick = null;
    _netTimer?.cancel();
    _netTimer = null;
    _stageSince = null;
    active.value = false;
    state.value = const EtollRefreshStatusState();
    netLevel.value = 'good';
  }

  static void setFirm(String firm) {
    if (!active.value) return;
    state.value = state.value.copyWith(firm: firm);
  }

  static void setPhase(String phase) {
    if (!active.value) return;
    _stageSince = DateTime.now();
    state.value = state.value.copyWith(phase: phase, loadHint: LoadHint.normal);
  }

  static void setStage(String stage, {String? url}) {
    if (!active.value) return;
    _stageSince = DateTime.now();
    final mapped = stageFromUrl(url ?? '', fallback: stage);
    state.value = state.value.copyWith(
      stage: mapped,
      urlShort: urlShort(url),
      loadHint: LoadHint.normal,
    );
  }

  static String stageFromUrl(String url, {String fallback = ''}) {
    final lu = url.toLowerCase();
    if (lu.contains('login-callback') || lu.contains('oauth') ||
        lu.contains('login.mf.gov.pl')) {
      return 'oauth';
    }
    if (lu.contains('login') || lu.contains('logowanie') || lu.contains('/auth/')) {
      return 'login';
    }
    if (lu.contains('billing-account')) return 'billing';
    if (lu.contains('/details') && lu.contains('/prepaid')) return 'details';
    if (lu.contains('/financing')) return 'financing';
    if (lu.contains('/manage')) return 'manage';
    if (fallback.isNotEmpty) return fallback;
    if (lu.contains('/subject/')) return 'cabinet';
    return 'loading';
  }

  static String urlShort(String? url) {
    if (url == null || url.isEmpty) return '';
    var u = url;
    if (u.contains('#')) u = u.substring(u.indexOf('#'));
    if (u.length > 56) u = '…${u.substring(u.length - 52)}';
    return u;
  }

  static void _onTick() {
    if (!active.value || _stageSince == null) return;
    final sec = DateTime.now().difference(_stageSince!).inSeconds;
    LoadHint hint = LoadHint.normal;
    if (sec >= 90) {
      hint = LoadHint.stuck;
    } else if (sec >= 30) {
      hint = LoadHint.slow;
    }
    state.value = state.value.copyWith(elapsedSec: sec, loadHint: hint);
  }

  static Future<void> _pingNet() async {
    if (!active.value) return;
    HttpClient? client;
    try {
      final sw = Stopwatch()..start();
      client = HttpClient()..connectionTimeout = const Duration(seconds: 5);
      final req = await client
          .getUrl(Uri.parse('https://www.gstatic.com/generate_204'))
          .timeout(const Duration(seconds: 5));
      final resp = await req.close().timeout(const Duration(seconds: 5));
      sw.stop();
      await resp.drain<void>();
      if (resp.statusCode >= 200 && resp.statusCode < 400) {
        netLevel.value =
            sw.elapsedMilliseconds < 1200 ? 'good' : 'weak';
      } else {
        netLevel.value = 'weak';
      }
    } catch (_) {
      netLevel.value = 'offline';
    } finally {
      try {
        client?.close(force: true);
      } catch (_) {}
    }
  }
}

enum LoadHint { normal, slow, stuck }

class EtollRefreshStatusState {
  final String firm;
  final String phase; // balance | card
  final String stage;
  final String urlShort;
  final int elapsedSec;
  final LoadHint loadHint;

  const EtollRefreshStatusState({
    this.firm = '',
    this.phase = 'balance',
    this.stage = '',
    this.urlShort = '',
    this.elapsedSec = 0,
    this.loadHint = LoadHint.normal,
  });

  EtollRefreshStatusState copyWith({
    String? firm,
    String? phase,
    String? stage,
    String? urlShort,
    int? elapsedSec,
    LoadHint? loadHint,
  }) {
    return EtollRefreshStatusState(
      firm: firm ?? this.firm,
      phase: phase ?? this.phase,
      stage: stage ?? this.stage,
      urlShort: urlShort ?? this.urlShort,
      elapsedSec: elapsedSec ?? this.elapsedSec,
      loadHint: loadHint ?? this.loadHint,
    );
  }

  bool get visible =>
      EtollRefreshStatus.active.value && (firm.isNotEmpty || stage.isNotEmpty);
}

