/// Полоска: фирма · этап · сеть · подсказка при медленной загрузке eTOLL.
class EtollRefreshStatusBar extends StatelessWidget {
  final String Function(String key) tr;
  final bool massActualizing;
  final String massFirm;

  const EtollRefreshStatusBar({
    super.key,
    required this.tr,
    this.massActualizing = false,
    this.massFirm = '',
  });

  String _stageLabel(String code) {
    switch (code) {
      case 'login':
        return tr('etoll_stage_login');
      case 'oauth':
        return tr('etoll_stage_oauth');
      case 'billing':
        return tr('etoll_stage_billing');
      case 'financing':
        return tr('etoll_stage_financing');
      case 'details':
        return tr('etoll_stage_details');
      case 'manage':
        return tr('etoll_stage_manage');
      case 'cabinet':
        return tr('etoll_stage_cabinet');
      case 'session-open-details':
      case 'session-card-ok':
      case 'session-no-card':
      case 'card-ok':
        return tr('etoll_stage_card');
      default:
        if (code.startsWith('fin-') || code.startsWith('session')) {
          return tr('etoll_stage_financing');
        }
        return tr('etoll_stage_loading');
    }
  }

  String _netLabel(String level) {
    switch (level) {
      case 'weak':
        return tr('net_weak');
      case 'offline':
        return tr('net_none');
      default:
        return tr('net_online');
    }
  }

  Color _netColor(String level) {
    switch (level) {
      case 'weak':
        return BalanceColors.amber;
      case 'offline':
        return BalanceColors.etRed;
      default:
        return BalanceColors.accent;
    }
  }

  @override
  Widget build(BuildContext context) {
    return ValueListenableBuilder<bool>(
      valueListenable: EtollRefreshStatus.active,
      builder: (_, on, __) {
        final showMass = massActualizing && !on;
        if (!on && !showMass) return const SizedBox.shrink();

        if (showMass && massFirm.isEmpty) {
          return _shell(
            net: 'good',
            line1: tr('updating_firms'),
            line2: '',
            hint: '',
            accent: BalanceColors.etRed,
          );
        }

        return ValueListenableBuilder<EtollRefreshStatusState>(
          valueListenable: EtollRefreshStatus.state,
          builder: (_, st, __) {
            return ValueListenableBuilder<String>(
              valueListenable: EtollRefreshStatus.netLevel,
              builder: (_, net, __) {
                final firm = st.firm.isNotEmpty
                    ? st.firm
                    : (massFirm.isNotEmpty ? massFirm : '');
                final phase = st.phase == 'card'
                    ? tr('etoll_refresh_phase_card')
                    : tr('etoll_refresh_phase_balance');
                final stage = _stageLabel(st.stage);
                final line1 = firm.isNotEmpty
                    ? '$firm · $phase · $stage'
                    : (massActualizing
                        ? tr('updating_firm').replaceAll('{0}', massFirm)
                        : '$phase · $stage');

                var line2 = '';
                if (st.elapsedSec > 0 && st.stage.isNotEmpty) {
                  line2 = tr('etoll_refresh_waiting')
                      .replaceAll('{0}', '${st.elapsedSec}');
                }
                if (st.urlShort.isNotEmpty) {
                  line2 = line2.isEmpty ? st.urlShort : '$line2 · ${st.urlShort}';
                }

                var hint = '';
                if (st.loadHint == LoadHint.stuck) {
                  hint = tr('etoll_refresh_very_slow');
                } else if (st.loadHint == LoadHint.slow || net == 'weak') {
                  hint = tr('etoll_refresh_slow');
                } else if (net == 'offline') {
                  hint = tr('no_connection');
                }

                return _shell(
                  net: net,
                  line1: line1,
                  line2: line2,
                  hint: hint,
                  accent: BalanceColors.etRed,
                );
              },
            );
          },
        );
      },
    );
  }

  Widget _shell({
    required String net,
    required String line1,
    required String line2,
    required String hint,
    required Color accent,
  }) {
    final nc = _netColor(net);
    return Container(
      width: double.infinity,
      margin: const EdgeInsets.only(bottom: 10),
      padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
      decoration: BoxDecoration(
        color: accent.withValues(alpha: 0.1),
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: accent.withValues(alpha: 0.35)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              SizedBox(
                width: 18,
                height: 18,
                child: CircularProgressIndicator(strokeWidth: 2, color: accent),
              ),
              const SizedBox(width: 10),
              Expanded(
                child: Text(
                  line1,
                  maxLines: 2,
                  overflow: TextOverflow.ellipsis,
                  style: const TextStyle(
                    color: BalanceColors.textPrimary,
                    fontSize: 13,
                    fontWeight: FontWeight.w800,
                    height: 1.25,
                  ),
                ),
              ),
              const SizedBox(width: 8),
              Container(
                padding:
                    const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                decoration: BoxDecoration(
                  color: nc.withValues(alpha: 0.15),
                  borderRadius: BorderRadius.circular(14),
                  border: Border.all(color: nc.withValues(alpha: 0.5)),
                ),
                child: Row(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Container(
                      width: 7,
                      height: 7,
                      decoration: BoxDecoration(
                        color: nc,
                        shape: BoxShape.circle,
                      ),
                    ),
                    const SizedBox(width: 5),
                    Text(
                      '${tr('etoll_refresh_net_label')}: ${_netLabel(net)}',
                      style: TextStyle(
                        color: nc,
                        fontSize: 10,
                        fontWeight: FontWeight.w800,
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
          if (line2.isNotEmpty) ...[
            const SizedBox(height: 6),
            Padding(
              padding: const EdgeInsets.only(left: 28),
              child: Text(
                line2,
                maxLines: 2,
                overflow: TextOverflow.ellipsis,
                style: TextStyle(
                  color: BalanceColors.textSecondary.withValues(alpha: 0.95),
                  fontSize: 11,
                  height: 1.3,
                ),
              ),
            ),
          ],
          if (hint.isNotEmpty) ...[
            const SizedBox(height: 6),
            Padding(
              padding: const EdgeInsets.only(left: 28),
              child: Text(
                hint,
                style: TextStyle(
                  color: BalanceColors.amber.withValues(alpha: 0.95),
                  fontSize: 11,
                  fontWeight: FontWeight.w600,
                  height: 1.35,
                ),
              ),
            ),
          ],
        ],
      ),
    );
  }
}

