Future<String> firmLabelForLogin(String login) async {
  final lg = login.trim();
  if (lg.isEmpty) return '';
  try {
    final firms = await BalanceStore.firms();
    final f = firms.firstWhere(
      (e) => (e['login'] ?? '').trim() == lg,
      orElse: () => <String, String>{},
    );
    final name = (f['name'] ?? '').trim();
    if (name.isNotEmpty) return name;
  } catch (_) {}
  return lg;
}

