import 'package:flutter_inappwebview/flutter_inappwebview.dart';
import 'package:shared_preferences/shared_preferences.dart';

import 'etoll_login_bindings.dart';

/// Блокировка автоповторов входа eTOLL после «неверный логин/пароль»
/// (Польша: 3 ошибки = сутки блок на сайте).
abstract final class EtollLoginGuard {
  static String _key(String login) =>
      'etoll_blocked_${login.trim().toLowerCase()}';

  static Future<bool> isBlocked(String login) async {
    final lg = login.trim();
    if (lg.isEmpty) return false;
    final prefs = await SharedPreferences.getInstance();
    final until = prefs.getInt(_key(lg));
    if (until == null) return false;
    if (DateTime.now().millisecondsSinceEpoch > until) {
      await prefs.remove(_key(lg));
      return false;
    }
    return true;
  }

  static Future<void> markWrongPassword(String login) async {
    final lg = login.trim();
    if (lg.isEmpty) return;
    final prefs = await SharedPreferences.getInstance();
    final until =
        DateTime.now().add(const Duration(hours: 24)).millisecondsSinceEpoch;
    await prefs.setInt(_key(lg), until);
  }

  static Future<void> clear(String login) async {
    final lg = login.trim();
    if (lg.isEmpty) return;
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove(_key(lg));
  }

  /// Тексты с login.mf.gov.pl (PL + EN) — по видео Oleg, 2026-06.
  /// НЕ ловим жёлтое «Access only to authorized users» — оно на форме всегда.
  static const detectWrongPasswordJs = r'''
(function(){
  try {
    function norm(s){return (s||'').toLowerCase().replace(/\s+/g,' ').trim();}
    var t=norm(document.body&&(document.body.innerText||document.body.textContent)||'');
    if(!t) return '0';
    var skip=[
      'access to the system is allowed only to authorized users',
      'dostep do systemu jest dozwolony jedynie dla uprawnionych uzytkownikow',
      'dostęp do systemu jest dozwolony jedynie dla uprawnionych użytkowników'
    ];
    for(var s=0;s<skip.length;s++){if(t.indexOf(skip[s])>=0&&t.indexOf('login error')<0&&t.indexOf('blad logowania')<0&&t.indexOf('błąd logowania')<0) return '0';}
    var wrong=[
      'login error','check your data and try again',
      '3 incorrect login attempt','blocked due to security reasons',
      'nieprawidlowy login lub haslo','nieprawidłowy login lub hasło',
      'bledny login lub haslo','błędny login lub hasło',
      'blad logowania','błąd logowania',
      'sprawdz dane i sprobuj ponownie','sprawdź dane i spróbuj ponownie',
      '3 nieprawidlow','3 nieprawidłow','3 bledn','3 błędn',
      'invalid username or password','incorrect username or password',
      'incorrect login or password','wrong username or password',
      'wrong password','invalid credentials','authentication failed',
      'logowanie nie powiodlo','logowanie nie powiodło'
    ];
    for(var i=0;i<wrong.length;i++){if(t.indexOf(wrong[i])>=0) return '1';}
    var alerts=document.querySelectorAll('[role="alert"],.alert-danger,.validation-summary-errors,[class*="error-message"],[class*="alert-error"]');
    for(var j=0;j<alerts.length;j++){
      var at=norm(alerts[j].innerText||alerts[j].textContent||'');
      if(!at||at.length>400) continue;
      for(var k=0;k<wrong.length;k++){if(at.indexOf(wrong[k])>=0) return '1';}
    }
    return '0';
  } catch(e){ return '0'; }
})();
''';

  /// Уже заблокировано на сайте (после 3 попыток) — отдельные формулировки.
  static const detectSiteBlockedJs = r'''
(function(){
  try {
    var t=(document.body&&(document.body.innerText||document.body.textContent)||'').toLowerCase();
    var markers=[
      'access has been blocked','your access has been blocked',
      'access is blocked','account has been locked','account is locked',
      'dostep zostal zablokowany','dostęp został zablokowany',
      'konto zostalo zablokowane','konto zostało zablokowane',
      'zablokowano dostep','zablokowano dostęp'
    ];
    for(var i=0;i<markers.length;i++){if(t.indexOf(markers[i])>=0) return '1';}
    return '0';
  } catch(e){ return '0'; }
})();
''';

  static Future<bool> detectWrongPassword(InAppWebViewController ctrl) async {
    final res =
        await ctrl.evaluateJavascript(source: detectWrongPasswordJs);
    return (res ?? '0').toString().trim() == '1';
  }

  static Future<bool> detectSiteBlocked(InAppWebViewController ctrl) async {
    final res = await ctrl.evaluateJavascript(source: detectSiteBlockedJs);
    return (res ?? '0').toString().trim() == '1';
  }

  /// Проверка страницы + 24ч блок в приложении + уведомление. true = стоп refresh.
  static Future<bool> reactIfLoginFailed(
    InAppWebViewController ctrl,
    String login, {
    void Function()? onFailed,
    bool brief = false,
  }) async {
    final lg = login.trim();
    if (lg.isEmpty) return false;
    if (await isBlocked(lg)) {
      onFailed?.call();
      notifyEtollWrongPassword(brief: true);
      return true;
    }
    if (!await detectWrongPassword(ctrl) &&
        !await detectSiteBlocked(ctrl)) {
      return false;
    }
    await markWrongPassword(lg);
    if (onFailed != null) {
      onFailed();
    } else {
      notifyEtollWrongPassword(brief: brief);
    }
    return true;
  }
}

