import 'dart:io';

import 'package:connectivity_plus/connectivity_plus.dart';

/// Канал связи телефона + доступность eTOLL (не Google).
class EtollNetSnapshot {
  final String transport; // wifi | mobile | none
  final String etoll; // good | weak | offline
  final int latencyMs;

  const EtollNetSnapshot({
    this.transport = 'none',
    this.etoll = 'offline',
    this.latencyMs = 0,
  });
}

abstract final class EtollNetStatus {
  static Future<String> _transport() async {
    try {
      final results = await Connectivity().checkConnectivity();
      if (results.isEmpty ||
          results.every((r) => r == ConnectivityResult.none)) {
        return 'none';
      }
      if (results.contains(ConnectivityResult.wifi) ||
          results.contains(ConnectivityResult.ethernet)) {
        return 'wifi';
      }
      if (results.contains(ConnectivityResult.mobile)) {
        return 'mobile';
      }
      // VPN / other — считаем как мобильный канал
      return 'mobile';
    } catch (_) {
      return 'none';
    }
  }

  /// transport = Wi‑Fi / LTE из системы; etoll = пинг etoll.gov.pl.
  static Future<EtollNetSnapshot> probe() async {
    final transport = await _transport();
    if (transport == 'none') {
      return const EtollNetSnapshot(transport: 'none', etoll: 'offline');
    }

    HttpClient? client;
    try {
      final sw = Stopwatch()..start();
      client = HttpClient()..connectionTimeout = const Duration(seconds: 6);
      final req = await client
          .getUrl(Uri.parse('https://etoll.gov.pl/'))
          .timeout(const Duration(seconds: 6));
      req.headers.set(HttpHeaders.userAgentHeader, 'RouteControl/1.0');
      final resp = await req.close().timeout(const Duration(seconds: 6));
      sw.stop();
      await resp.drain<void>();
      final ms = sw.elapsedMilliseconds;
      if (resp.statusCode >= 200 && resp.statusCode < 500) {
        return EtollNetSnapshot(
          transport: transport,
          etoll: ms < 2500 ? 'good' : 'weak',
          latencyMs: ms,
        );
      }
      return EtollNetSnapshot(
        transport: transport,
        etoll: 'weak',
        latencyMs: ms,
      );
    } catch (_) {
      return EtollNetSnapshot(transport: transport, etoll: 'offline');
    } finally {
      try {
        client?.close(force: true);
      } catch (_) {}
    }
  }

  /// Быстрая проверка «есть ли вообще сеть» (DNS).
  static Future<bool> hasAnyNetwork() async {
    final t = await _transport();
    if (t != 'none') return true;
    try {
      final res = await InternetAddress.lookup('etoll.gov.pl')
          .timeout(const Duration(seconds: 4));
      return res.isNotEmpty && res.first.rawAddress.isNotEmpty;
    } catch (_) {
      return false;
    }
  }
}

import 'dart:async';

import 'package:flutter/foundation.dart';

import 'etoll_net_status.dart';

/// Глобальный статус фонового refresh eTOLL (баланс + карта).
abstract final class EtollRefreshStatus {
  static final active = ValueNotifier<bool>(false);
  static final state = ValueNotifier<EtollRefreshStatusState>(
    const EtollRefreshStatusState(),
  );

  static Timer? _tick;
  static Timer? _netTimer;
  static int _refs = 0;
  static DateTime? _stageSince;

  /// wifi | mobile | none
  static final netTransport = ValueNotifier<String>('wifi');

  /// good | weak | offline — пинг etoll.gov.pl
  static final netEtoll = ValueNotifier<String>('good');

  static void begin({String firm = '', String phase = 'balance'}) {
    _refs++;
    _stageSince = DateTime.now();
    active.value = true;
    state.value = EtollRefreshStatusState(
      firm: firm,
      phase: phase,
      stage: 'start',
      elapsedSec: 0,
      loadHint: LoadHint.normal,
    );
    _tick ??= Timer.periodic(const Duration(seconds: 1), (_) => _onTick());
    _netTimer ??= Timer.periodic(const Duration(seconds: 8), (_) => _probeNet());
    _probeNet();
  }

  static void end() {
    if (_refs > 0) _refs--;
    if (_refs > 0) return;
    _tick?.cancel();
    _tick = null;
    _netTimer?.cancel();
    _netTimer = null;
    _stageSince = null;
    active.value = false;
    state.value = const EtollRefreshStatusState();
    netTransport.value = 'wifi';
    netEtoll.value = 'good';
  }

  static void setFirm(String firm) {
    if (!active.value) return;
    state.value = state.value.copyWith(firm: firm);
  }

  static void setPhase(String phase) {
    if (!active.value) return;
    _stageSince = DateTime.now();
    state.value = state.value.copyWith(phase: phase, loadHint: LoadHint.normal);
  }

  static void setStage(String stage, {String? url}) {
    if (!active.value) return;
    _stageSince = DateTime.now();
    final mapped = stageFromUrl(url ?? '', fallback: stage);
    state.value = state.value.copyWith(
      stage: mapped,
      urlShort: urlShort(url),
      loadHint: LoadHint.normal,
    );
  }

  static String stageFromUrl(String url, {String fallback = ''}) {
    final lu = url.toLowerCase();
    if (lu.contains('login-callback') || lu.contains('oauth') ||
        lu.contains('login.mf.gov.pl')) {
      return 'oauth';
    }
    if (lu.contains('login') || lu.contains('logowanie') || lu.contains('/auth/')) {
      return 'login';
    }
    if (lu.contains('billing-account')) return 'billing';
    if (lu.contains('/details') && lu.contains('/prepaid')) return 'details';
    if (lu.contains('/financing')) return 'financing';
    if (lu.contains('/manage')) return 'manage';
    if (fallback.isNotEmpty) return fallback;
    if (lu.contains('/subject/')) return 'cabinet';
    return 'loading';
  }

  static String urlShort(String? url) {
    if (url == null || url.isEmpty) return '';
    var u = url;
    if (u.contains('#')) u = u.substring(u.indexOf('#'));
    if (u.length > 56) u = '…${u.substring(u.length - 52)}';
    return u;
  }

  static void _onTick() {
    if (!active.value || _stageSince == null) return;
    final sec = DateTime.now().difference(_stageSince!).inSeconds;
    LoadHint hint = LoadHint.normal;
    if (sec >= 90) {
      hint = LoadHint.stuck;
    } else if (sec >= 30) {
      hint = LoadHint.slow;
    }
    state.value = state.value.copyWith(elapsedSec: sec, loadHint: hint);
  }

  static Future<void> _probeNet() async {
    if (!active.value) return;
    final snap = await EtollNetStatus.probe();
    netTransport.value = snap.transport;
    netEtoll.value = snap.etoll;
  }
}

enum LoadHint { normal, slow, stuck }

class EtollRefreshStatusState {
  final String firm;
  final String phase; // balance | card
  final String stage;
  final String urlShort;
  final int elapsedSec;
  final LoadHint loadHint;

  const EtollRefreshStatusState({
    this.firm = '',
    this.phase = 'balance',
    this.stage = '',
    this.urlShort = '',
    this.elapsedSec = 0,
    this.loadHint = LoadHint.normal,
  });

  EtollRefreshStatusState copyWith({
    String? firm,
    String? phase,
    String? stage,
    String? urlShort,
    int? elapsedSec,
    LoadHint? loadHint,
  }) {
    return EtollRefreshStatusState(
      firm: firm ?? this.firm,
      phase: phase ?? this.phase,
      stage: stage ?? this.stage,
      urlShort: urlShort ?? this.urlShort,
      elapsedSec: elapsedSec ?? this.elapsedSec,
      loadHint: loadHint ?? this.loadHint,
    );
  }

  bool get visible =>
      EtollRefreshStatus.active.value && (firm.isNotEmpty || stage.isNotEmpty);
}

