/// Полоска: фирма · этап · сеть · подсказка при медленной загрузке eTOLL.
class EtollRefreshStatusBar extends StatelessWidget {
  final String Function(String key) tr;
  final bool massActualizing;
  final String massFirm;

  const EtollRefreshStatusBar({
    super.key,
    required this.tr,
    this.massActualizing = false,
    this.massFirm = '',
  });

  String _stageLabel(String code) {
    switch (code) {
      case 'login':
        return tr('etoll_stage_login');
      case 'login-error':
        return tr('etoll_stage_login_error');
      case 'oauth':
        return tr('etoll_stage_oauth');
      case 'billing':
        return tr('etoll_stage_billing');
      case 'financing':
        return tr('etoll_stage_financing');
      case 'details':
        return tr('etoll_stage_details');
      case 'manage':
        return tr('etoll_stage_manage');
      case 'cabinet':
        return tr('etoll_stage_cabinet');
      case 'session-open-details':
      case 'session-card-ok':
      case 'session-no-card':
      case 'card-ok':
        return tr('etoll_stage_card');
      default:
        if (code.startsWith('fin-') || code.startsWith('session')) {
          return tr('etoll_stage_financing');
        }
        return tr('etoll_stage_loading');
    }
  }

  String _transportLabel(String transport) {
    switch (transport) {
      case 'wifi':
        return tr('net_wifi');
      case 'mobile':
        return tr('net_mobile');
      default:
        return tr('net_none');
    }
  }

  String _etollLabel(String etoll) {
    switch (etoll) {
      case 'weak':
        return tr('net_weak');
      case 'offline':
        return tr('net_etoll_off');
      default:
        return tr('net_online');
    }
  }

  String _netBadge(String transport, String etoll) {
    if (transport == 'none') return tr('net_none');
    return '${_transportLabel(transport)} · ${_etollLabel(etoll)}';
  }

  Color _netColor(String transport, String etoll) {
    if (transport == 'none' || etoll == 'offline') {
      return BalanceColors.etollRed;
    }
    if (etoll == 'weak') return BalanceColors.amber;
    return BalanceColors.accent;
  }

  String _hint({
    required String transport,
    required String etoll,
    required LoadHint loadHint,
  }) {
    if (transport == 'none') return tr('no_connection');
    if (loadHint == LoadHint.stuck) return tr('etoll_refresh_very_slow');
    if (etoll == 'offline') return tr('net_etoll_off_hint');
    if (loadHint == LoadHint.slow || etoll == 'weak') {
      if (transport == 'mobile') return tr('etoll_refresh_slow');
      return tr('etoll_refresh_slow_wifi');
    }
    return '';
  }

  @override
  Widget build(BuildContext context) {
    return ValueListenableBuilder<bool>(
      valueListenable: EtollRefreshStatus.active,
      builder: (_, on, __) {
        final showMass = massActualizing && !on;
        if (!on && !showMass) return const SizedBox.shrink();

        if (showMass && massFirm.isEmpty) {
          return ValueListenableBuilder<String>(
            valueListenable: EtollRefreshStatus.netTransport,
            builder: (_, trn, __) {
              return ValueListenableBuilder<String>(
                valueListenable: EtollRefreshStatus.netEtoll,
                builder: (_, et, __) {
                  return _shell(
                    transport: trn,
                    etoll: et,
                    line1: tr('updating_firms'),
                    line2: '',
                    hint: '',
                    accent: BalanceColors.etollRed,
                  );
                },
              );
            },
          );
        }

        return ValueListenableBuilder<EtollRefreshStatusState>(
          valueListenable: EtollRefreshStatus.state,
          builder: (_, st, __) {
            return ValueListenableBuilder<String>(
              valueListenable: EtollRefreshStatus.netTransport,
              builder: (_, transport, __) {
                return ValueListenableBuilder<String>(
                  valueListenable: EtollRefreshStatus.netEtoll,
                  builder: (_, etoll, __) {
                    final firm = st.firm.isNotEmpty
                        ? st.firm
                        : (massFirm.isNotEmpty ? massFirm : '');
                    final phase = st.phase == 'card'
                        ? tr('etoll_refresh_phase_card')
                        : tr('etoll_refresh_phase_balance');
                    final stage = _stageLabel(st.stage);
                    final line1 = firm.isNotEmpty
                        ? '$firm · $phase · $stage'
                        : (massActualizing
                            ? tr('updating_firm').replaceAll('{0}', massFirm)
                            : '$phase · $stage');

                    var line2 = '';
                    if (st.elapsedSec > 0 && st.stage.isNotEmpty) {
                      line2 = tr('etoll_refresh_waiting')
                          .replaceAll('{0}', '${st.elapsedSec}');
                    }
                    if (st.urlShort.isNotEmpty) {
                      line2 =
                          line2.isEmpty ? st.urlShort : '$line2 · ${st.urlShort}';
                    }

                    final hint = _hint(
                      transport: transport,
                      etoll: etoll,
                      loadHint: st.loadHint,
                    );

                    return _shell(
                      transport: transport,
                      etoll: etoll,
                      line1: line1,
                      line2: line2,
                      hint: hint,
                      accent: BalanceColors.etollRed,
                    );
                  },
                );
              },
            );
          },
        );
      },
    );
  }

  Widget _shell({
