class OnlineStatusBadge extends StatefulWidget {
  const OnlineStatusBadge({super.key});

  @override
  State<OnlineStatusBadge> createState() => _OnlineStatusBadgeState();
}

class _OnlineStatusBadgeState extends State<OnlineStatusBadge>
    with SingleTickerProviderStateMixin {
  _NetState _state = _NetState.good;
  Timer? _timer;
  bool _checking = false;
  String _lang = 'ru';
  late final AnimationController _pulse;

  @override
  void initState() {
    super.initState();
    ProfileStore.language().then((l) {
      if (mounted) setState(() => _lang = l);
    });
    _pulse = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 750),
    )..repeat(reverse: true);
    _check();
    _timer = Timer.periodic(const Duration(seconds: 5), (_) => _check());
  }

  Future<void> _check() async {
    if (_checking) return;
    _checking = true;
    _NetState result;
    HttpClient? client;
    try {
      final sw = Stopwatch()..start();
      client = HttpClient()..connectionTimeout = const Duration(seconds: 4);
      final req = await client
          .getUrl(Uri.parse('https://www.gstatic.com/generate_204'))
          .timeout(const Duration(seconds: 4));
      final resp = await req.close().timeout(const Duration(seconds: 4));
      sw.stop();
      await resp.drain<void>();
      if (resp.statusCode >= 200 && resp.statusCode < 400) {
        // быстро — хорошо, медленно — нестабильно
        result = sw.elapsedMilliseconds < 900
            ? _NetState.good
            : _NetState.unstable;
      } else {
        result = _NetState.unstable;
      }
    } catch (_) {
      result = _NetState.none;
    } finally {
      try {
        client?.close(force: true);
      } catch (_) {}
    }
    if (mounted) setState(() => _state = result);
    _checking = false;
  }

  @override
  void dispose() {
    _timer?.cancel();
    _pulse.dispose();
    super.dispose();
  }

  Color get _color {
    switch (_state) {
      case _NetState.good:
        return AppColors.accent; // синий — хорошее
      case _NetState.unstable:
        return AppColors.amber; // жёлтый — нестабильно
      case _NetState.none:
        return AppColors.etollRed; // красный — нет интернета
    }
  }

  String get _label {
    switch (_state) {
      case _NetState.good:
        return AppStrings.tr(gAppLang, 'net_online');
      case _NetState.unstable:
        return AppStrings.tr(gAppLang, 'net_weak');
      case _NetState.none:
        return AppStrings.tr(gAppLang, 'net_none');
    }
  }

