import 'balance_bindings.dart';
import 'etoll_card_sync.dart';
import 'etoll_details_store.dart';
import 'etoll_refresh_status.dart';

/// Карта + prepaid/details после успешного refresh баланса.
abstract final class EtollCardAfterBalance {
  static Future<void> sync({
    required Future<String?> Function() subjectId,
    required Future<String> Function() resolvedAccountId,
    required Future<List<Map<String, String>>> Function() firms,
    required CredentialsLoader loadCredentials,
    required Future<void> Function(String card4) setTopUpCard4,
    required Future<void> Function(bool v) setAutoTopUp,
    required Future<void> Function(String id) setAccountId,
    required Future<void> Function(String firmId) saveFirmSnapshot,
  }) async {
    if (EtollRefreshStatus.active.value) {
      EtollRefreshStatus.setPhase('card');
      final st = EtollRefreshStatus.state.value.stage;
      if (!st.startsWith('session') && st != 'card-timeout') {
        EtollRefreshStatus.setStage('card');
      }
    }

    final sid = (await subjectId())?.trim() ?? '';
    if (sid.isNotEmpty) {
      final cached = await EtollDetailsStore.load(sid);
      if (cached != null && cached.hasCard) {
        await setTopUpCard4(cached.card4);
        if (cached.hasAutoFromSite) {
          await setAutoTopUp(true);
        } else if (cached.finType.isNotEmpty) {
          await setAutoTopUp(false);
        }
        await saveFirmSnapshot(sid);
        return;
      }
    }

    // Полоска уже прочитала карту in-session — не запускаем второй headless.
    if (EtollRefreshStatus.active.value) {
      final stage = EtollRefreshStatus.state.value.stage;
      if (stage == 'session-card-ok' || stage == 'session-fin-only') {
        final d = sid.isNotEmpty ? await EtollDetailsStore.load(sid) : null;
        if (d != null) {
          if (d.hasAutoFromSite) {
            await setAutoTopUp(true);
          } else if (d.finType.isNotEmpty) {
            await setAutoTopUp(false);
          }
        }
        if (sid.isNotEmpty) await saveFirmSnapshot(sid);
        return;
      }
      if (stage == 'session-no-aid' ||
          stage == 'session-no-card' ||
          stage == 'session-error' ||
          stage == 'card-timeout') {
        if (sid.isNotEmpty) await saveFirmSnapshot(sid);
        return;
      }
    }

    await EtollCardSync.syncAfterBalanceRefresh(
      subjectId: subjectId,
      resolvedAccountId: resolvedAccountId,
      firms: firms,
      loadCredentials: loadCredentials,
      onCard4: setTopUpCard4,
      onPrepaidId: (id) async {
        final cur = (await subjectId())?.trim() ?? '';
        if (id.isNotEmpty && id != cur) await setAccountId(id);
      },
      onDetails: (d) async {
        if (d.hasAutoFromSite) {
          await setAutoTopUp(true);
        } else {
          await setAutoTopUp(false);
        }
      },
    );

    final saveId = (await subjectId())?.trim() ?? sid;
    if (saveId.isNotEmpty) await saveFirmSnapshot(saveId);
  }
}

import 'etoll_refresh_status.dart';

/// Старт/стоп полоски refresh и синхронизация метки фирмы.
abstract final class EtollRefreshFlow {
  static Future<String> firmLabelForLogin(
    String login,
    Future<List<Map<String, String>>> Function() firms,
  ) async {
    final lg = login.trim();
    if (lg.isEmpty) return '';
    try {
      final list = await firms();
      final f = list.firstWhere(
        (e) => (e['login'] ?? '').trim() == lg,
        orElse: () => <String, String>{},
      );
      final name = (f['name'] ?? '').trim();
      if (name.isNotEmpty) return name;
    } catch (_) {}
    return lg;
  }

  static Future<void> begin(
    String login, {
    String phase = 'balance',
    String massFirmLabel = '',
    Future<List<Map<String, String>>> Function()? firms,
  }) async {
    final label = massFirmLabel.isNotEmpty
        ? massFirmLabel
        : await firmLabelForLogin(login, firms ?? (() async => []));
    EtollRefreshStatus.begin(firm: label, phase: phase);
  }

  static void end() => EtollRefreshStatus.end();

  /// Пользователь переключил фирму на экране — обновить подпись на полоске.
  static void onViewingFirmChanged(String firmName) {
    if (!EtollRefreshStatus.active.value) return;
    final n = firmName.trim();
    if (n.isNotEmpty) EtollRefreshStatus.setFirm(n);
  }
}

