class _OnlineStatusBadgeState extends State<OnlineStatusBadge>
    with SingleTickerProviderStateMixin {
  String _transport = 'wifi';
  String _etoll = 'good';
  Timer? _timer;
  bool _checking = false;
  late final AnimationController _pulse;

  @override
  void initState() {
    super.initState();
    _pulse = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 750),
    )..repeat(reverse: true);
    _check();
    _timer = Timer.periodic(const Duration(seconds: 8), (_) => _check());
  }

  Future<void> _check() async {
    if (_checking) return;
    _checking = true;
    final snap = await EtollNetStatus.probe();
    if (mounted) {
      setState(() {
        _transport = snap.transport;
        _etoll = snap.etoll;
      });
    }
    _checking = false;
  }

  @override
  void dispose() {
    _timer?.cancel();
    _pulse.dispose();
    super.dispose();
  }

  _NetState get _state {
    if (_transport == 'none' || _etoll == 'offline') return _NetState.none;
    if (_etoll == 'weak') return _NetState.unstable;
    return _NetState.good;
  }

  Color get _color {
    switch (_state) {
      case _NetState.good:
        return AppColors.accent;
      case _NetState.unstable:
        return AppColors.amber;
      case _NetState.none:
        return AppColors.etollRed;
    }
  }

  String get _label {
    if (_transport == 'none') {
      return AppStrings.tr(gAppLang, 'net_none');
    }
    final trn = _transport == 'mobile'
        ? AppStrings.tr(gAppLang, 'net_mobile')
        : AppStrings.tr(gAppLang, 'net_wifi');
    final qual = switch (_etoll) {
      'weak' => AppStrings.tr(gAppLang, 'net_weak'),
      'offline' => AppStrings.tr(gAppLang, 'net_etoll_off'),
      _ => AppStrings.tr(gAppLang, 'net_online'),
    };
    return '$trn · $qual';
  }

  @override
  Widget build(BuildContext context) {
    final c = _color;
    return AnimatedBuilder(
      animation: _pulse,
      builder: (context, _) {
        // нет интернета — сильное мигание; иначе — лёгкая «живая» пульсация
        final double dotOpacity = _state == _NetState.none
            ? (0.2 + 0.8 * _pulse.value)
            : (0.65 + 0.35 * _pulse.value);
        return Container(
          padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
          decoration: BoxDecoration(
            color: c.withValues(alpha: 0.12),
            borderRadius: BorderRadius.circular(20),
            border: Border.all(color: c.withValues(alpha: 0.6)),
          ),
          child: Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              Container(
                width: 9,
                height: 9,
                decoration: BoxDecoration(
                  color: c.withValues(alpha: dotOpacity),
                  shape: BoxShape.circle,
                  boxShadow: [
                    BoxShadow(
                      color: c.withValues(alpha: 0.6 * dotOpacity),
                      blurRadius: 6,
                      spreadRadius: 1,
                    ),
                  ],
                ),
              ),
              const SizedBox(width: 7),
              Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    AppStrings.tr(gAppLang, 'net_label'),
                    style: const TextStyle(
                      color: AppColors.textMuted,
                      fontSize: 8,
                      fontWeight: FontWeight.w700,
                      letterSpacing: 1.2,
                    ),
                  ),
                  Text(
                    _label,
                    style: TextStyle(
                      color: c,
                      fontSize: 12,
                      fontWeight: FontWeight.w800,
                      letterSpacing: 1,
                    ),
                  ),
                ],
              ),
            ],
          ),
        );
      },
    );
  }
}

