import 'dart:io';

import 'package:connectivity_plus/connectivity_plus.dart';

import 'etoll_urls.dart';

/// Канал связи телефона. Скорость интернета пользователя ≠ ответ eTOLL.
class EtollNetSnapshot {
  /// wifi | mobile | none — из системы телефона.
  final String transport;

  /// ok | slow | unknown — мягкая проба кабинета (HttpClient может ошибаться).
  final String etollServer;
  final int latencyMs;

  const EtollNetSnapshot({
    this.transport = 'none',
    this.etollServer = 'unknown',
    this.latencyMs = 0,
  });

  /// У пользователя есть интернет (Wi‑Fi или LTE).
  bool get userOnline => transport != 'none';
}

abstract final class EtollNetStatus {
  static const _probeUrl = '${EtollUrls.base}';
  static const _probeTimeout = Duration(seconds: 12);
  static const _slowMs = 8000;

  static Future<String> _transport() async {
    try {
      final results = await Connectivity().checkConnectivity();
      if (results.isEmpty ||
          results.every((r) => r == ConnectivityResult.none)) {
        return 'none';
      }
      if (results.contains(ConnectivityResult.wifi) ||
          results.contains(ConnectivityResult.ethernet)) {
        return 'wifi';
      }
      if (results.contains(ConnectivityResult.mobile)) {
        return 'mobile';
      }
      return 'mobile';
    } catch (_) {
      return 'none';
    }
  }

  /// transport = реальный канал телефона; etollServer — только подсказка про сервер.
  static Future<EtollNetSnapshot> probe() async {
    final transport = await _transport();
    if (transport == 'none') {
      return const EtollNetSnapshot(transport: 'none');
    }

    HttpClient? client;
    try {
      final sw = Stopwatch()..start();
      client = HttpClient()..connectionTimeout = _probeTimeout;
      final req = await client
          .getUrl(Uri.parse(_probeUrl))
          .timeout(_probeTimeout);
      req.headers.set(
        HttpHeaders.userAgentHeader,
        'Mozilla/5.0 (Linux; Android 14) AppleWebKit/537.36 Chrome/149 Mobile Safari/537.36',
      );
      final resp = await req.close().timeout(_probeTimeout);
      sw.stop();
      await resp.drain<void>();
      final ms = sw.elapsedMilliseconds;
      if (resp.statusCode >= 200 && resp.statusCode < 500) {
        return EtollNetSnapshot(
          transport: transport,
          etollServer: ms < _slowMs ? 'ok' : 'slow',
          latencyMs: ms,
        );
      }
      return EtollNetSnapshot(
        transport: transport,
        etollServer: 'slow',
        latencyMs: ms,
      );
    } catch (_) {
      // Incapsula / SPA часто режут HttpClient — интернет у пользователя при этом OK.
      return EtollNetSnapshot(transport: transport, etollServer: 'unknown');
    } finally {
      try {
        client?.close(force: true);
      } catch (_) {}
    }
  }

  static Future<bool> hasAnyNetwork() async {
    final t = await _transport();
    return t != 'none';
  }
}

