Future<void> _gotoFinancingForRefresh(Uri? url) async {
  if (_controller == null || _refreshAborted) return;
  final isLogin = widget.autoLogin != null && widget.autoLogin!.isNotEmpty;
  if (!isLogin) return;
  final u = url?.toString() ?? '';
  if (u.contains('login')) return;
  final m = RegExp(r'/subject/(\d+)').firstMatch(u);
  final id = m?.group(1) ?? '';
  if (id.isEmpty) return;
  await BalanceStore.setSubjectId(id);
  if (u.contains('/manage/financing/list') ||
      u.contains('/financing/prepaid/')) {
    await _readFinancingInfo();
    return;
