  final fn = await _controller!.evaluateJavascript(source: r'''
    (function(){try{
      var t=document.body?document.body.innerText:'';
      var lines = t.split('\n').map(function(s){return s.trim();}).filter(function(s){return s;});
      var g=/^(good\s+morning|good\s+afternoon|good\s+evening|good\s+day|good\s+night|welcome\s+back|welcome|hello|hi|witaj|witamy|dzie[nń]\s+dobry|dobry\s+wiecz[oó]r|добро пожаловать|доброе утро|добрый день|добрый вечер|здравствуйте)\s*[,!:.\-]\s*(.+)$/i;
      for(var i=0;i<lines.length;i++){
        var mm=lines[i].match(g);
        if(mm && mm[2]){ var nm=mm[2].replace(/\s+/g,' ').trim(); if(nm.length>1 && nm.length<80) return nm; }
      }
      var m=t.match(/[^\n]*(S\.R\.L\.|S\.R\.L|SRL|Sp\.\s*z\s*o\.o\.|S\.A\.|GmbH|OOO|ООО|SP\.|LLC)[^\n]*/i);
      return m?m[0].replace(/\s+/g,' ').trim().substring(0,80):'';
    }catch(e){return '';}})();
  ''');
  final firm = stripGreeting((fn ?? '').toString().trim());
  if (firm.isNotEmpty) {
    await BalanceStore.setCompany(firm);
    await BalanceStore.addFirm(id, firm, (widget.autoLogin ?? '').trim());
  }
  if (_financingNavDone) return;
  final listUrl = EtollUrls.financingList(id);
  if (widget.onDone != null) {
    EtollDebugWeb.track(
      'Баланс · ${widget.autoLogin ?? ''}',
      listUrl,
      stage: 'financing-list',
    );
  }
  await _controller!.loadUrl(
    urlRequest: URLRequest(url: WebUri(listUrl)),
  );
  _financingNavDone = true;
}

Future<void> _readFinancingInfo() async {
  if (_controller == null || _refreshAborted || _readingFinancing) return;
  _readingFinancing = true;
  try {
    await _pollFinancingInfo();
  } finally {
    _readingFinancing = false;
  }
}

static const _readPlnJs = r'''
  (function(){
    try {
      var t = document.body ? document.body.innerText : '';
      var m = t.match(/([0-9]+[.,][0-9]{2})\s*PLN/i)
           || t.match(/([0-9][0-9\s.,]*[0-9]|[0-9])\s*PLN/i);
      return m ? m[0].replace(/\s+/g,' ').trim() : '';
    } catch(e){ return ''; }
  })();
''';

Future<void> _pollFinancingInfo() async {
  String bal = '';
  String accId = '';
  String subj = '';
  for (int attempt = 0; attempt < 30; attempt++) {
    if (_refreshAborted || _controller == null) return;
    if (!await EtollPageReady.ensureReady(_controller!)) continue;
    final u = (await _controller!.getUrl())?.toString() ?? '';
    if (widget.onDone != null) {
      EtollDebugWeb.track('Баланс · ${widget.autoLogin ?? ''}', u);
    }
    final sidM = RegExp(r'/subject/(\d+)').firstMatch(u);
    subj = sidM?.group(1) ?? subj;
    final res = await _controller!.evaluateJavascript(source: _readPlnJs);
    bal = (res ?? '').toString().trim();
    final aidRes = await _controller!.evaluateJavascript(
      source: EtollFinancingNav.extractAccountIdJs,
    );
    accId = (aidRes ?? '').toString().trim();
    if (accId == subj) accId = '';
    if (bal.isNotEmpty &&
        accId.isEmpty &&
        subj.isNotEmpty &&
        !u.contains('/manage/financing/list')) {
      final listUrl = EtollUrls.financingList(subj);
      await _controller!.loadUrl(
        urlRequest: URLRequest(url: WebUri(listUrl)),
      );
      await EtollPageReady.waitAfterAction(_controller!, urlBefore: u);
      continue;
    }
    if (bal.isNotEmpty) break;
    await EtollPageReady.waitForJs(
      _controller!,
      EtollPageReady.hasPlnBalanceJs,
    );
  }
  if (bal.isEmpty || _refreshAborted) return;
  final prevId = (await BalanceStore.subjectId())?.trim() ?? '';
  await BalanceStore.saveBalance(bal);
  if (subj.isNotEmpty) await BalanceStore.setSubjectId(subj);
  if (accId.isNotEmpty) await BalanceStore.setAccountId(accId);
  if (widget.autoLogin != null && widget.autoLogin!.isNotEmpty) {
    await BalanceStore.setLastLogin(widget.autoLogin!);
  }
  if (mounted) setState(() => _balance = bal);

  if (widget.onDone != null &&
      _controller != null &&
      !_refreshAborted) {
    final firmId =
        subj.isNotEmpty ? subj : (await BalanceStore.subjectId()) ?? '';
    if (firmId.isNotEmpty) {
      final aliasId =
          prevId.isNotEmpty && prevId != firmId ? prevId : null;
      await EtollCardInSession.read(
        ctrl: _controller!,
        firmId: firmId,
        subjectId: firmId,
        accountId: accId,
        aliasFirmId: aliasId,
        onCard4: BalanceStore.setTopUpCard4,
        onPrepaidId: (id) async {
          if (id.isNotEmpty && id != firmId) {
            await BalanceStore.setAccountId(id);
          }
        },
      );
      final d = await EtollDetailsStore.load(firmId);
      if (d != null) {
        if (d.hasAutoFromSite) {
          await BalanceStore.setAutoTopUp(true);
        } else if (d.finType.isNotEmpty) {
          await BalanceStore.setAutoTopUp(false);
        }
      }
      await BalanceStore.saveFirmSnapshotFromGlobals(firmId);
    }
  }

  _closedAfterRead = true;
  if (_controller != null && !_refreshAborted) {
    await EtollPageReady.ensureReady(_controller!);
  }
  if (_refreshAborted) return;
  if (widget.onDone != null) {
    widget.onDone!();
  } else {
    Navigator.of(context).maybePop();
  }
}

