import 'card_brand_detect.dart';

/// Одна сохранённая карта (с tecspayment или details).
class EtollSavedCard {
  final String card4;
  final String cardType; // visa | mastercard | …
  final bool isDefault;

  const EtollSavedCard({
    required this.card4,
    this.cardType = '',
    this.isDefault = false,
  });

  bool get valid => card4.length == 4;

  String get resolvedType => CardBrandDetect.fromSiteText(cardType);

  String get label {
    final b = CardBrandDetect.label(resolvedType);
    return b.isNotEmpty ? '$b …$card4' : '…$card4';
  }

  Map<String, dynamic> toJson() => {
        'card4': card4,
        'cardType': cardType,
        'isDefault': isDefault,
      };

  factory EtollSavedCard.fromJson(Map<String, dynamic> m) {
    return EtollSavedCard(
      card4: (m['card4'] ?? '').toString(),
      cardType: (m['cardType'] ?? '').toString(),
      isDefault: m['isDefault'] == true,
    );
  }

  @override
  bool operator ==(Object other) =>
      other is EtollSavedCard && other.card4 == card4;

  @override
  int get hashCode => card4.hashCode;
}

/// Результат сверки списка карт после refresh.
class EtollCardListDiff {
  final List<EtollSavedCard> added;
  final List<EtollSavedCard> removed;
  final List<EtollSavedCard> current;

  const EtollCardListDiff({
    this.added = const [],
    this.removed = const [],
    this.current = const [],
  });

  bool get changed => added.isNotEmpty || removed.isNotEmpty;
}

import 'dart:convert';

import 'package:shared_preferences/shared_preferences.dart';

import 'etoll_saved_card.dart';

/// Все карты фирмы (tecspayment Select Card) — отдельно от одной карты на details.
class EtollCardListStore {
  static String _key(String firmId) => 'etoll_cards_$firmId';

  static Future<List<EtollSavedCard>> load(String firmId) async {
    if (firmId.isEmpty) return [];
    final prefs = await SharedPreferences.getInstance();
    final raw = prefs.getString(_key(firmId));
    if (raw == null || raw.isEmpty) return [];
    try {
      final list = jsonDecode(raw) as List;
      return list
          .map((e) => EtollSavedCard.fromJson(
              Map<String, dynamic>.from(e as Map)))
          .where((c) => c.valid)
          .toList();
    } catch (_) {
      return [];
    }
  }

  static Future<void> save(String firmId, List<EtollSavedCard> cards) async {
    if (firmId.isEmpty) return;
    final unique = _dedupe(cards);
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(
      _key(firmId),
      jsonEncode(unique.map((c) => c.toJson()).toList()),
    );
  }

  static Future<EtollCardListDiff> saveAndDiff(
    String firmId,
    List<EtollSavedCard> incoming,
  ) async {
    final prev = await load(firmId);
    final next = _dedupe(incoming);
    await save(firmId, next);
    final prevSet = {for (final c in prev) c.card4};
    final nextSet = {for (final c in next) c.card4};
    return EtollCardListDiff(
      added: next.where((c) => !prevSet.contains(c.card4)).toList(),
      removed: prev.where((c) => !nextSet.contains(c.card4)).toList(),
      current: next,
    );
  }

  static List<EtollSavedCard> _dedupe(List<EtollSavedCard> cards) {
    final seen = <String>{};
    final out = <EtollSavedCard>[];
    for (final c in cards) {
      if (!c.valid || seen.contains(c.card4)) continue;
      seen.add(c.card4);
      out.add(c);
    }
    return out;
  }
}

import 'dart:convert';

import 'etoll_saved_card.dart';

/// Парсинг страницы tecspayment (Select Card) — полный список карт.
abstract final class EtollTecsPaymentParser {
  static bool isGatewayUrl(String url) {
    final lu = url.toLowerCase();
    return lu.contains('tecspayment') ||
        lu.contains('tecs-pay') ||
        (lu.contains('tecs') && lu.contains('payment'));
  }

  static bool looksLikeSelectCard(String url, String bodySample) {
    if (isGatewayUrl(url)) return true;
    final t = bodySample.toLowerCase();
    return t.contains('select card') ||
        t.contains('wybierz kart') ||
        t.contains('choose card') ||
        t.contains('select a card');
  }

  static const hasCardsJs = r'''
(function(){
  try {
    var t = (document.body && document.body.innerText) ? document.body.innerText : '';
    if (!t) return '0';
    var low = t.toLowerCase();
    if (low.indexOf('select card')>=0 || low.indexOf('wybierz kart')>=0) return '1';
    if (/(visa|mastercard|maestro)[^\d]{0,30}\d{4}/i.test(t)) return '1';
    if (/(\*{2,}|•+|\.{3,})\s*\d{4}\b/.test(t)) return '1';
    return '0';
  } catch(e){ return '0'; }
})();
''';

  static const parseJs = r'''
(function(){
  try {
    var out = [];
    var seen = {};
    function add(type, last4, isDefault){
      if (!last4 || last4.length !== 4 || seen[last4]) return;
      seen[last4] = true;
      out.push({card4: last4, cardType: (type||'').toLowerCase(), isDefault: !!isDefault});
    }
    var body = (document.body && document.body.innerText) ? document.body.innerText : '';
    var html = (document.body && document.body.innerHTML) ? document.body.innerHTML : '';

    // Visa/Mastercard …6534
    var re1 = /(visa|mastercard|maestro|amex|discover)[^\d]{0,40}(\d{4})\b/gi;
    var m;
    while ((m = re1.exec(body)) !== null) {
      add(m[1], m[2], false);
    }

    // Маска + 4 цифры: ****2488, ••••6534
    var re2 = /(?:\*{2,}|•+|\.{3,}|…)\s*(\d{4})\b/g;
    while ((m = re2.exec(body)) !== null) {
      add('', m[1], false);
    }

    // radio / selected row — default card
    var inputs = document.querySelectorAll('input[type="radio"],input[type="checkbox"]');
    for (var i=0;i<inputs.length;i++){
      var inp = inputs[i];
      if (!inp.checked && inp.type==='radio') continue;
      var row = inp.closest('label,li,div,tr,mat-list-item') || inp.parentElement;
      if (!row) continue;
      var rt = (row.innerText||'').trim();
      var rm = rt.match(/(visa|mastercard|maestro)[^\d]{0,30}(\d{4})/i);
      if (rm) { add(rm[1], rm[2], inp.checked); continue; }
      var rm2 = rt.match(/(\*{2,}|•+|\.{3,})\s*(\d{4})/);
      if (rm2) add('', rm2[2], inp.checked);
    }

    // data-* в html
    var re3 = /(\d{4})<\/[^>]+>(?:\s|<)*$/gm;
    // fallback: любые 4 цифры после card/karta в строке
    var lines = body.split('\n');
    for (var li=0; li<lines.length; li++){
      var ln = lines[li];
      if (!/(card|karta|visa|master|maestro)/i.test(ln)) continue;
      var gm = ln.match(/(\d{4})\s*$/);
      if (gm) add('', gm[1], li===0);
    }

    return JSON.stringify(out);
  } catch(e){ return '[]'; }
})();
''';

  static List<EtollSavedCard> parseResult(Object? raw) {
    if (raw == null) return [];
    var s = raw.toString().trim();
    if (s.isEmpty || s == 'null') return [];
    try {
      final decoded = jsonDecode(s);
      if (decoded is! List) return [];
      final cards = decoded
          .map((e) => EtollSavedCard.fromJson(
              Map<String, dynamic>.from(e as Map)))
          .where((c) => c.valid)
          .toList();
      if (cards.isEmpty) return cards;
      // Если default не помечена — первая = default (как на видео MC …2488).
      if (!cards.any((c) => c.isDefault)) {
        return [
          EtollSavedCard(
            card4: cards.first.card4,
            cardType: cards.first.cardType,
            isDefault: true,
          ),
          ...cards.skip(1),
        ];
      }
      return cards;
    } catch (_) {
      return [];
    }
  }
}

import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_debug_web.dart';
import 'etoll_page_ready.dart';
import 'etoll_refresh_status.dart';
import 'etoll_saved_card.dart';
import 'etoll_tecspayment_parser.dart';
