import 'package:shared_preferences/shared_preferences.dart';

/// Спросить refresh на главной после смены версии приложения (pubspec version+build).
abstract final class AppUpgradePrompt {
  static const _key = 'app_build_marker';

  /// Должно совпадать с `version` в pubspec.yaml (1.0.0+2 → 1.0.0+2).
  static const currentMarker = '1.0.0+2';

  /// true — версия изменилась с прошлого запуска (обновление APK).
  static Future<bool> needsRefreshAfterUpgrade() async {
    final prefs = await SharedPreferences.getInstance();
    final prev = prefs.getString(_key);
    return prev != null && prev != currentMarker;
  }

  static Future<void> markCurrentVersionSeen() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(_key, currentMarker);
  }

  /// Первый запуск — запомнить версию без принудительного refresh.
  static Future<void> ensureStored() async {
    final prefs = await SharedPreferences.getInstance();
    if (!prefs.containsKey(_key)) {
      await prefs.setString(_key, currentMarker);
    }
  }
}

import 'package:shared_preferences/shared_preferences.dart';

/// Главный экран: когда показывать детальные этапы refresh (не баннер).
abstract final class HomeRefreshUi {
  static const _massEverKey = 'home_mass_refresh_ever';
  static String _watchKey(String firmId) => 'firm_card_watch_$firmId';

  /// Первое массовое обновление или у фирмы раньше менялись карты.
  static Future<bool> shouldShowStagesFor(String firmId) async {
    if (!(await massRefreshEverDone())) return true;
    if (firmId.isEmpty) return false;
    final prefs = await SharedPreferences.getInstance();
    return prefs.getBool(_watchKey(firmId)) ?? false;
  }

  static Future<bool> massRefreshEverDone() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getBool(_massEverKey) ?? false;
  }

  static Future<void> markMassRefreshEverDone() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_massEverKey, true);
  }

  static Future<void> setCardWatch(String firmId, bool watch) async {
    if (firmId.isEmpty) return;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_watchKey(firmId), watch);
  }
}

