Future<void> _homeRefreshSingleFirm() async {
  final firms = await BalanceStore.visibleFirms();
  String? login;
  if (firms.length == 1) {
    login = (firms.first['login'] ?? '').trim();
    if (login.isEmpty) login = null;
  }
  login ??= await BalanceStore.lastLogin();
  if (login == null || login.isEmpty) return;
  final fid = (await BalanceStore.subjectId())?.trim() ?? '';
  gHomeRefreshFirmId = fid.isNotEmpty ? fid : null;
  if (mounted) {
    setState(() {
      _homeShowStageDetail =
          fid.isNotEmpty && HomeRefreshUi.shouldShowStagesFor(fid) as bool;
    });
  }
  final showStages = fid.isNotEmpty
      ? await HomeRefreshUi.shouldShowStagesFor(fid)
      : false;
  if (mounted) setState(() => _homeShowStageDetail = showStages);
  final ok = await _homeRefreshViaStripe(login);
  if (!mounted) return;
  try {
    if (ok && !_etollRefreshStopped) {
      await syncEtollCardAfterBalanceGlobal();
      await _loadHomeBalance();
      _flashHomePlateOk();
      await HomeRefreshUi.markMassRefreshEverDone();
      await AppUpgradePrompt.markCurrentVersionSeen();
    } else if (!ok || _etollRefreshStopped) {
      _flashHomePlateFail();
    }
  } finally {
    gHomeRefreshFirmId = null;
    if (mounted) setState(() => _homeShowStageDetail = false);
    endEtollRefreshStatus();
  }
}

