import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_card_list_store.dart';
import 'etoll_debug_web.dart';
import 'etoll_details_model.dart';
import 'etoll_details_parser.dart';
import 'etoll_details_store.dart';
import 'etoll_financing_nav.dart';
import 'etoll_page_ready.dart';
import 'etoll_refresh_status.dart';
import 'etoll_saved_card.dart';
import 'etoll_topup_in_session.dart';
import 'etoll_urls.dart';

/// Чтение карты в уже залогиненной сессии WebView (после баланса).
/// Путь: прямой URL details → top-up → tecspayment (без лишних кликов).
abstract final class EtollCardInSession {
  static const _topUpBudget = Duration(seconds: 90);

  static Future<EtollPrepaidDetails?> read({
    required InAppWebViewController ctrl,
    required String firmId,
    required String subjectId,
    String accountId = '',
    String? aliasFirmId,
    void Function(String card4)? onCard4,
    void Function(String prepaidId)? onPrepaidId,
    void Function(EtollCardListDiff diff)? onCardListDiff,
  }) async {
    if (firmId.isEmpty || subjectId.isEmpty) return null;
    if (EtollRefreshStatus.cancelRequested) return null;

    const step = EtollPageReady.refreshStepWait;
    var aid = accountId.trim();
    if (aid == subjectId.trim()) aid = '';

    String diagStage = 'session-start';

    try {
      final curUrl = (await ctrl.getUrl())?.toString() ?? '';
      if (aid.isEmpty) {
        aid = EtollFinancingNav.prepaidIdFromUrl(curUrl);
        if (aid == subjectId) aid = '';
      }
      if (aid.isEmpty) {
        aid = (await _extractPrepaidId(ctrl)).trim();
        if (aid == subjectId) aid = '';
      }

      // Нет prepaid ID — один раз list, вытащить ID, сразу на details.
      if (aid.isEmpty) {
        diagStage = 'session-goto-list';
        final listUrl = EtollUrls.financingList(subjectId);
        await EtollPageReady.loadAndWait(
          ctrl,
          WebUri(listUrl),
          maxWait: step,
        );
        EtollDebugWeb.track('Карта in-session', listUrl, stage: diagStage);
        await EtollPageReady.waitForJs(
          ctrl,
          EtollFinancingNav.hasPrepaidAccountJs,
          maxWait: step,
        );
        aid = (await _extractPrepaidId(ctrl)).trim();
        if (aid == subjectId) aid = '';
      }

      if (aid.isEmpty) {
        diagStage = 'session-no-aid';
        EtollDebugWeb.setStage(diagStage);
        return null;
      }

      // Прямой URL details (не клик «Details» на list).
      diagStage = 'session-open-details';
      final detailsUrl = EtollUrls.prepaidDetails(subjectId, aid);
      await EtollPageReady.loadAndWait(
        ctrl,
        WebUri(detailsUrl),
        maxWait: step,
      );
      EtollDebugWeb.track('Карта in-session', detailsUrl, stage: diagStage);
      await EtollPageReady.waitForUrlContains(ctrl, '/details', maxWait: step);

      EtollPrepaidDetails? result;
      for (int i = 0; i < 6; i++) {
        if (EtollRefreshStatus.cancelRequested) {
          diagStage = 'stopped';
          EtollDebugWeb.setStage(diagStage);
          break;
        }
        await EtollPageReady.ensureReady(ctrl, maxWait: step);
        final cur = ((await ctrl.getUrl())?.toString() ?? '').toLowerCase();
        if (!cur.contains('/details') || !cur.contains('/prepaid')) {
          await EtollPageReady.loadAndWait(
            ctrl,
            WebUri(detailsUrl),
            maxWait: step,
          );
          continue;
        }
        final raw =
            await ctrl.evaluateJavascript(source: EtollDetailsParser.parseJs);
        final parsed = EtollDetailsParser.parseResult(raw);
        if (parsed.hasCard || parsed.finType.isNotEmpty) {
          result = parsed;
          final alias = aliasFirmId?.trim() ?? '';
          if (alias.isNotEmpty && alias != firmId) {
            await EtollDetailsStore.saveBoth(firmId, alias, parsed);
          } else {
            await EtollDetailsStore.save(firmId, parsed);
          }
          if (parsed.hasCard && onCard4 != null) onCard4(parsed.card4);
          diagStage =
              parsed.hasCard ? 'session-details-ok' : 'session-fin-only';
          EtollDebugWeb.setStage(diagStage, url: cur);
          break;
        }
        await EtollPageReady.waitForJs(
          ctrl,
          EtollDetailsParser.hasContentJs,
          maxWait: step,
        );
      }

      // Прямой top-up → tecspayment (отдельный бюджет времени).
      if (aid.isNotEmpty && !EtollRefreshStatus.cancelRequested) {
        EtollRefreshStatus.setPhase('card');
        final topUpDeadline = DateTime.now().add(_topUpBudget);
        final cards = await EtollTopUpInSession.unlockCardList(
          ctrl: ctrl,
          subjectId: subjectId,
          prepaidId: aid,
          deadline: topUpDeadline,
        );
        if (cards.isNotEmpty) {
          final diff = await EtollCardListStore.saveAndDiff(firmId, cards);
          onCardListDiff?.call(diff);
          final primary = cards.firstWhere(
            (c) => c.isDefault,
            orElse: () => cards.first,
          );
          if (primary.valid && onCard4 != null) onCard4(primary.card4);
          diagStage = 'session-cards-ok';
          EtollDebugWeb.setStage(diagStage);
        } else if (result == null) {
          diagStage = 'session-no-card';
          EtollDebugWeb.setStage(diagStage);
        }
      } else if (result == null) {
        diagStage = 'session-no-card';
        EtollDebugWeb.setStage(diagStage);
      }

      if (aid.isNotEmpty && onPrepaidId != null) onPrepaidId(aid);
      return result;
    } catch (_) {
      diagStage = 'session-error';
      EtollDebugWeb.setStage(diagStage);
      return null;
    } finally {
      await EtollDetailsStore.saveDiag(
        firmId,
        '[$diagStage] sid=$subjectId aid=${aid.isNotEmpty ? aid : accountId} in-session',
      );
    }
  }

  static Future<String> _extractPrepaidId(InAppWebViewController ctrl) async {
    if (!await EtollPageReady.isReady(ctrl)) return '';
    final extracted = await ctrl.evaluateJavascript(
      source: EtollFinancingNav.extractAccountIdJs,
    );
    return (extracted ?? '').toString().trim();
  }
}

import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_debug_web.dart';
import 'etoll_page_ready.dart';
import 'etoll_refresh_status.dart';
import 'etoll_saved_card.dart';
import 'etoll_tecspayment_parser.dart';
