/// В той же сессии WebView: top-up 20 PLN → PayByNet → tecspayment → все карты. Без оплаты.
abstract final class EtollTopUpInSession {
  static const unlockAmountPln = '20';
  static const _step = EtollPageReady.refreshStepWait;

  static Future<List<EtollSavedCard>> unlockCardList({
    required InAppWebViewController ctrl,
    required String subjectId,
    required String prepaidId,
    DateTime? deadline,
  }) async {
    if (subjectId.isEmpty || prepaidId.isEmpty) return [];
    if (EtollRefreshStatus.cancelRequested) return [];

    final end = deadline ?? DateTime.now().add(const Duration(seconds: 90));
    Duration left() {
      final d = end.difference(DateTime.now());
      return d.isNegative ? Duration.zero : d;
    }

    Duration cap(Duration preferred) {
      final l = left();
      if (l <= Duration.zero) return Duration.zero;
      return l < preferred ? l : preferred;
    }

    Future<bool> ready({Duration preferred = _step}) async {
      final l = left();
      if (l <= Duration.zero) return false;
      final m = l < preferred ? l : preferred;
      return EtollPageReady.ensureReady(ctrl, maxWait: m);
    }

    // Сразу прямой URL top-up (не клики по меню).
    EtollRefreshStatus.setStage('top-up');
    final topUpUrl = EtollUrls.prepaidTopUp(subjectId, prepaidId);
    await EtollPageReady.loadAndWait(
      ctrl,
      WebUri(topUpUrl),
      maxWait: cap(_step),
    );
    EtollDebugWeb.track('Refresh unlock', topUpUrl, stage: 'top-up');

    var amountFilled = false;
    int payClicks = 0;

    for (int tick = 0; tick < 50 && left() > Duration.zero; tick++) {
      if (EtollRefreshStatus.cancelRequested) break;
      if (!await ready()) continue;

      final cur = (await ctrl.getUrl())?.toString() ?? '';
      final lu = cur.toLowerCase();
      EtollDebugWeb.track('Refresh unlock', cur);

      if (EtollTecsPaymentParser.isGatewayUrl(lu) ||
          EtollTecsPaymentParser.looksLikeSelectCard(
            cur,
            await _bodySample(ctrl),
          )) {
        EtollRefreshStatus.setStage('tecspayment');
        final cards = await _readGatewayCards(ctrl, left());
        if (cards.isNotEmpty) {
          EtollRefreshStatus.setStage('session-cards-ok');
          return cards;
        }
      }

      if (lu.contains('paybynet') || lu.contains('pay-by-net')) {
        EtollRefreshStatus.setStage('paybynet');
        if (payClicks < 8) {
          payClicks++;
          await _clickPayByNetOrProceed(ctrl);
          await EtollPageReady.waitAfterAction(
            ctrl,
            urlBefore: cur,
            maxWait: cap(_step),
          );
        }
        continue;
      }

      if (lu.contains('/payment') ||
          lu.contains('/summary') ||
          (lu.contains('/pay') && lu.contains('etoll'))) {
        EtollRefreshStatus.setStage('payment');
        if (payClicks < 8) {
          payClicks++;
          await _clickPayByNetOrProceed(ctrl);
          await EtollPageReady.waitAfterAction(
            ctrl,
            urlBefore: cur,
            maxWait: cap(_step),
          );
        }
        continue;
      }

      if (lu.contains('/top-up')) {
        EtollRefreshStatus.setStage('top-up');
        if (!amountFilled) {
          amountFilled = await _fillAmount(ctrl, unlockAmountPln);
          if (amountFilled) {
            await EtollPageReady.waitAfterAction(
              ctrl,
              urlBefore: cur,
              maxWait: cap(_step),
            );
            await _clickNext(ctrl);
          }
        } else {
          await _clickNext(ctrl);
        }
        continue;
      }

      // Не там где нужно — снова прямой URL top-up (не крутимся на list/manage).
      if (!EtollTecsPaymentParser.isGatewayUrl(lu)) {
        await EtollPageReady.loadAndWait(
          ctrl,
          WebUri(topUpUrl),
          maxWait: cap(_step),
        );
        amountFilled = false;
      }

      await Future<void>.delayed(const Duration(milliseconds: 350));
    }

    final lastCards = await _readGatewayCards(ctrl, left());
    if (lastCards.isNotEmpty) {
      EtollRefreshStatus.setStage('session-cards-ok');
    }
    return lastCards;
  }

  static Future<String> _bodySample(InAppWebViewController ctrl) async {
    final bodyHint = await ctrl.evaluateJavascript(source: r'''
      (function(){try{return (document.body&&document.body.innerText||'').substring(0,4000);}catch(e){return '';}})();
    ''');
    return (bodyHint ?? '').toString();
  }

  static Future<List<EtollSavedCard>> _readGatewayCards(
    InAppWebViewController ctrl,
    Duration budget,
  ) async {
    final cap = budget < _step ? budget : _step;
    await EtollPageReady.waitForJs(
      ctrl,
      EtollTecsPaymentParser.hasCardsJs,
      maxWait: cap,
    );
    for (int i = 0; i < 6; i++) {
      if (EtollRefreshStatus.cancelRequested) break;
      await EtollPageReady.ensureReady(ctrl, maxWait: _step);
      final raw =
          await ctrl.evaluateJavascript(source: EtollTecsPaymentParser.parseJs);
      final cards = EtollTecsPaymentParser.parseResult(raw);
      if (cards.isNotEmpty) return cards;
      await Future<void>.delayed(const Duration(milliseconds: 400));
    }
    return [];
  }

  static Future<bool> _fillAmount(InAppWebViewController ctrl, String amt) async {
    final safe = amt.replaceAll("'", '');
    final res = await ctrl.evaluateJavascript(source: '''
(function(){try{
  var want='$safe';
  function vis(el){return el&&el.offsetParent!==null&&!el.disabled&&!el.readOnly;}
  var ins=document.querySelectorAll('input');
  var byMeta=null, byNum=null, anyTxt=null;
  for(var i=0;i<ins.length;i++){var el=ins[i];if(!vis(el))continue;
    var ty=(el.type||'text').toLowerCase();
    if(ty==='password'||ty==='checkbox'||ty==='radio'||ty==='hidden'||ty==='submit'||ty==='button')continue;
    var meta=((el.name||'')+' '+(el.id||'')+' '+(el.placeholder||'')+' '+(el.getAttribute('aria-label')||'')).toLowerCase();
    if(!byMeta&&(meta.indexOf('kwot')>=0||meta.indexOf('amount')>=0||meta.indexOf('sum')>=0||meta.indexOf('warto')>=0))byMeta=el;
    if(!byNum&&ty==='number')byNum=el;
    anyTxt=el;
  }
  var target=byMeta||byNum||anyTxt;
  if(!target||!want) return '0';
  var setter=Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype,'value').set;
  setter.call(target, want);
  target.dispatchEvent(new Event('input',{bubbles:true}));
  target.dispatchEvent(new Event('change',{bubbles:true}));
  target.dispatchEvent(new Event('blur',{bubbles:true}));
  return '1';
}catch(e){return '0';}})();
''');
    return (res ?? '').toString().trim() == '1';
  }

  static Future<void> _clickNext(InAppWebViewController ctrl) async {
    await ctrl.evaluateJavascript(source: r'''
(function(){try{
  function realClick(el){try{var rc=el.getBoundingClientRect();
    var o={bubbles:true,cancelable:true,view:window,
      clientX:rc.left+rc.width/2,clientY:rc.top+rc.height/2};
    el.dispatchEvent(new MouseEvent('pointerdown',o));
    el.dispatchEvent(new MouseEvent('mousedown',o));
    el.dispatchEvent(new MouseEvent('mouseup',o));
    el.dispatchEvent(new MouseEvent('click',o));el.click();
  }catch(e){try{el.click();}catch(e2){}}}}
  var words=['next','dalej','continue','kontynuuj','proceed','przejdź','przejdz','далее','продолжить','дальше'];
  var btns=document.querySelectorAll('button,a,[role="button"],input[type="submit"],input[type="button"]');
  for(var i=0;i<btns.length;i++){var el=btns[i];
    if(el.offsetParent===null||el.disabled)continue;
    var t=(el.innerText||el.value||'').trim().toLowerCase();
    if(!t||t.length>28)continue;
    for(var w=0;w<words.length;w++){
      if(t===words[w]||t.indexOf(words[w])===0){realClick(el);return;}}}
}catch(e){}})();
''');
  }

  static Future<void> _clickPayByNetOrProceed(InAppWebViewController ctrl) async {
    await ctrl.evaluateJavascript(source: r'''
(function(){try{
  function realClick(el){try{el.click();}catch(e){}}
  var href=(location.href||'').toLowerCase();
  if(href.indexOf('tecspayment')>=0) return;
  var priority=['paybynet','pay by net','pay bynet','płatność paybynet','platnosc paybynet'];
  var els=document.querySelectorAll('button,a,[role="button"],input[type="submit"],input[type="button"]');
  for(var p=0;p<priority.length;p++){
    for(var i=0;i<els.length;i++){
      var el=els[i]; if(el.offsetParent===null||el.disabled) continue;
      var t=(el.innerText||el.value||'').trim().toLowerCase();
      if(t.indexOf(priority[p])>=0){ realClick(el); return; }
    }
  }
  var payWords=['pay','zapłać','zaplac','opłać','oplac','оплатить','pay now'];
  for(var i=0;i<els.length;i++){
    var el=els[i]; if(el.offsetParent===null||el.disabled) continue;
    var t=(el.innerText||el.value||'').trim().toLowerCase();
    if(!t||t.length>24) continue;
    if(t.indexOf('cancel')>=0||t.indexOf('anuluj')>=0||t.indexOf('отмен')>=0) continue;
    for(var w=0;w<payWords.length;w++){
      if(t===payWords[w]||t.indexOf(payWords[w])===0){ realClick(el); return; }
    }
  }
}catch(e){}})();
''');
  }
}

