import 'dart:convert';

import 'package:flutter_inappwebview/flutter_inappwebview.dart';

/// Выбор метода оплаты на страницах eTOLL / PayByNet / tecspayment.
/// Без клика по PayByNet (радио/плитка) до Select Card не дойти.
abstract final class EtollPaymentMethods {
  static const payByNetNeedles = [
    'paybynet',
    'pay by net',
    'pay bynet',
    'pay-by-net',
    'płatność paybynet',
    'platnosc paybynet',
    'płatność online paybynet',
  ];

  static const cardNeedles = [
    'karta płatnicza',
    'karta platnicza',
    'payment card',
    'credit card',
    'debit card',
    'card payment',
    'karta bankowa',
  ];

  /// Что видно на странице: методы оплаты, URL-тип, выбранное.
  static const probeJs = r'''
(function(){
  try {
    function txt(el){
      return ((el.innerText||el.textContent||el.value||el.getAttribute('aria-label')||'')+'').trim();
    }
    function vis(el){ return el && el.offsetParent!==null && !el.disabled; }
    var href=(location.href||'').toLowerCase();
    var body=(document.body&&document.body.innerText)||'';
    var low=body.toLowerCase();
    var methods=[];
    var seen={};
    function addMethod(name, kind, selected){
      var k=(name||'').toLowerCase().substring(0,40);
      if(!k||seen[k]) return;
      seen[k]=1;
      methods.push({name:name.substring(0,60), kind:kind, selected:!!selected});
    }
    var radios=document.querySelectorAll('input[type="radio"],mat-radio-button,[role="radio"]');
    for(var i=0;i<radios.length;i++){
      var r=radios[i];
      if(!vis(r) && r.tagName!=='MAT-RADIO-BUTTON') continue;
      var row=r.closest('label,mat-list-item,li,div,tr,mat-radio-button')||r.parentElement;
      var t=txt(row||r);
      if(!t||t.length>120) continue;
      var sel=r.checked||r.getAttribute('aria-checked')==='true'||
        (r.classList&&r.classList.contains('mat-radio-checked'));
      addMethod(t,'radio',sel);
    }
    var tiles=document.querySelectorAll(
      'mat-list-item,li,[class*="payment"],[class*="method"],label,a,button,[role="button"],[role="listitem"]');
    for(var j=0;j<tiles.length;j++){
      var el=tiles[j];
      if(!vis(el)) continue;
      var t2=txt(el).toLowerCase();
      if(t2.indexOf('paybynet')>=0||t2.indexOf('pay by net')>=0||
         t2.indexOf('karta')>=0||t2.indexOf('card')>=0||t2.indexOf('blik')>=0){
        addMethod(txt(el),'tile',false);
      }
    }
    var page='other';
    if(href.indexOf('tecspayment')>=0||href.indexOf('tecs-pay')>=0) page='tecspayment';
    else if(href.indexOf('paybynet')>=0||href.indexOf('pay-by-net')>=0) page='paybynet';
    else if(href.indexOf('/top-up')>=0) page='topup';
    else if(href.indexOf('/payment')>=0||href.indexOf('/summary')>=0) page='payment';
    else if(low.indexOf('select card')>=0||low.indexOf('wybierz kart')>=0) page='tecspayment';
    var hasPbn=low.indexOf('paybynet')>=0||low.indexOf('pay by net')>=0;
    var hasCards=/(visa|mastercard|maestro)[^\d]{0,20}\d{4}/i.test(body)||
      /(\*{2,}|•+)\s*\d{4}/.test(body);
    return JSON.stringify({
      page:page, href:href.substring(0,120), methods:methods.slice(0,12),
      hasPayByNet:hasPbn, hasCards:hasCards,
      bodyHead: body.substring(0,200).replace(/\s+/g,' ')
    });
  } catch(e){ return JSON.stringify({page:'err', methods:[], error:String(e)}); }
})();
''';

  static Future<PaymentPageProbe> probe(InAppWebViewController ctrl) async {
    final raw = await ctrl.evaluateJavascript(source: probeJs);
    return PaymentPageProbe.parse(raw);
  }

  /// Выбрать PayByNet: radio → label → плитка → картинка.
  static const selectPayByNetJs = r'''
(function(){
  try {
    function realClick(el){
      try {
        var rc=el.getBoundingClientRect();
        var o={bubbles:true,cancelable:true,view:window,
          clientX:rc.left+rc.width/2,clientY:rc.top+rc.height/2};
        el.dispatchEvent(new MouseEvent('pointerdown',o));
        el.dispatchEvent(new MouseEvent('mousedown',o));
        el.dispatchEvent(new MouseEvent('mouseup',o));
        el.dispatchEvent(new MouseEvent('click',o));
        el.click();
      } catch(e){ try{el.click();}catch(e2){} }
    }
    function fireInput(el){
      try{
        el.dispatchEvent(new Event('input',{bubbles:true}));
        el.dispatchEvent(new Event('change',{bubbles:true}));
      }catch(e){}
    }
    function textOf(el){
      return ((el.innerText||el.textContent||el.value||el.getAttribute('aria-label')||'')+'')
        .trim().toLowerCase();
    }
    function vis(el){ return el && el.offsetParent!==null && !el.disabled; }
    var needles=['paybynet','pay by net','pay bynet','pay-by-net',
      'płatność paybynet','platnosc paybynet','płatność online paybynet'];
    function matches(t){
      if(!t) return false;
      for(var i=0;i<needles.length;i++){
        if(t.indexOf(needles[i])>=0) return true;
      }
      return false;
    }
    // 1) mat-radio-button / radio + label
    var radios=document.querySelectorAll('mat-radio-button,input[type="radio"],[role="radio"]');
    for(var i=0;i<radios.length;i++){
      var r=radios[i];
      var row=r.closest('mat-radio-button,label,mat-list-item,li,div,tr')||r;
      if(!matches(textOf(row)) && !matches(textOf(r))) continue;
      var inp=r.querySelector&&r.querySelector('input[type="radio"]')||(
        r.tagName==='INPUT'&&r.type==='radio'?r:null);
      if(inp){ inp.checked=true; fireInput(inp); }
      realClick(r);
      if(row&&row!==r) realClick(row);
      return 'radio';
    }
    // 2) label / list item / tile
    var els=document.querySelectorAll(
      'label,mat-list-item,li,a,button,[role="button"],[role="listitem"],div,span');
    for(var j=0;j<els.length;j++){
      var el=els[j];
      if(!vis(el)) continue;
      var t=textOf(el);
      if(!matches(t)||t.length>100) continue;
      realClick(el);
      return 'tile';
    }
    // 3) img logo PayByNet
    var imgs=document.querySelectorAll('img');
    for(var k=0;k<imgs.length;k++){
      var im=imgs[k];
      var src=(im.getAttribute('src')||'').toLowerCase();
      var alt=(im.getAttribute('alt')||'').toLowerCase();
      if(src.indexOf('paybynet')>=0||alt.indexOf('paybynet')>=0){
        var p=im.closest('label,mat-list-item,li,a,button,[role="button"],div')||im;
        realClick(p);
        return 'img';
      }
    }
    // 4) ссылка paybynet
    var links=document.querySelectorAll('a[href*="paybynet"],a[href*="pay-by-net"]');
    for(var l=0;l<links.length;l++){
      if(!vis(links[l])) continue;
      realClick(links[l]);
      return 'link';
    }
    return 'none';
  } catch(e){ return 'err'; }
})();
''';

  /// На tecspayment: выбрать оплату картой / первую сохранённую карту.
  static const selectCardOnGatewayJs = r'''
(function(){
  try {
    function realClick(el){
      try{ el.click(); }catch(e){}
    }
    function vis(el){ return el && el.offsetParent!==null && !el.disabled; }
    function txt(el){
      return ((el.innerText||el.textContent||'')+'').trim().toLowerCase();
    }
    var radios=document.querySelectorAll('input[type="radio"],mat-radio-button,[role="radio"]');
    for(var i=0;i<radios.length;i++){
      var r=radios[i];
      var row=r.closest('label,mat-list-item,li,div,tr,mat-radio-button')||r;
      var t=txt(row||r);
      if(!t) continue;
      if(/visa|mastercard|maestro|\d{4}|karta|card/.test(t)){
        var inp=r.querySelector&&r.querySelector('input[type="radio"]')||
          (r.tagName==='INPUT'&&r.type==='radio'?r:null);
        if(inp){ inp.checked=true;
          inp.dispatchEvent(new Event('change',{bubbles:true}));
        }
        realClick(r);
        return 'card-radio';
      }
    }
    var items=document.querySelectorAll('mat-list-item,li,label,[role="listitem"],div');
    for(var j=0;j<items.length;j++){
      var el=items[j];
      if(!vis(el)) continue;
      var t2=txt(el);
      if(/visa|mastercard|maestro/.test(t2) && /\d{4}/.test(t2)){
        realClick(el);
        return 'card-tile';
      }
    }
    return 'none';
  } catch(e){ return 'err'; }
})();
''';

  /// Dalej / Pay / Zapłać после выбора метода.
  static const clickProceedJs = r'''
(function(){
  try {
    function realClick(el){
      try {
        var rc=el.getBoundingClientRect();
        var o={bubbles:true,cancelable:true,view:window,
          clientX:rc.left+rc.width/2,clientY:rc.top+rc.height/2};
        el.dispatchEvent(new MouseEvent('pointerdown',o));
        el.dispatchEvent(new MouseEvent('mousedown',o));
        el.dispatchEvent(new MouseEvent('mouseup',o));
        el.dispatchEvent(new MouseEvent('click',o));
        el.click();
      } catch(e){ try{el.click();}catch(e2){} }
    }
    var href=(location.href||'').toLowerCase();
    if(href.indexOf('tecspayment')>=0) return 'gateway';
    var priority=['paybynet','pay by net','pay bynet'];
    var els=document.querySelectorAll('button,a,[role="button"],input[type="submit"],input[type="button"]');
    for(var p=0;p<priority.length;p++){
      for(var i=0;i<els.length;i++){
        var el=els[i]; if(!el.offsetParent||el.disabled) continue;
        var t=(el.innerText||el.value||'').trim().toLowerCase();
        if(t.indexOf(priority[p])>=0){ realClick(el); return 'btn-pbn'; }
      }
    }
    var payWords=['pay','zapłać','zaplac','opłać','oplac','оплатить','pay now',
      'dalej','next','continue','kontynuuj','proceed','przejdź','przejdz'];
    for(var i=0;i<els.length;i++){
      var el=els[i]; if(!el.offsetParent||el.disabled) continue;
      var t=(el.innerText||el.value||'').trim().toLowerCase();
      if(!t||t.length>28) continue;
      if(/cancel|anuluj|wstecz|back|отмен/.test(t)) continue;
      for(var w=0;w<payWords.length;w++){
        if(t===payWords[w]||t.indexOf(payWords[w])===0){ realClick(el); return 'btn-pay'; }
      }
    }
    return 'none';
  } catch(e){ return 'err'; }
})();
''';

  static Future<String> selectPayByNet(InAppWebViewController ctrl) async {
    final r = await ctrl.evaluateJavascript(source: selectPayByNetJs);
    return (r ?? 'none').toString().trim();
  }

  static Future<String> selectCardOnGateway(InAppWebViewController ctrl) async {
    final r = await ctrl.evaluateJavascript(source: selectCardOnGatewayJs);
    return (r ?? 'none').toString().trim();
  }

  static Future<String> clickProceed(InAppWebViewController ctrl) async {
    final r = await ctrl.evaluateJavascript(source: clickProceedJs);
    return (r ?? 'none').toString().trim();
  }
}

class PaymentPageProbe {
  final String page;
  final String href;
  final List<PaymentMethodHint> methods;
  final bool hasPayByNet;
  final bool hasCards;
  final String bodyHead;

  const PaymentPageProbe({
    this.page = '',
    this.href = '',
    this.methods = const [],
    this.hasPayByNet = false,
    this.hasCards = false,
    this.bodyHead = '',
  });

  factory PaymentPageProbe.parse(Object? raw) {
    if (raw == null) return const PaymentPageProbe();
    try {
      final m = jsonDecode(raw.toString()) as Map<String, dynamic>;
      final list = m['methods'];
      final methods = <PaymentMethodHint>[];
      if (list is List) {
        for (final e in list) {
          if (e is! Map) continue;
          methods.add(PaymentMethodHint(
            name: (e['name'] ?? '').toString(),
            kind: (e['kind'] ?? '').toString(),
            selected: e['selected'] == true,
          ));
        }
      }
      return PaymentPageProbe(
        page: (m['page'] ?? '').toString(),
        href: (m['href'] ?? '').toString(),
        methods: methods,
        hasPayByNet: m['hasPayByNet'] == true,
        hasCards: m['hasCards'] == true,
        bodyHead: (m['bodyHead'] ?? '').toString(),
      );
    } catch (_) {
      return const PaymentPageProbe();
    }
  }

  String checkpoint() {
    if (methods.isEmpty) return 'probe-$page-none';
    final names = methods
        .map((m) => '${m.selected ? "*" : ""}${m.name.substring(0, m.name.length.clamp(0, 12))}')
        .take(3)
        .join('|');
    return 'probe-$page-$names';
  }
}

class PaymentMethodHint {
  final String name;
  final String kind;
  final bool selected;

  const PaymentMethodHint({
    required this.name,
    required this.kind,
    required this.selected,
  });
}

import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_debug_web.dart';
import 'etoll_details_store.dart';
import 'etoll_page_ready.dart';
import 'etoll_payment_methods.dart';
import 'etoll_refresh_status.dart';
import 'etoll_saved_card.dart';
import 'etoll_tecspayment_parser.dart';
import 'etoll_urls.dart';

/// top-up 20 PLN → выбор PayByNet → PayByNet → tecspayment → все карты.
/// На каждом шаге — контрольная точка (chk-*), без клика по методу оплаты карт нет.
abstract final class EtollTopUpInSession {
  static const unlockAmountPln = '20';
  static const _load = EtollPageReady.pageLoadMax;
  static const _stepsMax = 8;

  static Future<List<EtollSavedCard>> unlockCardList({
    required InAppWebViewController ctrl,
    required String subjectId,
    required String prepaidId,
    String firmId = '',
  }) async {
    if (subjectId.isEmpty || prepaidId.isEmpty) return [];
    if (EtollRefreshStatus.cancelRequested) return [];

    final diag = <String>[];
    void chk(String name, String detail) {
      final line = '$name:$detail';
      diag.add(line);
      EtollDebugWeb.setStage('chk-$name-$detail');
    }

    final topUpUrl = EtollUrls.prepaidTopUp(subjectId, prepaidId);

    // ── 1) top-up URL ──
    EtollRefreshStatus.setStage('top-up');
    await EtollPageReady.loadAndWait(ctrl, WebUri(topUpUrl), maxWait: _load);
    if (!await _onTopUp(ctrl, topUpUrl)) {
      chk('topup', 'wrong-url');
      await _saveDiag(firmId, diag);
      return [];
    }
    chk('topup', 'ok');

    // ── 2) сумма 20 ──
    if (!await _fillAmount(ctrl, unlockAmountPln)) {
      chk('amount', 'fail');
      await _saveDiag(firmId, diag);
      return [];
    }
    chk('amount', '20');

    // ── 3) Dalej ──
    final beforeNext = (await ctrl.getUrl())?.toString() ?? '';
    await _clickNext(ctrl);
    await EtollPageReady.waitAfterAction(
      ctrl,
      urlBefore: beforeNext,
      maxWait: _load,
    );
    chk('next', 'clicked');

    // ── 4+) payment / PayByNet / tecspayment ──
    for (int step = 0; step < _stepsMax; step++) {
      if (EtollRefreshStatus.cancelRequested) break;
      if (!await EtollPageReady.ensureReady(ctrl, maxWait: _load)) break;

      final cur = (await ctrl.getUrl())?.toString() ?? '';
      final lu = cur.toLowerCase();
      final probe = await EtollPaymentMethods.probe(ctrl);
      chk('s$step', probe.checkpoint());
      EtollDebugWeb.track('Refresh unlock', cur, stage: probe.page);

      // tecspayment — Select Card
      if (EtollTecsPaymentParser.isGatewayUrl(lu) ||
          probe.page == 'tecspayment' ||
          EtollTecsPaymentParser.looksLikeSelectCard(lu, probe.bodyHead)) {
        EtollRefreshStatus.setStage('tecspayment');
        final pick = await EtollPaymentMethods.selectCardOnGateway(ctrl);
        chk('gw-card', pick);
        if (pick != 'none' && pick != 'err') {
          await EtollPageReady.waitAfterAction(
            ctrl,
            urlBefore: cur,
            maxWait: _load,
          );
        }
        final cards = await _readGatewayCards(ctrl);
        chk('cards', '${cards.length}');
        if (cards.isNotEmpty) {
          EtollRefreshStatus.setStage('session-cards-ok');
        }
        await _saveDiag(firmId, diag);
        return cards;
      }

      // Страница выбора метода или summary — сначала PayByNet, потом Pay
      if (probe.page == 'payment' ||
          lu.contains('/payment') ||
          lu.contains('/summary') ||
          probe.hasPayByNet ||
          probe.methods.isNotEmpty) {
        EtollRefreshStatus.setStage('payment');
        final sel = await EtollPaymentMethods.selectPayByNet(ctrl);
        chk('select-pbn', sel);
        if (sel != 'none' && sel != 'err') {
          await Future<void>.delayed(const Duration(milliseconds: 400));
        }
        final proceed = await EtollPaymentMethods.clickProceed(ctrl);
        chk('proceed', proceed);
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _load,
        );
        continue;
      }

      // PayByNet промежуточная
      if (lu.contains('paybynet') || lu.contains('pay-by-net') || probe.page == 'paybynet') {
        EtollRefreshStatus.setStage('paybynet');
        final sel = await EtollPaymentMethods.selectPayByNet(ctrl);
        chk('pbn-page', sel);
        final proceed = await EtollPaymentMethods.clickProceed(ctrl);
        chk('pbn-go', proceed);
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _load,
        );
        continue;
      }

      // Ещё на top-up — ещё раз Dalej
      if (lu.contains('/top-up')) {
        await _clickNext(ctrl);
        chk('topup-next', 'retry');
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _load,
        );
        continue;
      }

      // Неизвестная страница — пробуем выбрать PayByNet на всякий случай
      if (probe.hasPayByNet || probe.methods.isNotEmpty) {
        final sel = await EtollPaymentMethods.selectPayByNet(ctrl);
        chk('fallback-pbn', sel);
        await EtollPaymentMethods.clickProceed(ctrl);
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _load,
        );
        continue;
      }

      chk('lost', lu.length > 40 ? lu.substring(lu.length - 40) : lu);
      break;
    }

    await _saveDiag(firmId, diag);
    return [];
  }

  static Future<void> _saveDiag(String firmId, List<String> lines) async {
    if (firmId.isEmpty) return;
    await EtollDetailsStore.saveDiag(
      firmId,
      '[topup-chain] ${lines.join(' → ')}',
    );
  }

  static Future<bool> _onTopUp(InAppWebViewController ctrl, String topUpUrl) async {
    var lu = ((await ctrl.getUrl())?.toString() ?? '').toLowerCase();
    if (lu.contains('/top-up')) return true;
    await EtollPageReady.loadAndWait(ctrl, WebUri(topUpUrl), maxWait: _load);
    lu = ((await ctrl.getUrl())?.toString() ?? '').toLowerCase();
    return lu.contains('/top-up');
  }

  static Future<List<EtollSavedCard>> _readGatewayCards(
    InAppWebViewController ctrl,
  ) async {
    await EtollPageReady.waitForJs(
      ctrl,
      EtollTecsPaymentParser.hasCardsJs,
      maxWait: _load,
    );
    for (int i = 0; i < 3; i++) {
      if (EtollRefreshStatus.cancelRequested) break;
      if (!await EtollPageReady.ensureReady(ctrl, maxWait: _load)) break;
      final raw =
          await ctrl.evaluateJavascript(source: EtollTecsPaymentParser.parseJs);
      final cards = EtollTecsPaymentParser.parseResult(raw);
      if (cards.isNotEmpty) return cards;
      await Future<void>.delayed(const Duration(milliseconds: 350));
    }
    return [];
  }

  static Future<bool> _fillAmount(InAppWebViewController ctrl, String amt) async {
    final safe = amt.replaceAll("'", '');
    final res = await ctrl.evaluateJavascript(source: '''
(function(){try{
  var want='$safe';
  function vis(el){return el&&el.offsetParent!==null&&!el.disabled&&!el.readOnly;}
  var ins=document.querySelectorAll('input');
  var byMeta=null, byNum=null, anyTxt=null;
  for(var i=0;i<ins.length;i++){var el=ins[i];if(!vis(el))continue;
    var ty=(el.type||'text').toLowerCase();
    if(ty==='password'||ty==='checkbox'||ty==='radio'||ty==='hidden'||ty==='submit'||ty==='button')continue;
    var meta=((el.name||'')+' '+(el.id||'')+' '+(el.placeholder||'')+' '+(el.getAttribute('aria-label')||'')).toLowerCase();
    if(!byMeta&&(meta.indexOf('kwot')>=0||meta.indexOf('amount')>=0||meta.indexOf('sum')>=0||meta.indexOf('warto')>=0))byMeta=el;
    if(!byNum&&ty==='number')byNum=el;
    anyTxt=el;
  }
  var target=byMeta||byNum||anyTxt;
  if(!target||!want) return '0';
  var setter=Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype,'value').set;
  setter.call(target, want);
  target.dispatchEvent(new Event('input',{bubbles:true}));
  target.dispatchEvent(new Event('change',{bubbles:true}));
  target.dispatchEvent(new Event('blur',{bubbles:true}));
  return '1';
}catch(e){return '0';}})();
''');
    return (res ?? '').toString().trim() == '1';
  }

  static Future<void> _clickNext(InAppWebViewController ctrl) async {
    await ctrl.evaluateJavascript(source: r'''
(function(){try{
  function realClick(el){try{var rc=el.getBoundingClientRect();
    var o={bubbles:true,cancelable:true,view:window,
      clientX:rc.left+rc.width/2,clientY:rc.top+rc.height/2};
    el.dispatchEvent(new MouseEvent('pointerdown',o));
    el.dispatchEvent(new MouseEvent('mousedown',o));
    el.dispatchEvent(new MouseEvent('mouseup',o));
    el.dispatchEvent(new MouseEvent('click',o));el.click();
  }catch(e){try{el.click();}catch(e2){}}}}
  var words=['next','dalej','continue','kontynuuj','proceed','przejdź','przejdz','далее','продолжить','дальше'];
  var btns=document.querySelectorAll('button,a,[role="button"],input[type="submit"],input[type="button"]');
  for(var i=0;i<btns.length;i++){var el=btns[i];
    if(el.offsetParent===null||el.disabled)continue;
    var t=(el.innerText||el.value||'').trim().toLowerCase();
    if(!t||t.length>28)continue;
    for(var w=0;w<words.length;w++){
      if(t===words[w]||t.indexOf(words[w])===0){realClick(el);return;}}}
}catch(e){}})();
''');
  }
}

