import 'dart:convert';

import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_saved_card.dart';

/// Карты могут появиться ПОСЛЕ клика по методу оплаты — на той же странице,
/// в radio-списке, mat-list, iframe, раскрытой панели. Ищем везде.
abstract final class EtollTecsPaymentParser {
  static bool isGatewayUrl(String url) {
    final lu = url.toLowerCase();
    return lu.contains('tecspayment') ||
        lu.contains('tecs-pay') ||
        (lu.contains('tecs') && lu.contains('payment'));
  }

  static bool looksLikeSelectCard(String url, String bodySample) {
    if (isGatewayUrl(url)) return true;
    final t = bodySample.toLowerCase();
    return t.contains('select card') ||
        t.contains('wybierz kart') ||
        t.contains('choose card') ||
        t.contains('select a card') ||
        t.contains('saved card') ||
        t.contains('zapisana karta');
  }

  static const hasCardsJs = r'''
(function(){
  try {
    function hasInText(t){
      if(!t) return false;
      var low=t.toLowerCase();
      if(low.indexOf('select card')>=0||low.indexOf('wybierz kart')>=0) return true;
      if(/(visa|mastercard|maestro|amex)[^\d]{0,30}\d{4}/i.test(t)) return true;
      if(/(\*{2,}|•+|\.{3,}|…)\s*\d{4}\b/.test(t)) return true;
      return false;
    }
    if(hasInText(document.body&&document.body.innerText)) return '1';
    var frames=document.querySelectorAll('iframe');
    for(var i=0;i<frames.length;i++){
      try{
        var d=frames[i].contentDocument;
        if(d&&d.body&&hasInText(d.body.innerText)) return '1';
      }catch(e){}
    }
    return '0';
  } catch(e){ return '0'; }
})();
''';

  static const parseJs = r'''
(function(){
  try {
    var out = [];
    var seen = {};
    function add(type, last4, isDefault){
      if (!last4 || last4.length !== 4 || seen[last4]) return;
      if (!/^\d{4}$/.test(last4)) return;
      seen[last4] = true;
      out.push({card4: last4, cardType: (type||'').toLowerCase(), isDefault: !!isDefault});
    }
    function scanText(text, isDefault){
      if(!text) return;
      var re1=/(visa|mastercard|maestro|amex|discover)[^\d]{0,40}(\d{4})\b/gi;
      var m; while((m=re1.exec(text))!==null) add(m[1],m[2],isDefault);
      var re2=/(?:\*{2,}|•+|\.{3,}|…)\s*(\d{4})\b/g;
      while((m=re2.exec(text))!==null) add('',m[1],isDefault);
    }
    function scanRoot(root, isDefault){
      if(!root) return;
      scanText(root.innerText||'', isDefault);
      var rows=root.querySelectorAll(
        'mat-list-item,mat-option,li,label,tr,[role="listitem"],[role="option"],'+
        '[class*="card"],[class*="Card"],mat-radio-button,.mat-list-item');
      for(var i=0;i<rows.length;i++){
        var rt=(rows[i].innerText||'').trim();
        if(!rt||rt.length>200) continue;
        if(!/(visa|mastercard|maestro|\d{4}|karta|card|\*{2,}|•+)/i.test(rt)) continue;
        var rm=rt.match(/(visa|mastercard|maestro)[^\d]{0,30}(\d{4})/i);
        if(rm){ add(rm[1],rm[2],isDefault); continue; }
        var rm2=rt.match(/(\*{2,}|•+|\.{3,})\s*(\d{4})/);
        if(rm2) add('',rm2[2],isDefault);
      }
      var inputs=root.querySelectorAll('input[type="radio"],input[type="checkbox"],mat-radio-button,[role="radio"]');
      for(var j=0;j<inputs.length;j++){
        var inp=inputs[j];
        var row=inp.closest('label,li,div,tr,mat-list-item,mat-radio-button')||inp.parentElement;
        if(!row) continue;
        var checked=inp.checked||inp.getAttribute('aria-checked')==='true'||
          (inp.classList&&inp.classList.contains('mat-radio-checked'));
        scanText(row.innerText||'', checked);
      }
    }
    scanRoot(document.body, false);
    var expanded=document.querySelectorAll('.mat-expanded,[aria-expanded="true"],.expanded,.show,.active');
    for(var e=0;e<expanded.length;e++) scanRoot(expanded[e], true);
    var frames=document.querySelectorAll('iframe');
    for(var f=0;f<frames.length;f++){
      try{ scanRoot(frames[f].contentDocument&&frames[f].contentDocument.body, false); }catch(ex){}
    }
    return JSON.stringify(out);
  } catch(e){ return '[]'; }
})();
''';

  static List<EtollSavedCard> parseResult(Object? raw) {
    if (raw == null) return [];
    var s = raw.toString().trim();
    if (s.isEmpty || s == 'null') return [];
    try {
      final decoded = jsonDecode(s);
      if (decoded is! List) return [];
      final cards = decoded
          .map((e) => EtollSavedCard.fromJson(
              Map<String, dynamic>.from(e as Map)))
          .where((c) => c.valid)
          .toList();
      if (cards.isEmpty) return cards;
      if (!cards.any((c) => c.isDefault)) {
        return [
          EtollSavedCard(
            card4: cards.first.card4,
            cardType: cards.first.cardType,
            isDefault: true,
          ),
          ...cards.skip(1),
        ];
      }
      return cards;
    } catch (_) {
      return [];
    }
  }

  static Future<List<EtollSavedCard>> readAnywhere(
    InAppWebViewController ctrl, {
    Duration maxWait = const Duration(seconds: 8),
  }) async {
    await ctrl.evaluateJavascript(source: hasCardsJs);
    for (int i = 0; i < 5; i++) {
      final raw = await ctrl.evaluateJavascript(source: parseJs);
      final cards = parseResult(raw);
      if (cards.isNotEmpty) return cards;
      await Future<void>.delayed(const Duration(milliseconds: 400));
    }
    return [];
  }
}

