  static Future<String> clickProceed(InAppWebViewController ctrl) async {
    final r = await ctrl.evaluateJavascript(source: clickProceedJs);
    return (r ?? 'none').toString().trim();
  }

  /// Karta płatnicza / Payment card — второй частый метод после PayByNet.
  static const selectCardPaymentMethodJs = r'''
(function(){
  try {
    function realClick(el){
      try {
        var rc=el.getBoundingClientRect();
        var o={bubbles:true,cancelable:true,view:window,
          clientX:rc.left+rc.width/2,clientY:rc.top+rc.height/2};
        el.dispatchEvent(new MouseEvent('pointerdown',o));
        el.dispatchEvent(new MouseEvent('mousedown',o));
        el.dispatchEvent(new MouseEvent('mouseup',o));
        el.dispatchEvent(new MouseEvent('click',o));
        el.click();
      } catch(e){ try{el.click();}catch(e2){} }
    }
    function textOf(el){
      return ((el.innerText||el.textContent||el.value||el.getAttribute('aria-label')||'')+'')
        .trim().toLowerCase();
    }
    function vis(el){ return el && el.offsetParent!==null && !el.disabled; }
    var needles=['karta płatnicza','karta platnicza','karta bankowa','payment card',
      'credit card','debit card','card payment','karta','payment by card','visa','mastercard'];
    function matchesCardMethod(t){
      if(!t||t.length>100) return false;
      if(t.indexOf('paybynet')>=0||t.indexOf('pay by net')>=0) return false;
      if(t.indexOf('blik')>=0) return false;
      for(var i=0;i<needles.length;i++){
        if(t.indexOf(needles[i])>=0) return true;
      }
      return false;
    }
    var radios=document.querySelectorAll('mat-radio-button,input[type="radio"],[role="radio"]');
    for(var i=0;i<radios.length;i++){
      var r=radios[i];
      var row=r.closest('mat-radio-button,label,mat-list-item,li,div,tr')||r;
      if(!matchesCardMethod(textOf(row))&&!matchesCardMethod(textOf(r))) continue;
      var inp=r.querySelector&&r.querySelector('input[type="radio"]')||
        (r.tagName==='INPUT'&&r.type==='radio'?r:null);
      if(inp){ inp.checked=true;
        inp.dispatchEvent(new Event('change',{bubbles:true}));
      }
      realClick(r);
      if(row&&row!==r) realClick(row);
      return 'radio-card';
    }
    var els=document.querySelectorAll('label,mat-list-item,li,a,button,[role="button"],[role="listitem"],div');
    for(var j=0;j<els.length;j++){
      var el=els[j];
      if(!vis(el)) continue;
      if(!matchesCardMethod(textOf(el))) continue;
      realClick(el);
      return 'tile-card';
    }
    return 'none';
  } catch(e){ return 'err'; }
})();
''';

  /// Клик по N-му методу из probe (0=первый radio/tile на странице).
  static String clickMethodByIndexJs(int index) => '''
(function(){
  try {
    function realClick(el){
      try{ el.click(); }catch(e){}
    }
    function vis(el){ return el && el.offsetParent!==null && !el.disabled; }
    function txt(el){
      return ((el.innerText||el.textContent||'')+'').trim().substring(0,80);
    }
    var cands=[];
    var seen=new Set();
    function add(el, kind){
      if(!el||!vis(el)) return;
      var t=txt(el).toLowerCase();
      if(!t||t.length<2) return;
      var key=kind+'|'+t.substring(0,30);
      if(seen.has(key)) return;
      seen.add(key);
      cands.push({el:el, name:t, kind:kind});
    }
    var radios=document.querySelectorAll('mat-radio-button,input[type="radio"],[role="radio"]');
    for(var i=0;i<radios.length;i++){
      var r=radios[i];
      add(r.closest('mat-radio-button,label,mat-list-item,li')||r,'radio');
    }
    var tiles=document.querySelectorAll('mat-list-item,li,[class*="payment"],[class*="method"],label');
    for(var j=0;j<tiles.length;j++){
      var t2=txt(tiles[j]).toLowerCase();
      if(/pay|płat|plat|karta|card|blik|net/.test(t2)) add(tiles[j],'tile');
    }
    var idx=$index;
    if(idx<0||idx>=cands.length) return JSON.stringify({ok:'0',total:cands.length});
    var c=cands[idx];
    var inp=c.el.querySelector&&c.el.querySelector('input[type="radio"]');
    if(inp){ inp.checked=true; inp.dispatchEvent(new Event('change',{bubbles:true})); }
    realClick(c.el);
    return JSON.stringify({ok:'1',kind:c.kind,name:c.name,total:cands.length});
  } catch(e){ return JSON.stringify({ok:'0',err:String(e)}); }
})();
''';

  static Future<String> selectCardPaymentMethod(InAppWebViewController ctrl) async {
    final r = await ctrl.evaluateJavascript(source: selectCardPaymentMethodJs);
    return (r ?? 'none').toString().trim();
  }

  static Future<String> clickMethodByIndex(
    InAppWebViewController ctrl,
    int index,
  ) async {
    final r = await ctrl.evaluateJavascript(source: clickMethodByIndexJs(index));
    try {
      final m = jsonDecode((r ?? '{}').toString()) as Map<String, dynamic>;
      if (m['ok']?.toString() == '1') {
        return '${m['kind']}:${(m['name'] ?? '').toString().substring(0, (m['name'] ?? '').toString().length.clamp(0, 20))}';
      }
      return 'none-${m['total'] ?? 0}';
    } catch (_) {
      return (r ?? 'none').toString();
    }
  }
}

