import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_debug_web.dart';
import 'etoll_details_store.dart';
import 'etoll_page_ready.dart';
import 'etoll_payment_methods.dart';
import 'etoll_refresh_status.dart';
import 'etoll_saved_card.dart';
import 'etoll_tecspayment_parser.dart';
import 'etoll_urls.dart';

/// top-up → клик по методу оплаты → карты появляются (на той же странице или tecspayment).
/// Сначала клик, потом читаем карты, только потом «Pay/Dalej» если карт ещё нет.
abstract final class EtollTopUpInSession {
  static const unlockAmountPln = '20';
  static const _load = EtollPageReady.pageLoadMax;
  static const _stepsMax = 10;

  static Future<List<EtollSavedCard>> unlockCardList({
    required InAppWebViewController ctrl,
    required String subjectId,
    required String prepaidId,
    String firmId = '',
  }) async {
    if (subjectId.isEmpty || prepaidId.isEmpty) return [];
    if (EtollRefreshStatus.cancelRequested) return [];

    final diag = <String>[];
    void chk(String name, String detail) {
      diag.add('$name:$detail');
      EtollDebugWeb.setStage('chk-$name-$detail');
    }

    final topUpUrl = EtollUrls.prepaidTopUp(subjectId, prepaidId);

    EtollRefreshStatus.setStage('top-up');
    await EtollPageReady.loadAndWait(ctrl, WebUri(topUpUrl), maxWait: _load);
    if (!await _onTopUp(ctrl, topUpUrl)) {
      chk('topup', 'wrong-url');
      await _saveDiag(firmId, diag);
      return [];
    }
    chk('topup', 'ok');

    if (!await _fillAmount(ctrl, unlockAmountPln)) {
      chk('amount', 'fail');
      await _saveDiag(firmId, diag);
      return [];
    }
    chk('amount', '20');

    final beforeNext = (await ctrl.getUrl())?.toString() ?? '';
    await _clickNext(ctrl);
    await EtollPageReady.waitAfterAction(
      ctrl,
      urlBefore: beforeNext,
      maxWait: _load,
    );
    chk('next', 'clicked');

    for (int step = 0; step < _stepsMax; step++) {
      if (EtollRefreshStatus.cancelRequested) break;
      if (!await EtollPageReady.ensureReady(ctrl, maxWait: _load)) break;

      final cur = (await ctrl.getUrl())?.toString() ?? '';
      final lu = cur.toLowerCase();
      final probe = await EtollPaymentMethods.probe(ctrl);
      chk('s$step', probe.checkpoint());
      EtollDebugWeb.track('Refresh unlock', cur, stage: probe.page);

      // Уже видны карты (без клика)?
      var cards = await _readCardsAfterClick(ctrl, chk, 'pre');
      if (cards.isNotEmpty) {
        await _saveDiag(firmId, diag);
        return cards;
      }

      // ── Клик по методам оплаты → ждём карты НА ЭТОЙ странице ──
      if (probe.page == 'payment' ||
          probe.page == 'paybynet' ||
          probe.hasPayByNet ||
          probe.methods.isNotEmpty ||
          lu.contains('/payment') ||
          lu.contains('/summary')) {
        EtollRefreshStatus.setStage('payment');

        final pbn = await EtollPaymentMethods.selectPayByNet(ctrl);
        chk('click-pbn', pbn);
        cards = await _readCardsAfterClick(ctrl, chk, 'after-pbn');
        if (cards.isNotEmpty) {
          await _saveDiag(firmId, diag);
          return cards;
        }

        final cardM = await EtollPaymentMethods.selectCardPaymentMethod(ctrl);
        chk('click-cardm', cardM);
        cards = await _readCardsAfterClick(ctrl, chk, 'after-cardm');
        if (cards.isNotEmpty) {
          await _saveDiag(firmId, diag);
          return cards;
        }

        for (int mi = 0; mi < probe.methods.length && mi < 6; mi++) {
          final ck = await EtollPaymentMethods.clickMethodByIndex(ctrl, mi);
          chk('click-m$mi', ck);
          cards = await _readCardsAfterClick(ctrl, chk, 'after-m$mi');
          if (cards.isNotEmpty) {
            await _saveDiag(firmId, diag);
            return cards;
          }
        }

        // Карт на странице нет — только тогда «Pay / Dalej»
        final proceed = await EtollPaymentMethods.clickProceed(ctrl);
        chk('proceed', proceed);
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _load,
        );
        continue;
      }

      // tecspayment / Select Card
      if (EtollTecsPaymentParser.isGatewayUrl(lu) ||
          probe.page == 'tecspayment' ||
          EtollTecsPaymentParser.looksLikeSelectCard(lu, probe.bodyHead)) {
        EtollRefreshStatus.setStage('tecspayment');
        await EtollPaymentMethods.selectCardOnGateway(ctrl);
        cards = await _readCardsAfterClick(ctrl, chk, 'gateway');
        await _saveDiag(firmId, diag);
        return cards;
      }

      if (lu.contains('paybynet') || lu.contains('pay-by-net')) {
        EtollRefreshStatus.setStage('paybynet');
        await EtollPaymentMethods.selectPayByNet(ctrl);
        cards = await _readCardsAfterClick(ctrl, chk, 'pbn-page');
        if (cards.isNotEmpty) {
          await _saveDiag(firmId, diag);
          return cards;
        }
        await EtollPaymentMethods.clickProceed(ctrl);
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _load,
        );
        continue;
      }

      if (lu.contains('/top-up')) {
        await _clickNext(ctrl);
        chk('topup-retry', 'next');
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _load,
        );
        continue;
      }

      // Любая страница с методами — перебираем клики
      if (probe.methods.isNotEmpty) {
        for (int mi = 0; mi < probe.methods.length && mi < 4; mi++) {
          await EtollPaymentMethods.clickMethodByIndex(ctrl, mi);
          cards = await _readCardsAfterClick(ctrl, chk, 'any-m$mi');
          if (cards.isNotEmpty) {
            await _saveDiag(firmId, diag);
            return cards;
          }
        }
      }

