import 'dart:async';

import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_refresh_status.dart';

/// Ждём реальную прогрузку страницы (complete + нет spinner).
/// Лимит не фиксированный 8 сек — зависит от сети:
/// • нормальная связь — до 45 сек на шаг;
/// • слабая / eTOLL тормозит — до 90 сек, пользователю «слабая связь»;
/// • нет сети — быстро выходим, «нет соединения».
abstract final class EtollPageReady {
  static const Duration normalPageMax = Duration(seconds: 45);
  static const Duration slowNetPageMax = Duration(seconds: 90);
  static const Duration noNetPageMax = Duration(seconds: 18);

  /// Алиасы — вызывающий код может не передавать maxWait → берётся [pageBudget].
  static Duration get refreshStepWait => pageBudget();
  static Duration get roamingMaxWait => pageBudget();
  static Duration get pageLoadMax => pageBudget();

  static const Duration _poll = Duration(milliseconds: 350);
  static const Duration _hintEvery = Duration(seconds: 3);

  static const _readyJs = r'''
(function(){
  try {
    if (document.readyState !== 'complete') return '0';
    var busy = document.querySelector(
      'mat-progress-bar,[role="progressbar"],.loading,.spinner,.mat-progress-spinner');
    if (busy && busy.offsetParent !== null) return '0';
    return '1';
  } catch(e) { return '0'; }
})();
''';

  static const hasPlnBalanceJs = r'''
(function(){
  try {
    var body = document.body ? document.body.innerText : '';
    return /[0-9][0-9\s.,]*\s*PLN/i.test(body) ? '1' : '0';
  } catch(e) { return '0'; }
})();
''';

  /// Сколько ждать прогрузку с учётом мониторинга сети (EtollRefreshStatus).
  static Duration pageBudget() {
    if (!EtollRefreshStatus.active.value) return normalPageMax;
    if (EtollRefreshStatus.netTransport.value == 'none') {
      return noNetPageMax;
    }
    if (EtollRefreshStatus.netEtoll.value == 'slow' ||
        EtollRefreshStatus.state.value.loadHint == LoadHint.slow) {
      return slowNetPageMax;
    }
    return normalPageMax;
  }

  static Future<bool> isReady(InAppWebViewController ctrl) async {
    final ready = await ctrl.evaluateJavascript(source: _readyJs);
    return (ready ?? '0').toString().trim() == '1';
  }

  static Future<bool> waitForReady(
    InAppWebViewController ctrl, {
    Duration? maxWait,
  }) async {
    if (await isReady(ctrl)) return true;
    final cap = maxWait ?? pageBudget();
    final deadline = DateTime.now().add(cap);
    var lastHint = DateTime.now();
    final started = DateTime.now();
    while (DateTime.now().isBefore(deadline)) {
      if (EtollRefreshStatus.cancelRequested) return false;
      if (await isReady(ctrl)) {
        EtollRefreshStatus.notePageReady();
        return true;
      }
      if (DateTime.now().difference(lastHint) >= _hintEvery) {
        lastHint = DateTime.now();
        final waited = DateTime.now().difference(started);
        EtollRefreshStatus.notePageWaiting(waited.inSeconds);
        if (EtollRefreshStatus.active.value) {
          unawaited(EtollRefreshStatus.refreshNetProbe());
        }
      }
      await Future.delayed(_poll);
    }
    final waited = DateTime.now().difference(started).inSeconds;
    EtollRefreshStatus.notePageWaiting(waited, timedOut: true);
    return isReady(ctrl);
  }

  static Future<bool> ensureReady(
    InAppWebViewController ctrl, {
    Duration? maxWait,
  }) =>
      waitForReady(ctrl, maxWait: maxWait);

  static Future<bool> loadAndWait(
    InAppWebViewController ctrl,
    WebUri url, {
    Duration? maxWait,
  }) async {
    if (EtollRefreshStatus.active.value) {
      unawaited(EtollRefreshStatus.refreshNetProbe());
    }
    try {
      await ctrl.loadUrl(urlRequest: URLRequest(url: url));
    } catch (_) {
      return false;
    }
    return waitForReady(ctrl, maxWait: maxWait);
  }

  static Future<bool> waitAfterAction(
    InAppWebViewController ctrl, {
    String? urlBefore,
    Duration? maxWait,
  }) async {
    final cap = maxWait ?? pageBudget();
    final deadline = DateTime.now().add(cap);
    var lastHint = DateTime.now();
    final started = DateTime.now();
    while (DateTime.now().isBefore(deadline)) {
      if (EtollRefreshStatus.cancelRequested) return false;
      final now = (await ctrl.getUrl())?.toString() ?? '';
      if (urlBefore != null && urlBefore.isNotEmpty) {
        if (now.isNotEmpty && now != urlBefore && await isReady(ctrl)) {
          EtollRefreshStatus.notePageReady();
          return true;
        }
      } else if (await isReady(ctrl)) {
        EtollRefreshStatus.notePageReady();
        return true;
      }
      if (DateTime.now().difference(lastHint) >= _hintEvery) {
        lastHint = DateTime.now();
        EtollRefreshStatus.notePageWaiting(
          DateTime.now().difference(started).inSeconds,
        );
      }
      await Future.delayed(_poll);
    }
    return isReady(ctrl);
  }

  static Future<bool> waitForJs(
    InAppWebViewController ctrl,
    String js, {
    Duration? maxWait,
  }) async {
    final cap = maxWait ?? pageBudget();
    final deadline = DateTime.now().add(cap);
    var lastHint = DateTime.now();
    final started = DateTime.now();
    while (DateTime.now().isBefore(deadline)) {
      if (EtollRefreshStatus.cancelRequested) return false;
      if (await isReady(ctrl)) {
        final r = await ctrl.evaluateJavascript(source: js);
        if ((r ?? '0').toString().trim() == '1') return true;
      } else {
        final left = deadline.difference(DateTime.now());
        if (left.isNegative) break;
        await waitForReady(
          ctrl,
          maxWait: left < pageBudget() ? left : pageBudget(),
        );
      }
      if (DateTime.now().difference(lastHint) >= _hintEvery) {
        lastHint = DateTime.now();
        EtollRefreshStatus.notePageWaiting(
          DateTime.now().difference(started).inSeconds,
        );
      }
      await Future.delayed(_poll);
    }
    return false;
  }

  static Future<bool> waitForUrlContains(
    InAppWebViewController ctrl,
    String part, {
    Duration? maxWait,
  }) async {
    final needle = part.toLowerCase();
    final cap = maxWait ?? pageBudget();
    final deadline = DateTime.now().add(cap);
    while (DateTime.now().isBefore(deadline)) {
      if (EtollRefreshStatus.cancelRequested) return false;
      if (await isReady(ctrl)) {
        final u = ((await ctrl.getUrl())?.toString() ?? '').toLowerCase();
        if (u.contains(needle)) return true;
      }
      await Future.delayed(_poll);
    }
    return false;
  }
}

