static void notePageWaiting(int waitedSec, {bool timedOut = false}) {
  if (!active.value) return;
  LoadHint hint = LoadHint.normal;
  if (netTransport.value == 'none') {
    hint = LoadHint.noNet;
  } else if (netEtoll.value == 'slow') {
