  }
}

static void notePageReady() {
  if (!active.value) return;
  if (state.value.loadHint != LoadHint.normal) {
    state.value = state.value.copyWith(loadHint: LoadHint.normal);
  }
}

static void _applyNetHint() {
  if (!active.value) return;
  LoadHint hint = LoadHint.normal;
  if (netTransport.value == 'none') {
    hint = LoadHint.noNet;
  } else if (netEtoll.value == 'slow') {
    hint = LoadHint.slow;
  }
  if (state.value.loadHint != hint &&
      state.value.loadHint != LoadHint.stuck) {
    state.value = state.value.copyWith(loadHint: hint);
  }
}

static void _onTick() {
  if (!active.value || _stageSince == null) return;
  final sec = DateTime.now().difference(_stageSince!).inSeconds;
  LoadHint hint = state.value.loadHint;
  if (netTransport.value == 'none') {
    hint = LoadHint.noNet;
  } else if (netEtoll.value == 'slow') {
    hint = LoadHint.slow;
  } else if (sec >= 120) {
    hint = LoadHint.stuck;
  } else if (sec >= 40 && hint == LoadHint.normal) {
    hint = LoadHint.waiting;
  }
  state.value = state.value.copyWith(elapsedSec: sec, loadHint: hint);
}

