import 'package:flutter/material.dart';

import 'balance_colors.dart';
import 'etoll_refresh_status.dart';

/// Баннер eTOLL: «Обновляю: {фирма}» + подсказка по сети + СТОП.
class EtollRefreshStatusBar extends StatelessWidget {
  final String Function(String key) tr;
  final bool massActualizing;
  final String massFirm;
  final VoidCallback? onStop;

  const EtollRefreshStatusBar({
    super.key,
    required this.tr,
    this.massActualizing = false,
    this.massFirm = '',
    this.onStop,
  });

  String _hint({
    required String transport,
    required String etoll,
    required LoadHint loadHint,
  }) {
    if (transport == 'none' || loadHint == LoadHint.noNet) {
      return tr('no_connection');
    }
    if (loadHint == LoadHint.stuck) {
      return tr('etoll_refresh_very_slow');
    }
    if (loadHint == LoadHint.slow || etoll == 'slow') {
      return tr('etoll_refresh_slow');
    }
    if (loadHint == LoadHint.waiting) {
      return tr('weak_waiting');
    }
    return '';
  }

  @override
  Widget build(BuildContext context) {
    return ValueListenableBuilder<bool>(
      valueListenable: EtollRefreshStatus.active,
      builder: (_, on, __) {
        final showMass = massActualizing && !on;
        if (!on && !showMass) return const SizedBox.shrink();

        if (showMass && massFirm.isEmpty) {
          return _shell(
            line1: tr('updating_firms'),
            hint: '',
            accent: BalanceColors.etollRed,
            onStop: onStop,
          );
        }

        return ValueListenableBuilder<EtollRefreshStatusState>(
          valueListenable: EtollRefreshStatus.state,
          builder: (_, st, __) {
            return ValueListenableBuilder<String>(
              valueListenable: EtollRefreshStatus.netTransport,
              builder: (_, transport, __) {
                return ValueListenableBuilder<String>(
                  valueListenable: EtollRefreshStatus.netEtoll,
                  builder: (_, etoll, __) {
                    final firm = st.firm.isNotEmpty
                        ? st.firm
                        : (massFirm.isNotEmpty ? massFirm : '');
                    final line1 = firm.isNotEmpty
                        ? tr('updating_firm').replaceAll('{0}', firm)
                        : tr('updating_firms');
                    final hint = _hint(
                      transport: transport,
                      etoll: etoll,
                      loadHint: st.loadHint,
                    );
                    return _shell(
                      line1: line1,
                      hint: hint,
                      accent: BalanceColors.etollRed,
                      onStop: onStop,
                    );
                  },
                );
              },
            );
          },
        );
      },
    );
  }

  Widget _shell({
    required String line1,
    required String hint,
    required Color accent,
    VoidCallback? onStop,
  }) {
    return Container(
      width: double.infinity,
      margin: const EdgeInsets.only(bottom: 10),
      padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
      decoration: BoxDecoration(
        color: accent.withValues(alpha: 0.1),
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: accent.withValues(alpha: 0.35)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: [
              SizedBox(
                width: 18,
                height: 18,
                child: CircularProgressIndicator(strokeWidth: 2, color: accent),
              ),
              const SizedBox(width: 10),
              Expanded(
                child: Text(
                  line1,
                  maxLines: 2,
                  overflow: TextOverflow.ellipsis,
                  style: const TextStyle(
                    color: BalanceColors.textPrimary,
                    fontSize: 13,
                    fontWeight: FontWeight.w800,
                    height: 1.25,
                  ),
                ),
              ),
              if (onStop != null) ...[
                const SizedBox(width: 8),
                Material(
                  color: BalanceColors.etollRed.withValues(alpha: 0.22),
                  borderRadius: BorderRadius.circular(8),
                  child: InkWell(
                    onTap: onStop,
                    borderRadius: BorderRadius.circular(8),
                    child: Padding(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 10,
                        vertical: 5,
                      ),
                      child: Text(
                        tr('stop_refresh'),
                        style: const TextStyle(
                          color: BalanceColors.etollRed,
                          fontSize: 11,
                          fontWeight: FontWeight.w900,
                        ),
                      ),
                    ),
                  ),
                ),
              ],
            ],
          ),
          if (hint.isNotEmpty) ...[
            const SizedBox(height: 6),
            Padding(
              padding: const EdgeInsets.only(left: 28),
              child: Text(
                hint,
                style: TextStyle(
                  color: BalanceColors.amber.withValues(alpha: 0.95),
                  fontSize: 11,
                  fontWeight: FontWeight.w600,
                  height: 1.35,
                ),
              ),
            ),
          ],
        ],
      ),
    );
  }
}

