import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_debug_web.dart';
import 'etoll_details_store.dart';
import 'etoll_page_ready.dart';
import 'etoll_payment_methods.dart';
import 'etoll_refresh_status.dart';
import 'etoll_saved_card.dart';
import 'etoll_tecspayment_parser.dart';
import 'etoll_urls.dart';

/// top-up → клик по методу оплаты → карты (на той же странице или tecspayment).
/// Pay / Dalej — только если карт ещё нет → страница выбора карты (все карты).
abstract final class EtollTopUpInSession {
  static const unlockAmountPln = '20';
  static const _stepsMax = 14;

  static Future<List<EtollSavedCard>> unlockCardList({
    required InAppWebViewController ctrl,
    required String subjectId,
    required String prepaidId,
    String firmId = '',
  }) async {
    if (subjectId.isEmpty || prepaidId.isEmpty) return [];
    if (EtollRefreshStatus.cancelRequested) return [];

    final diag = <String>[];
    void chk(String name, String detail) {
      diag.add('$name:$detail');
      EtollDebugWeb.setStage('chk-$name-$detail');
    }

    final collected = <String, EtollSavedCard>{};

    List<EtollSavedCard> finalize() {
      if (collected.isEmpty) return [];
      final list = collected.values.toList();
      if (!list.any((c) => c.isDefault)) {
        list[0] = EtollSavedCard(
          card4: list[0].card4,
          cardType: list[0].cardType,
          isDefault: true,
        );
      }
      EtollRefreshStatus.markCardsSaved();
      EtollRefreshStatus.setStage('session-cards-ok');
      return list;
    }

    void absorb(List<EtollSavedCard> batch) {
      for (final c in batch) {
        if (!c.valid) continue;
        final prev = collected[c.card4];
        if (prev == null) {
          collected[c.card4] = c;
        } else if (c.isDefault) {
          collected[c.card4] = c;
        }
      }
    }

    bool isGateway(String lu, EtollPaymentProbe probe) =>
        EtollTecsPaymentParser.isGatewayUrl(lu) ||
        probe.page == 'tecspayment' ||
        EtollTecsPaymentParser.looksLikeSelectCard(lu, probe.bodyHead);

    bool isPaymentPage(String lu, EtollPaymentProbe probe) =>
        probe.page == 'payment' ||
        probe.page == 'paybynet' ||
        probe.hasPayByNet ||
        probe.methods.isNotEmpty ||
        lu.contains('/payment') ||
        lu.contains('/summary');

    final topUpUrl = EtollUrls.prepaidTopUp(subjectId, prepaidId);

    EtollRefreshStatus.setStage('top-up');
    await EtollPageReady.loadAndWait(ctrl, WebUri(topUpUrl));
    if (!await _onTopUp(ctrl, topUpUrl)) {
      chk('topup', 'wrong-url');
      await _saveDiag(firmId, diag);
      return [];
    }
    chk('topup', 'ok');

    if (!await _fillAmount(ctrl, unlockAmountPln)) {
      chk('amount', 'fail');
      await _saveDiag(firmId, diag);
      return [];
    }
    chk('amount', '20');

    final beforeNext = (await ctrl.getUrl())?.toString() ?? '';
    await _clickNext(ctrl);
    await EtollPageReady.waitAfterAction(ctrl, urlBefore: beforeNext);
    chk('next', 'clicked');

    for (int step = 0; step < _stepsMax; step++) {
      if (EtollRefreshStatus.cancelRequested) break;
      if (!await EtollPageReady.ensureReady(ctrl)) break;

      final cur = (await ctrl.getUrl())?.toString() ?? '';
      final lu = cur.toLowerCase();
      final probe = await EtollPaymentMethods.probe(ctrl);
      chk('s$step', probe.checkpoint());
      EtollDebugWeb.track('Refresh unlock', cur, stage: probe.page);

      // Уже видны карты (без клика)?
      var cards = await _readCardsAfterClick(ctrl, chk, 'pre');
      absorb(cards);
      if (collected.isNotEmpty && isGateway(lu, probe)) {
        await _saveDiag(firmId, diag);
        return finalize();
      }
      if (collected.isNotEmpty && isPaymentPage(lu, probe)) {
        await _saveDiag(firmId, diag);
        return finalize();
      }

      // ── Страница выбора карты (tecspayment / Select Card) ──
      if (isGateway(lu, probe)) {
        EtollRefreshStatus.setStage('tecspayment');
        await EtollTecsPaymentParser.expandPanels(ctrl);
        await EtollPaymentMethods.selectCardOnGateway(ctrl);
        cards = await _readCardsAfterClick(ctrl, chk, 'gateway');
        absorb(cards);
        if (collected.isNotEmpty) {
          await _saveDiag(firmId, diag);
          return finalize();
        }
        chk('gateway', 'empty-retry');
        continue;
      }

      // ── Методы оплаты: клик → карты на странице; Pay/Dalej только если пусто ──
      if (isPaymentPage(lu, probe)) {
        EtollRefreshStatus.setStage('payment');

        final pbn = await EtollPaymentMethods.selectPayByNet(ctrl);
        chk('click-pbn', pbn);
        cards = await _readCardsAfterClick(ctrl, chk, 'after-pbn');
        absorb(cards);
        if (collected.isNotEmpty) {
          await _saveDiag(firmId, diag);
          return finalize();
        }

        final cardM = await EtollPaymentMethods.selectCardPaymentMethod(ctrl);
        chk('click-cardm', cardM);
        cards = await _readCardsAfterClick(ctrl, chk, 'after-cardm');
        absorb(cards);
        if (collected.isNotEmpty) {
          await _saveDiag(firmId, diag);
          return finalize();
        }

        for (int mi = 0; mi < probe.methods.length && mi < 6; mi++) {
          final ck = await EtollPaymentMethods.clickMethodByIndex(ctrl, mi);
          chk('click-m$mi', ck);
          cards = await _readCardsAfterClick(ctrl, chk, 'after-m$mi');
          absorb(cards);
          if (collected.isNotEmpty) {
            await _saveDiag(firmId, diag);
            return finalize();
          }
        }

        // Карт нет — Pay / Dalej → следующая страница (выбор карты)
        final proceed = await EtollPaymentMethods.clickProceed(ctrl);
        chk('proceed', proceed);
        if (proceed != 'none' && proceed != 'gateway') {
          await EtollPageReady.waitAfterAction(ctrl, urlBefore: cur);
        }
        continue;
      }

      if (lu.contains('paybynet') || lu.contains('pay-by-net')) {
        EtollRefreshStatus.setStage('paybynet');
        await EtollPaymentMethods.selectPayByNet(ctrl);
        cards = await _readCardsAfterClick(ctrl, chk, 'pbn-page');
        absorb(cards);
        if (collected.isNotEmpty) {
          await _saveDiag(firmId, diag);
          return finalize();
        }
        final proceed = await EtollPaymentMethods.clickProceed(ctrl);
        chk('pbn-proceed', proceed);
        await EtollPageReady.waitAfterAction(ctrl, urlBefore: cur);
        continue;
      }

      if (lu.contains('/top-up')) {
        await _clickNext(ctrl);
        chk('topup-retry', 'next');
        await EtollPageReady.waitAfterAction(ctrl, urlBefore: cur);
        continue;
      }

      if (probe.methods.isNotEmpty) {
        for (int mi = 0; mi < probe.methods.length && mi < 4; mi++) {
          await EtollPaymentMethods.clickMethodByIndex(ctrl, mi);
          cards = await _readCardsAfterClick(ctrl, chk, 'any-m$mi');
          absorb(cards);
          if (collected.isNotEmpty) {
            await _saveDiag(firmId, diag);
            return finalize();
          }
        }
      }

      // Неизвестная страница — попробовать Dalej, не сдаваться сразу
      final lostProceed = await EtollPaymentMethods.clickProceed(ctrl);
      chk('lost-proceed', lostProceed);
      if (lostProceed != 'none' && lostProceed != 'gateway') {
        await EtollPageReady.waitAfterAction(ctrl, urlBefore: cur);
        continue;
      }

      chk('lost', lu.length > 36 ? lu.substring(lu.length - 36) : lu);
      break;
    }

    if (collected.isNotEmpty) {
      await _saveDiag(firmId, diag);
      return finalize();
    }
    await _saveDiag(firmId, diag);
    return [];
  }

  static Future<List<EtollSavedCard>> _readCardsAfterClick(
    InAppWebViewController ctrl,
    void Function(String, String) chk,
    String tag,
  ) async {
    await EtollPageReady.waitForJs(ctrl, EtollTecsPaymentParser.hasCardsJs);
    final cards = await EtollTecsPaymentParser.readAnywhere(ctrl);
    chk('cards-$tag', '${cards.length}');
    return cards;
  }

  static Future<void> _saveDiag(String firmId, List<String> lines) async {
    if (firmId.isEmpty) return;
    await EtollDetailsStore.saveDiag(
      firmId,
      '[topup-chain] ${lines.join(' → ')}',
    );
  }

  static Future<bool> _onTopUp(InAppWebViewController ctrl, String topUpUrl) async {
    var lu = ((await ctrl.getUrl())?.toString() ?? '').toLowerCase();
    if (lu.contains('/top-up')) return true;
    await EtollPageReady.loadAndWait(ctrl, WebUri(topUpUrl));
    lu = ((await ctrl.getUrl())?.toString() ?? '').toLowerCase();
    return lu.contains('/top-up');
  }

  static Future<bool> _fillAmount(InAppWebViewController ctrl, String amt) async {
    final safe = amt.replaceAll("'", '');
    final res = await ctrl.evaluateJavascript(source: '''
(function(){try{
  var want='$safe';
  function vis(el){return el&&el.offsetParent!==null&&!el.disabled&&!el.readOnly;}
  var ins=document.querySelectorAll('input');
  var byMeta=null, byNum=null, anyTxt=null;
  for(var i=0;i<ins.length;i++){var el=ins[i];if(!vis(el))continue;
    var ty=(el.type||'text').toLowerCase();
    if(ty==='password'||ty==='checkbox'||ty==='radio'||ty==='hidden'||ty==='submit'||ty==='button')continue;
    var meta=((el.name||'')+' '+(el.id||'')+' '+(el.placeholder||'')+' '+(el.getAttribute('aria-label')||'')).toLowerCase();
    if(!byMeta&&(meta.indexOf('kwot')>=0||meta.indexOf('amount')>=0||meta.indexOf('sum')>=0||meta.indexOf('warto')>=0))byMeta=el;
    if(!byNum&&ty==='number')byNum=el;
    anyTxt=el;
  }
  var target=byMeta||byNum||anyTxt;
  if(!target||!want) return '0';
  var setter=Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype,'value').set;
  setter.call(target, want);
  target.dispatchEvent(new Event('input',{bubbles:true}));
  target.dispatchEvent(new Event('change',{bubbles:true}));
  target.dispatchEvent(new Event('blur',{bubbles:true}));
  return '1';
}catch(e){return '0';}})();
''');
    return (res ?? '').toString().trim() == '1';
  }

  static Future<void> _clickNext(InAppWebViewController ctrl) async {
    await ctrl.evaluateJavascript(source: r'''
(function(){try{
  function realClick(el){try{var rc=el.getBoundingClientRect();
    var o={bubbles:true,cancelable:true,view:window,
      clientX:rc.left+rc.width/2,clientY:rc.top+rc.height/2};
    el.dispatchEvent(new MouseEvent('pointerdown',o));
    el.dispatchEvent(new MouseEvent('mousedown',o));
    el.dispatchEvent(new MouseEvent('mouseup',o));
    el.dispatchEvent(new MouseEvent('click',o));el.click();
  }catch(e){try{el.click();}catch(e2){}}}}
  var words=['next','dalej','continue','kontynuuj','proceed','przejdź','przejdz','далее','продолжить','дальше'];
  var btns=document.querySelectorAll('button,a,[role="button"],input[type="submit"],input[type="button"]');
  for(var i=0;i<btns.length;i++){var el=btns[i];
    if(el.offsetParent===null||el.disabled)continue;
    var t=(el.innerText||el.value||'').trim().toLowerCase();
    if(!t||t.length>28)continue;
    for(var w=0;w<words.length;w++){
      if(t===words[w]||t.indexOf(words[w])===0){realClick(el);return;}}}
}catch(e){}})();
''');
  }
}

