import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_debug_web.dart';
import 'etoll_details_store.dart';
import 'etoll_page_ready.dart';
import 'etoll_payment_methods.dart';
import 'etoll_refresh_status.dart';
import 'etoll_saved_card.dart';
import 'etoll_tecspayment_parser.dart';
import 'etoll_urls.dart';

/// top-up → PayByNet → если карт нет или одна → Dalej → gateway (ВСЕ карты).
abstract final class EtollTopUpInSession {
  static const unlockAmountPln = '20';
  static const _stepsMax = 12;
  static const _probeWait = Duration(seconds: 10);
  static const _probeRead = Duration(seconds: 12);

  static Future<List<EtollSavedCard>> unlockCardList({
    required InAppWebViewController ctrl,
    required String subjectId,
    required String prepaidId,
    String firmId = '',
  }) async {
    if (subjectId.isEmpty || prepaidId.isEmpty) return [];
    if (EtollRefreshStatus.cancelRequested) return [];

    final diag = <String>[];
    void chk(String name, String detail) {
      diag.add('$name:$detail');
      EtollDebugWeb.setStage('chk-$name-$detail');
    }

    final collected = <String, EtollSavedCard>{};

    List<EtollSavedCard> finalize() {
      if (collected.isEmpty) return [];
      final list = collected.values.toList();
      if (!list.any((c) => c.isDefault)) {
        list[0] = EtollSavedCard(
          card4: list[0].card4,
          cardType: list[0].cardType,
          isDefault: true,
        );
      }
      EtollRefreshStatus.setStage('session-cards-ok');
      return list;
    }

    void absorb(List<EtollSavedCard> batch) {
      for (final c in batch) {
        if (!c.valid) continue;
        final prev = collected[c.card4];
        if (prev == null) {
          collected[c.card4] = c;
        } else if (c.isDefault) {
          collected[c.card4] = c;
        }
      }
    }

    bool isGateway(String lu, PaymentPageProbe probe) =>
        EtollTecsPaymentParser.isGatewayUrl(lu) ||
        probe.page == 'tecspayment' ||
        EtollTecsPaymentParser.looksLikeSelectCard(lu, probe.bodyHead);

    bool isPaymentPage(String lu, PaymentPageProbe probe) =>
        probe.page == 'payment' ||
        probe.page == 'paybynet' ||
        probe.hasPayByNet ||
        probe.methods.isNotEmpty ||
        lu.contains('/payment') ||
        lu.contains('/summary');

    final topUpUrl = EtollUrls.prepaidTopUp(subjectId, prepaidId);

    EtollRefreshStatus.setStage('top-up');
    await EtollPageReady.loadAndWait(ctrl, WebUri(topUpUrl));
    if (!await _onTopUp(ctrl, topUpUrl)) {
      chk('topup', 'wrong-url');
      await _saveDiag(firmId, diag);
      return [];
    }
    chk('topup', 'ok');

    if (!await _fillAmount(ctrl, unlockAmountPln)) {
      chk('amount', 'fail');
      await _saveDiag(firmId, diag);
      return [];
    }
    chk('amount', '20');

    final beforeNext = (await ctrl.getUrl())?.toString() ?? '';
    await _clickNext(ctrl);
    await EtollPageReady.waitAfterAction(
      ctrl,
      urlBefore: beforeNext,
      maxWait: _probeWait,
    );
    chk('next', 'clicked');

    for (int step = 0; step < _stepsMax; step++) {
      if (EtollRefreshStatus.cancelRequested) break;
      if (!await EtollPageReady.ensureReady(ctrl, maxWait: _probeWait)) break;

      final cur = (await ctrl.getUrl())?.toString() ?? '';
      final lu = cur.toLowerCase();
      final probe = await EtollPaymentMethods.probe(ctrl);
      chk('s$step', probe.checkpoint());
      EtollDebugWeb.track('Refresh unlock', cur, stage: probe.page);

      // ── Страница выбора карты — читаем ВСЕ (4 и больше) ──
      if (isGateway(lu, probe)) {
        EtollRefreshStatus.setStage('tecspayment');
        final cards = await EtollTecsPaymentParser.readGatewayAll(ctrl);
        absorb(cards);
        chk('gateway-all', '${collected.length}');
        if (collected.isNotEmpty) {
          await _saveDiag(firmId, diag);
          return finalize();
        }
        chk('gateway', 'empty-retry');
        continue;
      }

      // ── Методы оплаты: клик PayByNet → если не gateway, Dalej за полным списком ──
      if (isPaymentPage(lu, probe)) {
        EtollRefreshStatus.setStage('payment');

        await EtollPaymentMethods.selectPayByNet(ctrl);
        chk('click-pbn', 'ok');
        absorb(await _probeCards(ctrl, chk, 'after-pbn'));

        if (collected.isEmpty) {
          await EtollPaymentMethods.selectCardPaymentMethod(ctrl);
          absorb(await _probeCards(ctrl, chk, 'after-cardm'));
        }

        if (collected.isEmpty) {
          for (int mi = 0; mi < probe.methods.length && mi < 6; mi++) {
            await EtollPaymentMethods.clickMethodByIndex(ctrl, mi);
            absorb(await _probeCards(ctrl, chk, 'after-m$mi'));
            if (collected.isNotEmpty) break;
          }
        }

        // На payment часто видна 1 карта — всегда Dalej к полному списку
        chk('partial', '${collected.length}');
        final proceed = await EtollPaymentMethods.clickProceed(ctrl);
        chk('proceed', proceed);
        if (proceed != 'none' && proceed != 'gateway') {
          await EtollPageReady.waitAfterAction(
            ctrl,
            urlBefore: cur,
            maxWait: _probeWait,
          );
        }
        continue;
      }

      if (lu.contains('paybynet') || lu.contains('pay-by-net')) {
        EtollRefreshStatus.setStage('paybynet');
        await EtollPaymentMethods.selectPayByNet(ctrl);
        absorb(await _probeCards(ctrl, chk, 'pbn-page'));
        final proceed = await EtollPaymentMethods.clickProceed(ctrl);
        chk('pbn-proceed', proceed);
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _probeWait,
        );
        continue;
      }

      if (lu.contains('/top-up')) {
        await _clickNext(ctrl);
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _probeWait,
        );
        continue;
      }

      if (probe.methods.isNotEmpty) {
        for (int mi = 0; mi < probe.methods.length && mi < 4; mi++) {
          await EtollPaymentMethods.clickMethodByIndex(ctrl, mi);
          absorb(await _probeCards(ctrl, chk, 'any-m$mi'));
        }
        final proceed = await EtollPaymentMethods.clickProceed(ctrl);
        if (proceed != 'none') {
          await EtollPageReady.waitAfterAction(
            ctrl,
            urlBefore: cur,
            maxWait: _probeWait,
          );
        }
        continue;
      }

      final lostProceed = await EtollPaymentMethods.clickProceed(ctrl);
      chk('lost-proceed', lostProceed);
      if (lostProceed != 'none' && lostProceed != 'gateway') {
        await EtollPageReady.waitAfterAction(
          ctrl,
          urlBefore: cur,
          maxWait: _probeWait,
        );
        continue;
      }

      chk('lost', lu.length > 36 ? lu.substring(lu.length - 36) : lu);
      break;
    }

    if (collected.isNotEmpty) {
      await _saveDiag(firmId, diag);
      return finalize();
    }
    await _saveDiag(firmId, diag);
    return [];
  }

  /// Быстрый probe — не ждём 90 сек на каждом клике.
  static Future<List<EtollSavedCard>> _probeCards(
    InAppWebViewController ctrl,
    void Function(String, String) chk,
    String tag,
  ) async {
    await EtollPageReady.waitForJs(
      ctrl,
      EtollTecsPaymentParser.hasCardsJs,
      maxWait: _probeWait,
    );
    final cards = await EtollTecsPaymentParser.readAnywhere(
      ctrl,
      maxWait: _probeRead,
    );
    chk('cards-$tag', '${cards.length}');
    return cards;
  }

  static Future<void> _saveDiag(String firmId, List<String> lines) async {
    if (firmId.isEmpty) return;
    await EtollDetailsStore.saveDiag(
      firmId,
      '[topup-chain] ${lines.join(' → ')}',
    );
  }

  static Future<bool> _onTopUp(InAppWebViewController ctrl, String topUpUrl) async {
