import 'etoll_card_list_store.dart';
import 'etoll_details_store.dart';
import 'etoll_refresh_status.dart';
import 'etoll_saved_card.dart';

/// Карты фирмы для показа на главной и в итоге refresh.
abstract final class EtollCardsDisplay {
  static bool isPendingRefresh(String firmId) =>
      EtollRefreshStatus.shouldHideCachedCards(firmId);

  static Future<List<EtollSavedCard>> forFirm(String firmId) async {
    final id = firmId.trim();
    if (id.isEmpty) return [];

    if (isPendingRefresh(id)) return [];

    final cards = await EtollCardListStore.load(id);
    if (cards.isNotEmpty) return cards;

    // Пока идёт чтение полного списка — не подменяем одной картой с details.
    if (EtollRefreshStatus.active.value &&
        EtollRefreshStatus.state.value.phase == 'card') {
      return [];
    }

    final d = await EtollDetailsStore.load(id);
    if (d != null && d.hasCard) {
      return [
        EtollSavedCard(
          card4: d.card4,
          cardType: d.resolvedCardType,
          isDefault: true,
        ),
      ];
    }
    return [];
  }

  static String formatCardLabel(
    EtollSavedCard card,
    String Function(String key) tr,
  ) {
    if (card.isDefault) {
      return '${card.label} (${tr('card_default')})';
    }
    return card.label;
  }

  static String formatLine(
    List<EtollSavedCard> cards,
    String Function(String key) tr,
  ) {
    if (cards.isEmpty) return tr('cards_not_read');
    return cards.map((c) => formatCardLabel(c, tr)).join(', ');
  }

  /// Поля для итога массового refresh (gFirmsBalances).
  static Future<Map<String, String>> summaryFields(String firmId) async {
    final cards = await forFirm(firmId);
    return {
      'cards': cards.map((c) => c.label).join(', '),
      'cardsOk': cards.isNotEmpty ? '1' : '',
    };
  }

  /// Итог refresh — все карты, основная помечена.
  static Future<Map<String, String>> summaryFieldsLocalized(
    String firmId,
    String Function(String key) tr,
  ) async {
    final cards = await forFirm(firmId);
    return {
      'cards': formatLine(cards, tr),
      'cardsOk': cards.isNotEmpty ? '1' : '',
    };
  }

  static Future<bool> hasCards(String firmId) async =>
      (await forFirm(firmId)).isNotEmpty;
}

