String _hint({
  required String transport,
  required String etoll,
  required LoadHint loadHint,
  required String phase,
}) {
  if (transport == 'none' || loadHint == LoadHint.noNet) {
    return tr('no_connection');
  }
  if (phase == 'card') {
    return tr('cards_updating');
  }
  if (loadHint == LoadHint.stuck) {
    return tr('etoll_refresh_very_slow');
  }
  if (loadHint == LoadHint.slow || etoll == 'slow') {
    return tr('etoll_refresh_slow_wifi');
  }
  if (loadHint == LoadHint.waiting) {
    // Долгая загрузка eTOLL — не «ваш интернет слабый», если связь есть.
    if (etoll == 'good' && transport != 'none') {
      return tr('etoll_refresh_slow_wifi');
    }
    return tr('weak_waiting');
  }
  return '';
}

