import 'etoll_urls.dart';

/// Навигация refresh: ТОЛЬКО financing (как на видео/скринах), НЕ billing.
///
/// login → firm → [financingList] → prepaid/details → top-up → gateway
abstract final class EtollRefreshNav {
  static String listUrl(String subjectId) =>
      EtollUrls.financingList(subjectId);

  static bool isListPage(String url) {
    final lu = url.toLowerCase();
    return lu.contains('/manage/financing/list');
  }

  static bool isBillingPage(String url) =>
      url.toLowerCase().contains('billing-account');

  /// Уже в цепочке financing (list → details → top-up → оплата).
  static bool isFinancingChain(String url) {
    final lu = url.toLowerCase();
    if (isListPage(url)) return true;
    if (lu.contains('/financing/prepaid/')) return true;
    if (lu.contains('/top-up')) return true;
    if (lu.contains('/payment') || lu.contains('/summary')) return true;
    if (lu.contains('tecspayment') || lu.contains('paybynet')) return true;
    return false;
  }

  /// На этих страницах refresh НЕ трогает URL (идёт чтение карт).
  static bool isCardChainPage(String url) {
    final lu = url.toLowerCase();
    if (lu.contains('tecspayment') || lu.contains('paybynet')) return true;
    if (lu.contains('/top-up')) return true;
    if (lu.contains('/payment') || lu.contains('/summary')) return true;
    if (lu.contains('/financing/prepaid/') &&
        (lu.contains('/details') ||
            lu.contains('/top-up') ||
            lu.contains('/payment'))) {
      return true;
    }
    return false;
  }
}

