/// Чтение баланса PLN с eTOLL: положительный, ноль, отрицательный — всё выводим.
abstract final class EtollBalanceRead {
  /// Любое число + PLN, включая −12,50 PLN и 0.00 PLN.
  static const readPlnJs = r'''
(function(){
  try {
    var t = document.body ? document.body.innerText : '';
    if (!t) return '';
    var minus = '[-−\\u2212]?\\s*';
    var num = '([0-9]+(?:[\\s][0-9]{3})*(?:[.,][0-9]{1,2})?|[0-9]+(?:[.,][0-9]{1,2})?|[0-9]+)';
    var re = new RegExp(minus + num + '\\s*PLN', 'i');
    var m = t.match(re);
    if (m) {
      var sign = (m[0].charAt(0) === '-' || m[0].charAt(0) === '−' ||
                  m[0].indexOf('\u2212') >= 0) ? '-' : '';
      var digits = m[0].replace(/[^0-9.,]/g, '').replace(/\s+/g, '');
      if (!digits) return '';
      return (sign + digits + ' PLN').replace(/\s+/g, ' ').trim();
    }
    var labels = ['balance','saldo','stan konta','środki','баланс'];
    var els = document.querySelectorAll('td,span,div,p,strong,b,li');
