''';

  /// Dart: распознать число для порогов/сравнений (знак сохраняем).
  static double? parseValue(String? raw) {
    if (raw == null || raw.trim().isEmpty) return null;
    final s = raw.trim();
    final neg = s.contains('-') || s.contains('−') || s.contains('\u2212');
    final cleaned =
        s.replaceAll(RegExp(r'[^0-9.,]'), '').replaceAll(',', '.');
    if (cleaned.isEmpty) return null;
    final v = double.tryParse(cleaned);
    if (v == null) return null;
    return neg ? -v.abs() : v;
  }
}

