import 'package:shared_preferences/shared_preferences.dart';

import 'etoll_card_list_store.dart';
import 'etoll_details_store.dart';

/// Одноразовая (и по версии) очистка кэша баланса/карт/details по фирмам.
/// НЕ трогает: [etoll_firms], cred_* (менеджер паролей), пороги, настройки UI.
abstract final class EtollFirmDataPurge {
  static const _versionKey = 'etoll_firm_data_purge_version';
  static const _currentVersion = 1;

  /// При первом refresh после обновления — сбросить устаревший кэш.
  static Future<bool> runIfNeeded() async {
    final prefs = await SharedPreferences.getInstance();
    final done = prefs.getInt(_versionKey) ?? 0;
    if (done >= _currentVersion) return false;
    await _purge(prefs);
    await prefs.setInt(_versionKey, _currentVersion);
    return true;
  }

  static Future<void> _purge(SharedPreferences prefs) async {
    final firmIds = <String>{};
    for (final key in prefs.getKeys()) {
      if (key.startsWith('cred_')) continue;
      if (key.startsWith('etoll_cards_')) {
        final id = key.substring('etoll_cards_'.length);
        if (id.isNotEmpty) firmIds.add(id);
        await prefs.remove(key);
        continue;
      }
      if (key.startsWith('etoll_details_')) {
        await prefs.remove(key);
        continue;
      }
    }

    final firmsRaw = prefs.getString('etoll_firms');
    if (firmsRaw != null && firmsRaw.isNotEmpty) {
      try {
        final decoded = prefs.getString('etoll_firms');
