/// Чтение карт в уже залогиненной сессии WebView (после баланса).
/// Путь: financing/list (prepaid ID) → top-up 20 PLN → tecspayment (без details/порогов).
abstract final class EtollCardInSession {
  static Future<void> read({
    required InAppWebViewController ctrl,
    required String firmId,
    required String subjectId,
    String accountId = '',
    String? aliasFirmId,
    void Function(String card4)? onCard4,
    void Function(String prepaidId)? onPrepaidId,
    void Function(EtollCardListDiff diff)? onCardListDiff,
  }) async {
    if (firmId.isEmpty || subjectId.isEmpty) return;
    if (EtollRefreshStatus.cancelRequested) return;

    var aid = accountId.trim();
    if (aid == subjectId.trim()) aid = '';

    String diagStage = 'session-start';

    try {
      final curUrl = (await ctrl.getUrl())?.toString() ?? '';
      if (aid.isEmpty) {
        aid = EtollFinancingNav.prepaidIdFromUrl(curUrl);
        if (aid == subjectId) aid = '';
      }
      if (aid.isEmpty) {
        aid = (await _extractPrepaidId(ctrl)).trim();
        if (aid == subjectId) aid = '';
      }

      if (aid.isEmpty) {
        diagStage = 'session-goto-list';
        final listUrl = EtollUrls.financingList(subjectId);
        await EtollPageReady.loadAndWait(ctrl, WebUri(listUrl));
        EtollDebugWeb.track('Карта in-session', listUrl, stage: diagStage);
        await EtollPageReady.waitForJs(
          ctrl,
          EtollFinancingNav.hasPrepaidAccountJs,
        );
        aid = (await _extractPrepaidId(ctrl)).trim();
        if (aid == subjectId) aid = '';
      }

      if (aid.isEmpty) {
        diagStage = 'session-no-aid';
        EtollRefreshStatus.markStall(diagStage);
        EtollDebugWeb.setStage(diagStage);
        return;
      }

      if (onPrepaidId != null) onPrepaidId(aid);

      // Сразу top-up 20 PLN → gateway (details/пороги не читаем).
      EtollRefreshStatus.setPhase('card');
      List<EtollSavedCard> cards = [];
      for (int attempt = 0; attempt < 2; attempt++) {
        if (EtollRefreshStatus.cancelRequested) break;
        if (attempt > 0) {
          diagStage = 'session-retry-topup';
          EtollRefreshStatus.setStage(diagStage);
          EtollDebugWeb.setStage(diagStage);
        }
        cards = await EtollTopUpInSession.unlockCardList(
          ctrl: ctrl,
          subjectId: subjectId,
          prepaidId: aid,
          firmId: firmId,
        );
        if (cards.isNotEmpty) break;
      }

      if (cards.isNotEmpty) {
        final diff = await EtollCardListStore.saveAndDiff(firmId, cards);
        EtollRefreshStatus.markCardsSaved(firmId);
        onCardListDiff?.call(diff);
        final primary = cards.firstWhere(
          (c) => c.isDefault,
          orElse: () => cards.first,
        );
        if (primary.valid && onCard4 != null) onCard4(primary.card4);
        diagStage = 'session-cards-ok';
        EtollRefreshStatus.setStage(diagStage);
        EtollDebugWeb.setStage(diagStage);
      } else {
        diagStage = 'session-no-cards';
        EtollRefreshStatus.markStall(diagStage);
        EtollRefreshStatus.setStage(diagStage);
        EtollDebugWeb.setStage(diagStage);
      }
    } catch (_) {
      diagStage = 'session-error';
      EtollRefreshStatus.markStall(diagStage);
      EtollDebugWeb.setStage(diagStage);
    } finally {
      await EtollDetailsStore.saveDiag(
        firmId,
        '[$diagStage] sid=$subjectId aid=${aid.isNotEmpty ? aid : accountId} in-session',
      );
    }
  }

  static Future<String> _extractPrepaidId(InAppWebViewController ctrl) async {
    if (!await EtollPageReady.isReady(ctrl)) return '';
    final extracted = await ctrl.evaluateJavascript(
      source: EtollFinancingNav.extractAccountIdJs,
    );
    return (extracted ?? '').toString().trim();
  }
}

