import 'package:flutter_inappwebview/flutter_inappwebview.dart';

/// Автопринятие GDPR / cookie-баннера eTOLL на любой странице.
abstract final class EtollCookies {
  /// Тот же набор, что в основном браузере: CMP-селекторы + «Rozumiem» / «Got it».
  static const acceptJs = r'''
(function() {
  try {
    if (window.__cookiesAccepted) return 'ok';
    var acceptWords = [
      'accept all','accept cookies','allow all','allow cookies','accept',
      'akceptuj','akceptuję','akceptuje','zgadzam','zgadzam się','zezwól',
      'rozumiem','wyrażam zgodę','zaakceptuj',
      'accepta','acceptați','acceptă','sunt de acord',
      'alle akzeptieren','akzeptieren',
      'accepter tout','accepter',
      'принять все','принять','согласен','разрешить',
      'i agree','got it','ok','zgoda'
    ];
    var cmpSelectors = [
      '#onetrust-accept-btn-handler',
      '#accept-recommended-btn-handler',
      '.onetrust-accept-btn-handler',
      '#CybotCookiebotDialogBodyLevelButtonLevelOptinAllowAll',
      '#CybotCookiebotDialogBodyButtonAccept',
      '[data-testid="cookie-policy-dialog-accept-button"]',
      '.cookie-accept','.cookies-accept','.accept-cookies',
      '#cookie-accept','#cookies-accept','#acceptCookies',
      '.js-accept-cookies','.js-cookie-accept',
      '[data-action="accept-cookies"]',
      '.cm__btn--accept','.cc-accept','.cc-btn.cc-allow'
    ];
    function tryClick(el) {
      try { el.click(); window.__cookiesAccepted = true; return true; }
      catch(e) { return false; }
    }
    function insideCookieBanner(el) {
      var node = el;
      for (var depth = 0; depth < 8 && node; depth++) {
        var idc = ((node.id||'') + ' ' + (node.className||'')).toString().toLowerCase();
        if (idc.indexOf('cookie')>=0 || idc.indexOf('consent')>=0 ||
            idc.indexOf('gdpr')>=0 || idc.indexOf('rodo')>=0 ||
            idc.indexOf('cmp')>=0 || idc.indexOf('privacy')>=0) {
          return true;
        }
        node = node.parentElement;
      }
      return false;
    }
    function attempt() {
      if (window.__cookiesAccepted) return true;
      for (var s = 0; s < cmpSelectors.length; s++) {
        var el = document.querySelector(cmpSelectors[s]);
        if (el && el.offsetParent !== null) { if (tryClick(el)) return true; }
      }
      var candidates = document.querySelectorAll(
        'button,a,a[role="button"],input[type="button"],input[type="submit"],[role="button"]'
      );
      for (var i = 0; i < candidates.length; i++) {
        var btn = candidates[i];
        if (btn.offsetParent === null) continue;
        var txt = (btn.innerText||btn.value||btn.getAttribute('aria-label')||'')
          .toLowerCase().trim();
        if (!txt || txt.length > 40) continue;
        var inBanner = insideCookieBanner(btn);
        for (var w = 0; w < acceptWords.length; w++) {
          if (txt === acceptWords[w] || txt.indexOf(acceptWords[w]) === 0) {
            if (inBanner || txt === 'got it' || txt === 'rozumiem' || txt === 'ok') {
              if (tryClick(btn)) return true;
            }
          }
        }
      }
      return false;
    }
    if (attempt()) return 'clicked';
    if (!window.__cookieIv) {
      var n = 0;
      window.__cookieIv = setInterval(function() {
        n++;
        if (attempt() || n >= 10) clearInterval(window.__cookieIv);
      }, 600);
    }
    return 'wait';
  } catch(e) { return 'err'; }
})();
''';

  static Future<void> accept(InAppWebViewController ctrl) async {
    try {
      await ctrl.evaluateJavascript(source: acceptJs);
    } catch (_) {}
  }
}

