import 'package:flutter_inappwebview/flutter_inappwebview.dart';

/// Автопринятие cookie / GDPR — eTOLL, login.gov.pl, login.mf.gov.pl.
abstract final class EtollCookies {
  /// Одна попытка (без setInterval — надёжнее из Dart-цикла).
  static const acceptOnceJs = r'''
(function() {
  try {
    function visible(el) {
      if (!el || el.disabled) return false;
      try {
        var st = window.getComputedStyle(el);
        if (st.display === 'none' || st.visibility === 'hidden') return false;
        if (parseFloat(st.opacity || '1') < 0.05) return false;
      } catch(e) {}
      var r = el.getBoundingClientRect();
      return r.width >= 6 && r.height >= 6;
    }
    function realClick(el) {
      try {
        var rc = el.getBoundingClientRect();
        var o = { bubbles: true, cancelable: true, view: window,
          clientX: rc.left + rc.width / 2, clientY: rc.top + rc.height / 2 };
        el.dispatchEvent(new MouseEvent('pointerdown', o));
        el.dispatchEvent(new MouseEvent('mousedown', o));
        el.dispatchEvent(new MouseEvent('mouseup', o));
        el.dispatchEvent(new MouseEvent('click', o));
        el.click();
        return true;
      } catch (e) {
        try { el.click(); return true; } catch (e2) { return false; }
      }
    }
    function bodyText() {
      return (document.body && document.body.innerText || '').toLowerCase();
    }
    function cookieWallVisible() {
      var t = bodyText();
      return t.indexOf('block cookies') >= 0 ||
        t.indexOf('cookie policy') >= 0 ||
        t.indexOf('plików cookie') >= 0 ||
        t.indexOf('pliki cookie') >= 0 ||
        (t.indexOf('cookies') >= 0 && t.indexOf('memory') >= 0) ||
        t.indexOf('nie blokujesz plik') >= 0;
    }
    if (window.__cookiesAccepted && !cookieWallVisible()) return 'ok';

    var acceptWords = [
      'got it', 'rozumiem', 'ok', 'zgoda', 'accept all', 'accept cookies',
      'allow all', 'allow cookies', 'accept', 'akceptuj', 'akceptuję',
      'akceptuje', 'zgadzam', 'zaakceptuj', 'wyrażam zgodę', 'i agree'
    ];
    var cmpSelectors = [
      '#onetrust-accept-btn-handler', '#accept-recommended-btn-handler',
      '.onetrust-accept-btn-handler',
      '#CybotCookiebotDialogBodyLevelButtonLevelOptinAllowAll',
      '#CybotCookiebotDialogBodyButtonAccept',
      '[data-testid="cookie-policy-dialog-accept-button"]',
      '.cookie-accept', '.cookies-accept', '.accept-cookies',
      '#cookie-accept', '#cookies-accept', '#acceptCookies'
    ];

    for (var s = 0; s < cmpSelectors.length; s++) {
      var el = document.querySelector(cmpSelectors[s]);
      if (el && visible(el) && realClick(el)) {
        window.__cookiesAccepted = true;
        return 'clicked-cmp';
      }
    }

    var wall = cookieWallVisible();
    var candidates = document.querySelectorAll(
      'button,a,a[role="button"],input[type="button"],input[type="submit"],[role="button"],label'
    );
    for (var i = 0; i < candidates.length; i++) {
      var btn = candidates[i];
      if (!visible(btn)) continue;
      var txt = (btn.innerText || btn.value || btn.getAttribute('aria-label') || '')
        .toLowerCase().trim();
      if (!txt || txt.length > 48) continue;
      for (var w = 0; w < acceptWords.length; w++) {
        var word = acceptWords[w];
        if (txt === word || txt.indexOf(word) === 0) {
          if (wall || word === 'got it' || word === 'rozumiem' || word === 'ok') {
            if (realClick(btn)) {
              window.__cookiesAccepted = true;
              return 'clicked-' + word;
            }
          }
        }
      }
    }
    return cookieWallVisible() ? 'wall' : 'none';
  } catch (e) { return 'err'; }
})();
''';

  static bool _isLoginOrEtoll(String url) {
    final u = url.toLowerCase();
    return u.contains('login.gov.pl') ||
        u.contains('login.mf.gov.pl') ||
        u.contains('etoll.gov.pl') ||
        u.contains('mojekonto');
  }

  static Future<String> acceptOnce(InAppWebViewController ctrl) async {
    try {
      return (await ctrl.evaluateJavascript(source: acceptOnceJs) ?? '')
          .toString()
          .trim();
    } catch (_) {
      return 'err';
    }
  }

  /// Несколько попыток — баннер login.gov.pl часто появляется ПОСЛЕ loadStop.
  static Future<bool> acceptBurst(
    InAppWebViewController ctrl, {
    int tries = 20,
    String? urlHint,
  }) async {
    var url = urlHint ?? '';
    if (url.isEmpty) {
      try {
        url = (await ctrl.getUrl())?.toString() ?? '';
      } catch (_) {}
    }
    final onLogin = _isLoginOrEtoll(url);
    final max = onLogin ? (tries < 30 ? 30 : tries) : tries;
    for (var i = 0; i < max; i++) {
      final r = await acceptOnce(ctrl);
      if (r.startsWith('clicked') || r == 'ok') return true;
      if (r == 'none' && !onLogin && i >= 3) return false;
      await Future.delayed(Duration(milliseconds: onLogin ? 450 : 350));
    }
    return false;
  }

  static Future<void> accept(InAppWebViewController ctrl) async {
    await acceptBurst(ctrl, tries: 8);
  }
}

