import 'package:flutter_inappwebview/flutter_inappwebview.dart';

import 'etoll_cookies.dart';
import 'etoll_page_ready.dart';

/// Автовход eTOLL: куки → Zaloguj → Login and password → логин/пароль → Submit.
abstract final class EtollLoginAutomation {
  static const _helpers = r'''
    function realClick(el){
      try {
        var rc=el.getBoundingClientRect();
        var o={bubbles:true,cancelable:true,view:window,
          clientX:rc.left+rc.width/2,clientY:rc.top+rc.height/2};
        el.dispatchEvent(new MouseEvent('pointerdown',o));
        el.dispatchEvent(new MouseEvent('mousedown',o));
        el.dispatchEvent(new MouseEvent('mouseup',o));
        el.dispatchEvent(new MouseEvent('click',o));
        el.click(); return true;
      } catch(e){ try{el.click();return true;}catch(e2){return false;} }
    }
    function visible(el){
      if(!el||el.disabled||el.readOnly) return false;
      try{
        var st=window.getComputedStyle(el);
        if(st.display==='none'||st.visibility==='hidden') return false;
      }catch(e){}
      var r=el.getBoundingClientRect();
      return r.width>=4&&r.height>=4;
    }
    function fireInput(el){
      el.focus();
      el.dispatchEvent(new Event('input',{bubbles:true}));
      el.dispatchEvent(new Event('change',{bubbles:true}));
      el.dispatchEvent(new KeyboardEvent('keydown',{bubbles:true}));
      el.dispatchEvent(new KeyboardEvent('keyup',{bubbles:true}));
      el.dispatchEvent(new Event('blur',{bubbles:true}));
    }
  ''';

  static Future<bool> hasPasswordField(InAppWebViewController ctrl) async {
    final r = await ctrl.evaluateJavascript(source: r'''
      (function(){ return document.querySelector('input[type="password"]') ? '1' : '0'; })();
    ''');
    return (r ?? '0').toString().trim() == '1';
  }

  static Future<bool> isOnLoginGateway(String url) {
    final u = url.toLowerCase();
    return Future.value(
      u.contains('login.gov.pl') ||
          u.contains('login.mf.gov.pl') ||
          u.contains('/auth/') ||
          (u.contains('login') && !u.contains('/subject/')),
    );
  }

  static Future<bool> isInsideFirm(String url) async {
    return RegExp(r'/subject/\d+').hasMatch(url) &&
        !url.toLowerCase().contains('login.gov');
  }

  /// Промежуточные экраны до поля пароля (gov.pl — без offsetParent).
  static Future<void> skipToPasswordForm(InAppWebViewController ctrl) async {
    await ctrl.evaluateJavascript(source: '''
      (function(){
        $_helpers
        try {
          if(document.querySelector('input[type="password"]')) return;
          var pageText=(document.body.innerText||'').toLowerCase();
          var marker=['login and password','login i hasło','login i haslo',
                      'логин и пароль','additional login method'];
          var hasMarker=false;
          for(var m=0;m<marker.length;m++){
            if(pageText.indexOf(marker[m])>=0){hasMarker=true;break;}
          }
          if(hasMarker){
            var heads=document.querySelectorAll('h1,h2,h3,h4,div,span,p,strong,b,button,a');
            for(var i=0;i<heads.length;i++){
              var ht=(heads[i].innerText||heads[i].textContent||'').toLowerCase().trim();
              if(ht.length>48) continue;
              if(ht.indexOf('login and password')>=0||ht.indexOf('login i has')>=0||
                 ht.indexOf('логин и пароль')>=0){
                var card=heads[i];
                for(var up=0;up<8&&card;up++){
                  var btns=card.querySelectorAll('button,a,[role="button"],input[type="button"],input[type="submit"]');
                  for(var b=0;b<btns.length;b++){
                    if(!visible(btns[b])) continue;
                    var bt=(btns[b].innerText||btns[b].value||'').toLowerCase().trim();
                    if(bt.indexOf('select')>=0||bt.indexOf('wybierz')>=0||bt.indexOf('выбрать')>=0){
                      realClick(btns[b]); return;
                    }
                  }
                  card=card.parentElement;
                }
              }
            }
          }
          var words=['zaloguj','zaloguj się','log in','sign in','войти','login'];
          var els=document.querySelectorAll('a,button,[role="button"],input[type="button"],input[type="submit"]');
          for(var k=0;k<els.length;k++){
            var el=els[k];
            if(!visible(el)) continue;
            var t=(el.innerText||el.value||el.getAttribute('aria-label')||'').toLowerCase().trim();
            if(!t||t.length>36) continue;
            for(var w=0;w<words.length;w++){
              if(t===words[w]||t.indexOf(words[w])===0){ realClick(el); return; }
            }
          }
        } catch(e){}
      })();
    ''');
  }

  static Future<void> fillCredentials(
    InAppWebViewController ctrl,
    String login,
    String password,
  ) async {
    final l = login.replaceAll("'", "\\'").replaceAll(r'\', r'\\');
    final p = password.replaceAll("'", "\\'").replaceAll(r'\', r'\\');
    await ctrl.evaluateJavascript(source: '''
      (function(){
        $_helpers
        var pw=document.querySelector('input[type="password"]');
        if(visible(pw)){ pw.value='$p'; fireInput(pw); }
        var loginEl=null;
        var cands=document.querySelectorAll('input[type="text"],input[type="email"],input[type="tel"],input:not([type])');
        var hints=['login','user','email','e-mail','username','nazwa','identyf'];
        for(var i=0;i<cands.length;i++){
          var el=cands[i];
          if(!visible(el)) continue;
          var meta=((el.name||'')+' '+(el.id||'')+' '+(el.placeholder||'')+' '+(el.getAttribute('autocomplete')||'')).toLowerCase();
          for(var h=0;h<hints.length;h++){ if(meta.indexOf(hints[h])>=0){ loginEl=el; break; } }
          if(loginEl) break;
        }
        if(!loginEl){ for(var j=0;j<cands.length;j++){ if(visible(cands[j])){ loginEl=cands[j]; break; } } }
        if(loginEl){ loginEl.value='$l'; fireInput(loginEl); }
        try{if(document.activeElement) document.activeElement.blur();}catch(e){}
      })();
    ''');
  }

  static Future<void> clickLoginSubmit(InAppWebViewController ctrl) async {
    await ctrl.evaluateJavascript(source: '''
      (function(){
        $_helpers
        try {
          var pw=document.querySelector('input[type="password"]');
          var f=pw?pw.form:null;
          var btn=null;
          if(f) btn=f.querySelector('button[type="submit"],input[type="submit"]');
          if(!btn||!visible(btn)) btn=document.querySelector('button[type="submit"],input[type="submit"]');
          if(!btn||!visible(btn)){
            var btns=document.querySelectorAll('button,a[role="button"],[role="button"]');
            var words=['log in','login','zaloguj','sign in','войти','вход','dalej'];
            for(var j=0;j<btns.length;j++){
              if(!visible(btns[j])) continue;
              var tx=(btns[j].innerText||btns[j].value||'').toLowerCase().trim();
              for(var k=0;k<words.length;k++){
                if(tx.indexOf(words[k])>=0){ btn=btns[j]; break; }
              }
              if(btn) break;
            }
          }
          if(btn&&visible(btn)) realClick(btn);
          else if(f) try{f.requestSubmit?f.requestSubmit():f.submit();}catch(e){}
        } catch(e){}
      })();
    ''');
  }

  /// Один шаг: куки → экраны → ввод → submit.
  static Future<bool> advanceStep(
    InAppWebViewController ctrl, {
    required String login,
    required String password,
  }) async {
    await EtollCookies.acceptBurst(ctrl, tries: 10);
    await skipToPasswordForm(ctrl);
    await EtollPageReady.waitForReady(
      ctrl,
      maxWait: const Duration(seconds: 8),
    );
    if (!await hasPasswordField(ctrl)) return false;
    await fillCredentials(ctrl, login, password);
    await Future.delayed(const Duration(milliseconds: 900));
    await clickLoginSubmit(ctrl);
    return true;
  }
}

