Future<void> _loginRetryLoop() async {
  if (widget.autoLogin == null || widget.autoLogin!.isEmpty) return;
  if (_controller == null) return;
  var lastUrl = (await _controller!.getUrl())?.toString() ?? '';
  for (int i = 0; i < 20; i++) {
    if (!mounted || _wrongPasswordHandled || _closedAfterRead) return;
    final curUrl = (await _controller!.getUrl())?.toString() ?? '';
    if (await EtollLoginAutomation.isInsideFirm(curUrl)) {
      if (widget.onDone != null &&
          !EtollRefreshNav.isCardChainPage(curUrl)) {
        await _gotoFinancingForRefresh(Uri.tryParse(curUrl));
      }
      return;
    }
    await EtollCookies.acceptBurst(_controller!, tries: 8, urlHint: curUrl);
    await _autofillLogin(widget.autoLogin!);
    if (await _checkLoginError()) return;
    await EtollPageReady.ensureReady(_controller!);
    final cu = await _controller?.getUrl();
    await _enterFirmFromList(cu);
    if (widget.onDone != null) {
      final nowU = cu?.toString() ?? '';
      if (!_closedAfterRead && !EtollRefreshNav.isCardChainPage(nowU)) {
        await _gotoFinancingForRefresh(cu);
      }
    } else {
      await _gotoBilling(cu);
    }
    if (widget.gotoFinancing) await _maybeGotoFinancing(cu);
    if (_closedAfterRead) return;
    final now = (await _controller?.getUrl())?.toString() ?? '';
    if (widget.onDone != null) {
      if (EtollRefreshNav.isFinancingChain(now) || _closedAfterRead) return;
      if (await EtollLoginAutomation.isInsideFirm(now)) return;
    } else if (now.contains('/billing-account')) {
      return;
    }
    await EtollPageReady.waitAfterAction(_controller!, urlBefore: lastUrl);
    lastUrl = now.isNotEmpty ? now : lastUrl;
  }
}

