Future<void> _autofillLogin(String login) async {
  if (_wrongPasswordHandled) return;
  if (await EtollLoginGuard.isBlocked(login)) {
    _wrongPasswordHandled = true;
    if (mounted) notifyEtollWrongPassword(brief: true);
    return;
  }
  if (_controller == null) return;
  final curUrl = (await _controller!.getUrl())?.toString() ?? '';
  if (await EtollLoginAutomation.isInsideFirm(curUrl)) return;

  final accounts = await CredentialStore.loadAll(_etollKey);
  String norm(String s) => s.trim().toLowerCase();
  final want = norm(login);
  final acc = accounts.firstWhere(
    (a) => norm(a['l'] ?? '') == want,
    orElse: () => <String, String>{},
  );
  if (acc.isEmpty) return;

  final lg = acc['l'] ?? '';
  final pw = acc['p'] ?? '';
  if (lg.isEmpty || pw.isEmpty) return;

  // Повторяем, пока на шлюзе входа — после куки форма появляется не сразу.
  if (!await EtollLoginAutomation.hasPasswordField(_controller!)) {
    await EtollLoginAutomation.skipToPasswordForm(_controller!);
    await EtollPageReady.waitForReady(
      _controller!,
      maxWait: const Duration(seconds: 10),
    );
  }
  if (!await EtollLoginAutomation.hasPasswordField(_controller!)) return;

  if (!_autoLoginFilled) {
    _autoLoginFilled = true;
    await EtollLoginAutomation.advanceStep(
      _controller!,
      login: lg,
      password: pw,
    );
  } else if (await EtollLoginAutomation.isOnLoginGateway(curUrl)) {
    await EtollLoginAutomation.advanceStep(
      _controller!,
      login: lg,
      password: pw,
    );
  }
  await EtollPageReady.waitForReady(
    _controller!,
    maxWait: const Duration(seconds: 12),
  );
}

