Future<void> _autofillLogin(String login) async {
  if (_wrongPasswordHandled) return;
  if (await EtollLoginGuard.isBlocked(login)) {
    _wrongPasswordHandled = true;
    if (mounted) notifyEtollWrongPassword(brief: true);
    return;
  }
  if (_controller == null || _autoLoginFilled) return;
  // есть ли поле пароля сейчас?
  final hasPw = await _controller!.evaluateJavascript(source: r'''
    (function(){ return document.querySelector('input[type="password"]') ? '1':'0'; })();
  ''');
  if ((hasPw ?? '0').toString().trim() != '1') return; // ещё не форма логина
  final accounts = await CredentialStore.loadAll(_etollKey);
  // Сравниваем логины устойчиво: без пробелов по краям и без учёта регистра.
  // Иначе при малейшем расхождении (пробел/регистр) пароль не находился и
  // форма не заполнялась — фирма «не обновлялась» до ручной проверки в редакторе.
