/// Полная цепочка refresh: firm → financing/list → top-up 20 → gateway (карты).
abstract final class EtollRefreshPipeline {
  /// Дойти до financing/list (autoclick с subject/list).
  static Future<String?> reachFinancingList(InAppWebViewController ctrl) async {
    if (EtollRefreshStatus.cancelRequested) return null;
    await EtollCookies.acceptBurst(ctrl, tries: 6);
    EtollRefreshStatus.setStage('financing');
    final subj = await EtollFinancingNav.ensureFinancingList(ctrl);
    if (subj != null && subj.isNotEmpty) {
      EtollDebugWeb.track('Refresh pipeline', '', stage: 'financing-list');
      EtollRefreshStatus.setStage('financing');
    }
    return subj;
  }

  /// После list — top-up → PayByNet → Dalej → gateway (все карты).
  static Future<bool> readCards({
    required InAppWebViewController ctrl,
    required String subjectId,
    String accountId = '',
    String firmId = '',
    void Function(String card4)? onCard4,
    void Function(String prepaidId)? onPrepaidId,
    void Function(EtollCardListDiff diff)? onCardListDiff,
  }) async {
    if (subjectId.isEmpty || EtollRefreshStatus.cancelRequested) return false;
    if (EtollRefreshStatus.cardsSavedThisRun &&
        EtollRefreshStatus.cardsSavedSubjectId == subjectId.trim()) {
      return true;
    }
    final fid = firmId.isNotEmpty ? firmId : subjectId;
    EtollRefreshStatus.setPhase('card');
    EtollRefreshStatus.setRefreshingSubject(fid);

    await EtollCardInSession.read(
      ctrl: ctrl,
      firmId: fid,
      subjectId: subjectId,
      accountId: accountId,
      onCard4: onCard4,
      onPrepaidId: onPrepaidId,
      onCardListDiff: onCardListDiff,
    );
    return EtollRefreshStatus.cardsSavedThisRun &&
        EtollRefreshStatus.cardsSavedSubjectId == fid;
  }

  /// Уже на payment/top-up — не сбрасывать, дочитать карты.
  static Future<bool> resumeCardChainIfNeeded({
    required InAppWebViewController ctrl,
    required String subjectId,
    String accountId = '',
    String firmId = '',
    void Function(String card4)? onCard4,
    void Function(String prepaidId)? onPrepaidId,
    void Function(EtollCardListDiff diff)? onCardListDiff,
  }) async {
    final url = (await ctrl.getUrl())?.toString() ?? '';
    if (!EtollRefreshNav.isCardChainPage(url)) return false;
    if (EtollRefreshStatus.cardsSavedThisRun) return true;
    return readCards(
      ctrl: ctrl,
      subjectId: subjectId,
      accountId: accountId,
      firmId: firmId,
      onCard4: onCard4,
      onPrepaidId: onPrepaidId,
      onCardListDiff: onCardListDiff,
    );
  }

  static Future<void> waitStable(InAppWebViewController ctrl) async {
    await EtollPageReady.waitForReady(
      ctrl,
      maxWait: const Duration(seconds: 12),
    );
  }
}

