/// Refresh: firm → financing/list → balance → top-up 20 → gateway.
Future<void> _ensureRefreshToCards() async {
  if (_controller == null || _refreshAborted || _closedAfterRead) return;
  if (widget.onDone == null) return;

  var url = (await _controller!.getUrl())?.toString() ?? '';
  if (EtollRefreshNav.isCardChainPage(url) &&
      !EtollRefreshStatus.cardsSavedThisRun) {
    var subj = EtollFinancingNav.subjectIdFromUrl(url);
    if (subj.isEmpty) subj = (await BalanceStore.subjectId())?.trim() ?? '';
    if (subj.isNotEmpty) {
      final aid = (await BalanceStore.accountId())?.trim() ?? '';
      await EtollRefreshPipeline.resumeCardChainIfNeeded(
        ctrl: _controller!,
        subjectId: subj,
        accountId: aid,
        firmId: subj,
        onCard4: BalanceStore.setTopUpCard4,
        onPrepaidId: (id) async {
          if (id.isNotEmpty && id != subj) {
            await BalanceStore.setAccountId(id);
          }
        },
        onCardListDiff: notifyEtollCardListDiff,
      );
    }
    return;
  }

  final subj = await EtollRefreshPipeline.reachFinancingList(_controller!);
  if (subj == null || subj.isEmpty) return;
  await BalanceStore.setSubjectId(subj);

  url = (await _controller!.getUrl())?.toString() ?? '';
  if (EtollRefreshNav.isListPage(url) &&
      !_readingFinancing &&
      !_closedAfterRead) {
    await _readFinancingInfo();
  }
}

