  if (RegExp(r'/subject/\d+').hasMatch(u)) return; // уже внутри фирмы — не трогаем
  await _controller!.evaluateJavascript(source: r'''
    (function(){
      try {
        function realClick(el){
          try {
            var r=el.getBoundingClientRect();
            var o={bubbles:true,cancelable:true,view:window,
                   clientX:r.left+r.width/2, clientY:r.top+r.height/2};
            el.dispatchEvent(new MouseEvent('pointerdown',o));
            el.dispatchEvent(new MouseEvent('mousedown',o));
            el.dispatchEvent(new MouseEvent('mouseup',o));
            el.dispatchEvent(new MouseEvent('click',o));
            el.click();
          } catch(e){ try{el.click();}catch(e2){} }
        }
        // 1) Ищем карточку фирмы с «Active» внутри.
        var conts=document.querySelectorAll('mat-card,.mat-card,article,section,li,tr,[class*="card"],[class*="firm"],[class*="company"]');
        var card=null;
        for(var i=0;i<conts.length;i++){
          var t=(conts[i].innerText||'').toLowerCase();
          if((t.indexOf('active')>=0 || t.indexOf('aktywny')>=0 || t.indexOf('aktywna')>=0) &&
             t.length<500){
            card=conts[i]; break;
          }
        }
        var scope = card || document;
        // 2) Клик по статусу "Active" внутри карточки.
        var words=['active','aktywny','aktywna'];
        var els=scope.querySelectorAll('span,div,p,strong,b,td,li,button,a');
        for(var j=0;j<els.length;j++){
          var el=els[j];
          if(el.offsetParent===null) continue;
          var tx=(el.innerText||el.textContent||'').trim().toLowerCase();
          for(var w=0;w<words.length;w++){
            if(tx===words[w]){ realClick(el); return '1'; }
          }
        }
        // 3) Фолбэк — клик по карточке/ссылке фирмы.
        if(card){
          var a=card.querySelector('a[href*="/subject/"]') || card.querySelector('a');
          if(a){ realClick(a); return '2'; }
          realClick(card); return '3';
        }
        return '0';
      } catch(e){ return '0'; }
    })();
  ''');
}

