static Future<void> saveFirmSnapshotFromGlobals(String id) async {
  if (id.isEmpty) return;
  final bal = await lastBalance();
  final t = await lastTime();
  final infos = await _readFirmInfos();
  final snap = <String, dynamic>{
    'time': t?.millisecondsSinceEpoch,
    'company': await company() ?? '',
    'accName': await accountName() ?? '',
    'accNumber': await accountNumber() ?? '',
    'accountId': await accountId() ?? '',
    'login': await lastLogin() ?? '',
  };
  if (bal != null && bal.trim().isNotEmpty) {
    snap['balance'] = bal.trim();
  }
  final cards = await EtollCardListStore.load(id);
  if (cards.isNotEmpty) {
    snap['cardsOk'] = '1';
    snap['cards'] = cards.map((c) => c.label).join(', ');
    final def = cards.firstWhere(
      (c) => c.isDefault,
      orElse: () => cards.first,
    );
    if (def.valid) snap['card4'] = def.card4;
  } else {
    final c4 = await topUpCard4();
    if (c4.isNotEmpty) snap['card4'] = c4;
  }
  infos[id] = snap;
  final prefs = await SharedPreferences.getInstance();
  await prefs.setString(_kFirmInfos, jsonEncode(infos));
}

